const RPS_NAMES: Record<string,string> = { "✊":"Rock","✋":"Paper","✌️":"Scissors" };
const rpsWinner = (p: string, a: string) => {
  if (p === a) return "draw";
  if ((p === "✊" && a === "✌️") || (p === "✋" && a === "✊") || (p === "✌️" && a === "✋")) return "player";
  return "ai";
};
