const QS_NOTE_NAMES=['C','C#','D','Eb','E','F','F#','G','Ab','A','Bb','B'];
const QS_SCALES:Record<string,number[]>={'Major':[0,2,4,5,7,9,11],'Minor':[0,2,3,5,7,8,10],'Pentatonic':[0,2,4,7,9],'Blues':[0,3,5,6,7,10],'Dorian':[0,2,3,5,7,9,10],'Phrygian':[0,1,3,5,7,8,10]};
function qsMidiToFreq(midi:number){return 440*Math.pow(2,(midi-69)/12);}
function qsMidiNoteName(midi:number){return QS_NOTE_NAMES[midi%12]+Math.floor(midi/12-1);}
function qsGetScaleNotes(keyStr:string){const p=keyStr.split(' '),r=QS_NOTE_NAMES.indexOf(p[0]),s=QS_SCALES[p.slice(1).join(' ')||'Minor']||QS_SCALES['Minor'];return s.map(i=>(r+i)%12);}
function qsGetScaleNote(keyStr:string,noteIndex:number,octaveShift=0){const p=keyStr.split(' '),n=p[0],m=p.slice(1).join(' ')||'Minor',r=QS_NOTE_NAMES.indexOf(n),rf=qsMidiToFreq(48+r),s=QS_SCALES[m]||QS_SCALES['Minor'],oct=Math.floor(noteIndex/s.length)+octaveShift,pos=noteIndex%s.length;return rf*Math.pow(2,(s[pos]+oct*12)/12);}

function qsMakeDistCurve(amount:number){const n=512,curve=new Float32Array(n),k=amount*150;for(let i=0;i<n;i++){const x=(i*2)/n-1;curve[i]=k>0?((Math.PI+k)*x)/(Math.PI+k*Math.abs(x)):x;}return curve;}
function qsCreateReverb(ctx:OfflineAudioContext|AudioContext,dur=2.5,decay=2.2){const len=ctx.sampleRate*dur,buf=ctx.createBuffer(2,len,ctx.sampleRate);for(let c=0;c<2;c++){const d=buf.getChannelData(c);for(let i=0;i<len;i++)d[i]=(Math.random()*2-1)*Math.pow(1-i/len,decay);}return buf;}
function qsPlayKick(ctx:AudioContext,dest:AudioNode,t:number,v:number){const o=ctx.createOscillator(),g=ctx.createGain();o.connect(g);g.connect(dest);o.frequency.setValueAtTime(220,t);o.frequency.exponentialRampToValueAtTime(35,t+0.1);g.gain.setValueAtTime(v*2.2,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.55);o.start(t);o.stop(t+0.6);const cl=ctx.sampleRate*0.01,cb=ctx.createBuffer(1,cl,ctx.sampleRate),cd=cb.getChannelData(0);for(let i=0;i<cl;i++)cd[i]=(Math.random()*2-1)*(1-i/cl);const cs=ctx.createBufferSource();cs.buffer=cb;const cg=ctx.createGain();cg.gain.setValueAtTime(v*0.5,t);cs.connect(cg);cg.connect(dest);cs.start(t);}
function qsPlaySnare(ctx:AudioContext,dest:AudioNode,t:number,v:number){const bl=ctx.sampleRate*0.22,buf=ctx.createBuffer(1,bl,ctx.sampleRate),d=buf.getChannelData(0);for(let i=0;i<bl;i++)d[i]=Math.random()*2-1;const ns=ctx.createBufferSource();ns.buffer=buf;const f=ctx.createBiquadFilter();f.type='bandpass';f.frequency.value=2800;f.Q.value=0.9;const g=ctx.createGain();g.gain.setValueAtTime(v*0.9,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.2);ns.connect(f);f.connect(g);g.connect(dest);ns.start(t);ns.stop(t+0.25);const o=ctx.createOscillator();o.type='triangle';o.frequency.value=190;const og=ctx.createGain();og.gain.setValueAtTime(v*0.55,t);og.gain.exponentialRampToValueAtTime(0.001,t+0.09);o.connect(og);og.connect(dest);o.start(t);o.stop(t+0.1);}
function qsPlayHHC(ctx:AudioContext,dest:AudioNode,t:number,v:number){const bl=ctx.sampleRate*0.06,buf=ctx.createBuffer(1,bl,ctx.sampleRate),d=buf.getChannelData(0);for(let i=0;i<bl;i++)d[i]=Math.random()*2-1;const s=ctx.createBufferSource();s.buffer=buf;const f=ctx.createBiquadFilter();f.type='highpass';f.frequency.value=9500;const g=ctx.createGain();g.gain.setValueAtTime(v*0.32,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.05);s.connect(f);f.connect(g);g.connect(dest);s.start(t);s.stop(t+0.07);}
function qsPlayHHO(ctx:AudioContext,dest:AudioNode,t:number,v:number){const bl=ctx.sampleRate*0.45,buf=ctx.createBuffer(1,bl,ctx.sampleRate),d=buf.getChannelData(0);for(let i=0;i<bl;i++)d[i]=Math.random()*2-1;const s=ctx.createBufferSource();s.buffer=buf;const f=ctx.createBiquadFilter();f.type='highpass';f.frequency.value=7500;const g=ctx.createGain();g.gain.setValueAtTime(v*0.28,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.4);s.connect(f);f.connect(g);g.connect(dest);s.start(t);}
function qsPlayClap(ctx:AudioContext,dest:AudioNode,t:number,v:number){for(let i=0;i<3;i++){const dl=i*0.013,bl=ctx.sampleRate*0.09,buf=ctx.createBuffer(1,bl,ctx.sampleRate),d=buf.getChannelData(0);for(let j=0;j<bl;j++)d[j]=(Math.random()*2-1)*(1-j/bl);const s=ctx.createBufferSource();s.buffer=buf;const f=ctx.createBiquadFilter();f.type='bandpass';f.frequency.value=1600;f.Q.value=1.3;const g=ctx.createGain();g.gain.setValueAtTime(v*0.75/(i+1),t+dl);g.gain.exponentialRampToValueAtTime(0.001,t+dl+0.12);s.connect(f);f.connect(g);g.connect(dest);s.start(t+dl);}}
function qsPlayTom(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number){const o=ctx.createOscillator(),g=ctx.createGain();o.connect(g);g.connect(dest);o.frequency.setValueAtTime(freq*1.6,t);o.frequency.exponentialRampToValueAtTime(freq,t+0.06);g.gain.setValueAtTime(v*1.3,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.38);o.start(t);o.stop(t+0.42);}
function qsPlayCymbal(ctx:AudioContext,dest:AudioNode,t:number,v:number){[205,287,340,406,527,630].forEach(f=>{const o=ctx.createOscillator();o.type='square';o.frequency.value=f;const flt=ctx.createBiquadFilter();flt.type='highpass';flt.frequency.value=4500;const g=ctx.createGain();g.gain.setValueAtTime(v*0.04,t);g.gain.exponentialRampToValueAtTime(0.001,t+1.6);o.connect(flt);flt.connect(g);g.connect(dest);o.start(t);o.stop(t+1.7);});}
function qsPlay808(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number,dur:number){const o=ctx.createOscillator();o.type='sine';const dist=ctx.createWaveShaper();dist.curve=qsMakeDistCurve(0.3);const g=ctx.createGain();o.connect(dist);dist.connect(g);g.connect(dest);o.frequency.setValueAtTime(freq*2.5,t);o.frequency.exponentialRampToValueAtTime(freq,t+0.05);g.gain.setValueAtTime(v*1.8,t);g.gain.setValueAtTime(v*1.6,t+dur*0.6);g.gain.exponentialRampToValueAtTime(0.001,t+dur);o.start(t);o.stop(t+dur+0.05);}
function qsPlayBassS(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number,dur:number,p:any={}){const o=ctx.createOscillator();o.type=p.oscType||'sawtooth';const f=ctx.createBiquadFilter();f.type='lowpass';f.frequency.setValueAtTime(freq*10,t);f.frequency.exponentialRampToValueAtTime(freq*2,t+dur*0.3);f.Q.value=5;const g=ctx.createGain();o.connect(f);f.connect(g);g.connect(dest);o.frequency.value=freq;const atk=p.attack||0.01,rel=p.release||0.3;g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(v*0.85,t+atk);g.gain.exponentialRampToValueAtTime(0.001,t+dur+rel);o.start(t);o.stop(t+dur+rel+0.05);}
function qsPlayLead(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number,dur:number,p:any={}){['sawtooth','square'].forEach((type,i)=>{const o=ctx.createOscillator();o.type=type as OscillatorType;o.frequency.value=freq*(1+i*0.003);const filt=ctx.createBiquadFilter();filt.type='lowpass';filt.frequency.setValueAtTime(freq*8,t);filt.frequency.exponentialRampToValueAtTime(freq*1.5,t+dur);filt.Q.value=4;const g=ctx.createGain();o.connect(filt);filt.connect(g);g.connect(dest);const atk=p.attack||0.01,rel=p.release||0.2;g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(v*0.22,t+atk);g.gain.exponentialRampToValueAtTime(0.001,t+dur+rel);o.start(t);o.stop(t+dur+rel+0.05);});}
function qsPlayPad(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number,dur:number,p:any={}){const atk=p.attack||0.12,rel=p.release||0.4;[freq,freq*1.004,freq*2.006,freq*3.009].forEach((f,i)=>{const o=ctx.createOscillator();o.type=i<2?'sine':'triangle';o.frequency.value=f;const g=ctx.createGain();o.connect(g);g.connect(dest);g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(v*(0.16-i*0.03),t+atk);g.gain.setValueAtTime(v*(0.13-i*0.02),t+dur*0.75);g.gain.exponentialRampToValueAtTime(0.001,t+dur+rel);o.start(t);o.stop(t+dur+rel+0.05);});}
function qsPlayPluck(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number,p:any={}){const o=ctx.createOscillator();o.type=p.oscType||'sawtooth';o.frequency.value=freq;const f=ctx.createBiquadFilter();f.type='lowpass';f.frequency.setValueAtTime(freq*12,t);f.frequency.exponentialRampToValueAtTime(freq*0.8,t+0.3);f.Q.value=2;const g=ctx.createGain();o.connect(f);f.connect(g);g.connect(dest);g.gain.setValueAtTime(v*0.5,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.75);o.start(t);o.stop(t+0.8);}
function qsPlayKeys(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number,dur:number,p:any={}){const atk=p.attack||0.005,rel=p.release||0.5;[1,2,3,4,5].forEach((h,i)=>{const o=ctx.createOscillator();o.type='sine';o.frequency.value=freq*h;const g=ctx.createGain();o.connect(g);g.connect(dest);g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(v*0.4/Math.pow(h,0.7),t+atk);g.gain.exponentialRampToValueAtTime(0.001,t+dur+rel*(1-i*0.08));o.start(t);o.stop(t+dur+rel+0.05);});}
function qsPlayArp(ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number){const o=ctx.createOscillator();o.type='square';o.frequency.value=freq*2;const f=ctx.createBiquadFilter();f.type='bandpass';f.frequency.value=freq*5;f.Q.value=2.5;const g=ctx.createGain();o.connect(f);f.connect(g);g.connect(dest);g.gain.setValueAtTime(v*0.22,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.18);o.start(t);o.stop(t+0.2);}
function qsPlayFX(ctx:AudioContext,dest:AudioNode,t:number,v:number,noteIdx:number){const bl=ctx.sampleRate*0.35,buf=ctx.createBuffer(1,bl,ctx.sampleRate),d=buf.getChannelData(0);for(let i=0;i<bl;i++)d[i]=(Math.random()*2-1)*Math.pow(1-i/bl,1+noteIdx*0.4);const s=ctx.createBufferSource();s.buffer=buf;const f=ctx.createBiquadFilter();f.type='bandpass';f.frequency.value=600+noteIdx*500;f.Q.value=3.5;const g=ctx.createGain();g.gain.setValueAtTime(v*0.45,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.3);s.connect(f);f.connect(g);g.connect(dest);s.start(t);s.stop(t+0.35);}
function qsDispatch(id:string,ctx:AudioContext,dest:AudioNode,t:number,v:number,freq:number,dur:number,noteIdx:number,p:any={}){const vel=v<=1?v:v/127;switch(id){case'kick':qsPlayKick(ctx,dest,t,vel);break;case'snare':qsPlaySnare(ctx,dest,t,vel);break;case'hhc':qsPlayHHC(ctx,dest,t,vel);break;case'hho':qsPlayHHO(ctx,dest,t,vel);break;case'clap':qsPlayClap(ctx,dest,t,vel);break;case'tom_hi':qsPlayTom(ctx,dest,t,vel,170);break;case'tom_lo':qsPlayTom(ctx,dest,t,vel,100);break;case'cymbal':qsPlayCymbal(ctx,dest,t,vel);break;case'bass808':qsPlay808(ctx,dest,t,vel,freq,dur);break;case'basssynth':qsPlayBassS(ctx,dest,t,vel,freq,dur,p);break;case'lead':qsPlayLead(ctx,dest,t,vel,freq,dur,p);break;case'pad':qsPlayPad(ctx,dest,t,vel,freq*0.5,dur,p);break;case'pluck':qsPlayPluck(ctx,dest,t,vel,freq,p);break;case'keys':qsPlayKeys(ctx,dest,t,vel,freq,dur,p);break;case'arp':qsPlayArp(ctx,dest,t,vel,freq);break;case'fx':qsPlayFX(ctx,dest,t,vel,noteIdx);break;}}
function qsBuildChannel(ctx:AudioContext,masterGain:GainNode,reverb:ConvolverNode){const inp=ctx.createGain(),mute=ctx.createGain(),vol=ctx.createGain(),pan=ctx.createStereoPanner();mute.gain.value=1;vol.gain.value=0.85;const eqLo=ctx.createBiquadFilter();eqLo.type='lowshelf';eqLo.frequency.value=200;eqLo.gain.value=0;const eqMid=ctx.createBiquadFilter();eqMid.type='peaking';eqMid.frequency.value=1000;eqMid.Q.value=1;eqMid.gain.value=0;const eqHi=ctx.createBiquadFilter();eqHi.type='highshelf';eqHi.frequency.value=6000;eqHi.gain.value=0;const filt=ctx.createBiquadFilter();filt.type='lowpass';filt.frequency.value=20000;filt.Q.value=1;const dist=ctx.createWaveShaper();dist.curve=qsMakeDistCurve(0);const chorusDry=ctx.createGain();chorusDry.gain.value=1;const chorusWet=ctx.createGain();chorusWet.gain.value=0;const chorusDly1=ctx.createDelay(0.1);chorusDly1.delayTime.value=0.022;const chorusDly2=ctx.createDelay(0.1);chorusDly2.delayTime.value=0.028;const chorusLFO1=ctx.createOscillator();chorusLFO1.type='sine';chorusLFO1.frequency.value=0.8;const chorusLFO2=ctx.createOscillator();chorusLFO2.type='sine';chorusLFO2.frequency.value=1.1;const cLG1=ctx.createGain();cLG1.gain.value=0.003;const cLG2=ctx.createGain();cLG2.gain.value=0.003;chorusLFO1.connect(cLG1);cLG1.connect(chorusDly1.delayTime);chorusLFO1.start();chorusLFO2.connect(cLG2);cLG2.connect(chorusDly2.delayTime);chorusLFO2.start();const chorusMix=ctx.createGain();const phaserDry=ctx.createGain();phaserDry.gain.value=1;const phaserWet=ctx.createGain();phaserWet.gain.value=0;const phaserFilters=[350,700,1400,2800].map(freq=>{const f=ctx.createBiquadFilter();f.type='allpass';f.frequency.value=freq;f.Q.value=10;return f;});for(let i=0;i<phaserFilters.length-1;i++)phaserFilters[i].connect(phaserFilters[i+1]);const phaserLFO=ctx.createOscillator();phaserLFO.frequency.value=0.5;const phaserLFOG=ctx.createGain();phaserLFOG.gain.value=0;phaserLFO.connect(phaserLFOG);phaserFilters.forEach(f=>phaserLFOG.connect(f.frequency));phaserLFO.start();const comp=ctx.createDynamicsCompressor();comp.threshold.value=-24;comp.ratio.value=4;comp.attack.value=0.003;comp.release.value=0.25;comp.knee.value=6;const rvbS=ctx.createGain();rvbS.gain.value=0;const dlyN=ctx.createDelay(2);dlyN.delayTime.value=0.25;const dlyF=ctx.createGain();dlyF.gain.value=0.35;const dlyS=ctx.createGain();dlyS.gain.value=0;inp.connect(mute);mute.connect(vol);vol.connect(pan);pan.connect(eqLo);eqLo.connect(eqMid);eqMid.connect(eqHi);eqHi.connect(filt);filt.connect(dist);dist.connect(chorusDry);chorusDly1.connect(chorusMix);chorusDly2.connect(chorusMix);dist.connect(chorusDly1);dist.connect(chorusDly2);chorusDry.connect(comp);chorusMix.connect(chorusWet);chorusWet.connect(comp);comp.connect(phaserDry);comp.connect(phaserFilters[0]);phaserDry.connect(masterGain);phaserFilters[phaserFilters.length-1].connect(phaserWet);phaserWet.connect(masterGain);comp.connect(rvbS);rvbS.connect(reverb);comp.connect(dlyS);dlyS.connect(dlyN);dlyN.connect(dlyF);dlyF.connect(dlyN);dlyN.connect(masterGain);return{inp,mute,vol,pan,eqLo,eqMid,eqHi,filt,dist,chorusDry,chorusWet,phaserDry,phaserWet,phaserLFOG,comp,rvbS,dlyS,dlyN,dlyF};}

function qsWavFromBuffer(audioBuffer:AudioBuffer){const numCh=audioBuffer.numberOfChannels,len=audioBuffer.length,sr=audioBuffer.sampleRate;const buf=new ArrayBuffer(44+len*numCh*2),v=new DataView(buf);const ws=(off:number,s:string)=>{for(let i=0;i<s.length;i++)v.setUint8(off+i,s.charCodeAt(i));};ws(0,'RIFF');v.setUint32(4,36+len*numCh*2,true);ws(8,'WAVE');ws(12,'fmt ');v.setUint32(16,16,true);v.setUint16(20,1,true);v.setUint16(22,numCh,true);v.setUint32(24,sr,true);v.setUint32(28,sr*numCh*2,true);v.setUint16(32,numCh*2,true);v.setUint16(34,16,true);ws(36,'data');v.setUint32(40,len*numCh*2,true);let off=44;for(let i=0;i<len;i++)for(let ch=0;ch<numCh;ch++){const s=Math.max(-1,Math.min(1,audioBuffer.getChannelData(ch)[i]));v.setInt16(off,s<0?s*0x8000:s*0x7FFF,true);off+=2;}return buf;}
async function qsExportWav(params:{patterns:any,mixer:any,bpm:number,steps:number,musicalKey:string,activePattern:string,swing:number}){const{patterns,mixer,bpm,steps,musicalKey,activePattern,swing=0}=params;const stepDur=60/bpm/4,totalDur=stepDur*steps*4+3;const offCtx=new OfflineAudioContext(2,Math.ceil(44100*totalDur),44100);const master=offCtx.createGain();master.gain.value=mixer.__master?.volume??0.75;const comp=offCtx.createDynamicsCompressor();comp.threshold.value=-12;comp.ratio.value=4;master.connect(comp);comp.connect(offCtx.destination);const reverb=offCtx.createConvolver();reverb.buffer=qsCreateReverb(offCtx);reverb.connect(master);const channels:Record<string,GainNode>={};INSTRUMENTS.forEach(inst=>{const vol=offCtx.createGain();vol.gain.value=mixer[inst.id]?.mute?0:(mixer[inst.id]?.volume??0.85);const pan=offCtx.createStereoPanner();pan.pan.value=mixer[inst.id]?.pan??0;vol.connect(pan);pan.connect(master);channels[inst.id]=vol;});const patData=patterns[activePattern]||{};for(let loop=0;loop<4;loop++)for(let step=0;step<steps;step++){const swingOff=step%2===1?swing*stepDur*0.5:0,t=(loop*steps+step)*stepDur+swingOff;INSTRUMENTS.forEach(inst=>{const track=patData[inst.id];if(!track)return;const s=track[step];if(!s?.active)return;if(mixer[inst.id]?.mute)return;const freq=qsGetScaleNote(musicalKey,s.note??0),dur=stepDur*(s.length??1)*0.95;qsDispatch(inst.id,offCtx as any,channels[inst.id],t,s.velocity??100,freq,dur,s.note??0,mixer[inst.id]?.synth||{});});}const rendered=await offCtx.startRendering();const wav=qsWavFromBuffer(rendered),blob=new Blob([wav],{type:'audio/wav'}),url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`quantum_studio_${Date.now()}.wav`;a.click();URL.revokeObjectURL(url);}
async function qsExportStems(params:{patterns:any,mixer:any,bpm:number,steps:number,musicalKey:string,activePattern:string,swing:number}){const{patterns,mixer,bpm,steps,musicalKey,activePattern,swing=0}=params;const stepDur=60/bpm/4,totalDur=stepDur*steps*4+3;for(const inst of INSTRUMENTS){if(mixer[inst.id]?.mute)continue;const offCtx=new OfflineAudioContext(2,Math.ceil(44100*totalDur),44100);const master=offCtx.createGain();master.gain.value=1;master.connect(offCtx.destination);const reverb=offCtx.createConvolver();reverb.buffer=qsCreateReverb(offCtx);reverb.connect(master);const vol=offCtx.createGain();vol.gain.value=mixer[inst.id]?.volume??0.85;const pan=offCtx.createStereoPanner();pan.pan.value=mixer[inst.id]?.pan??0;vol.connect(pan);pan.connect(master);const patData=patterns[activePattern]||{};for(let loop=0;loop<4;loop++)for(let step=0;step<steps;step++){const swingOff=step%2===1?swing*stepDur*0.5:0,t=(loop*steps+step)*stepDur+swingOff;const track=patData[inst.id];if(!track)continue;const s=track[step];if(!s?.active)continue;const freq=qsGetScaleNote(musicalKey,s.note??0),dur=stepDur*(s.length??1)*0.95;qsDispatch(inst.id,offCtx as any,vol,t,s.velocity??100,freq,dur,s.note??0,mixer[inst.id]?.synth||{});}const rendered=await offCtx.startRendering();const wav=qsWavFromBuffer(rendered),blob=new Blob([wav],{type:'audio/wav'}),url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`stem_${inst.id}_${Date.now()}.wav`;a.click();URL.revokeObjectURL(url);await new Promise(r=>setTimeout(r,200));}}
function qsExportMidi(notes:any[],bpm=140,instrumentName='Piano Roll'){if(!notes.length){alert('No notes to export.');return;}const ticksPerBeat=480,msPerBeat=Math.round(60000000/bpm);function varLen(n:number):number[]{if(n===0)return[0];const bytes:number[]=[];while(n>0){bytes.unshift(n&0x7F);n>>=7;}for(let i=0;i<bytes.length-1;i++)bytes[i]|=0x80;return bytes;}const events:any[]=[];notes.forEach(note=>{const st=Math.round(note.startStep*ticksPerBeat/4),et=st+Math.max(1,Math.round(note.lengthSteps*ticksPerBeat/4));events.push({tick:st,type:'on',pitch:note.pitch,velocity:note.velocity||100});events.push({tick:et,type:'off',pitch:note.pitch});});events.sort((a,b)=>a.tick-b.tick||(a.type==='off'?-1:1));const trackData:number[]=[];trackData.push(...varLen(0),0xFF,0x51,0x03,(msPerBeat>>16)&0xFF,(msPerBeat>>8)&0xFF,msPerBeat&0xFF);const nameBytes=[...instrumentName].map(c=>c.charCodeAt(0));trackData.push(...varLen(0),0xFF,0x03,...varLen(nameBytes.length),...nameBytes);let lastTick=0;events.forEach(ev=>{const delta=ev.tick-lastTick;lastTick=ev.tick;trackData.push(...varLen(delta));trackData.push(ev.type==='on'?0x90:0x80,ev.pitch,ev.type==='on'?ev.velocity:0);});trackData.push(0,0xFF,0x2F,0);const header=[0x4D,0x54,0x68,0x64,0,0,0,6,0,0,0,1,(ticksPerBeat>>8)&0xFF,ticksPerBeat&0xFF];const tLen=trackData.length;const trackHeader=[0x4D,0x54,0x72,0x6B,(tLen>>24)&0xFF,(tLen>>16)&0xFF,(tLen>>8)&0xFF,tLen&0xFF];const bytes=new Uint8Array([...header,...trackHeader,...trackData]);const blob=new Blob([bytes],{type:'audio/midi'}),url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`${instrumentName.replace(/ /g,'_')}_${Date.now()}.mid`;a.click();URL.revokeObjectURL(url);}

const QS_ALL_PATTERNS=['A','B','C','D','E','F','G','H'];
const QS_STEPS_DEFAULT=16;
const QS_TRANSPORT_KEYS=['C Major','C Minor','C# Major','C# Minor','D Major','D Minor','Eb Major','Eb Minor','E Major','E Minor','F Major','F Minor','F# Major','F# Minor','G Major','G Minor','Ab Major','Ab Minor','A Major','A Minor','Bb Major','Bb Minor','B Major','B Minor'];
const QS_GENRES=['trap','hip_hop','drill','lofi','rnb','electronic','pop','afrobeat','jazz','reggaeton','rock','synthwave','ambient','drum_and_bass','house','classical','techno','dnb','dubstep','future_bass','phonk','hyperpop'];
const QS_PATTERN_COLORS:Record<string,string>={A:'#8b5cf6',B:'#06b6d4',C:'#f97316',D:'#22c55e',E:'#f43f5e',F:'#eab308',G:'#14b8a6',H:'#ec4899'};
function qsDefaultTrack(steps:number){return Array(steps).fill(null).map(()=>({active:false,velocity:100,note:0,length:1}));}
function qsBuildEmptyPattern(steps:number){const p:any={};INSTRUMENTS.forEach(inst=>{p[inst.id]=qsDefaultTrack(steps);});return p;}
function qsBuildDefaultMixer(){const m:any={__master:{volume:0.75}};INSTRUMENTS.forEach(inst=>{m[inst.id]={volume:0.85,pan:0,mute:false,solo:false,eqLo:0,eqMid:0,eqHi:0,eqMidFreq:1000,reverb:0,delay:0,delayFeedback:0.35,distortion:0,chorus:0,phaser:0,compThreshold:-24,compRatio:4,filterType:'lowpass',filterCutoff:20000,filterRes:1,synth:{}};});return m;}
function qsBuildInitialPatterns(steps:number){const p:any={};QS_ALL_PATTERNS.forEach(pat=>{p[pat]=qsBuildEmptyPattern(steps);});return p;}
function qsBuildInitialPianoRoll(){const n:any={};QS_ALL_PATTERNS.forEach(p=>{n[p]={};});return n;}

function useQsAudioEngine(){
  const ctxRef=useRef<AudioContext|null>(null),masterRef=useRef<GainNode|null>(null),reverbRef=useRef<ConvolverNode|null>(null);
  const chansRef=useRef<Record<string,any>>({}),timerRef=useRef<any>(null),stepRef=useRef(0),nextRef=useRef(0);
  const [isPlaying,setIsPlaying]=useState(false);
  const [currentStep,setCurrentStep]=useState(-1);
  const patternsRef=useRef<any>({}),mixerRef=useRef<any>({}),bpmRef=useRef(140),patternRef=useRef('A');
  const stepsRef=useRef(16),keyRef=useRef('C Minor'),swingRef=useRef(0);
  const pianoRollRef=useRef<any>({}),arrangementRef=useRef<any[]>([]),arrangeModeRef=useRef(false);
  const globalStepRef=useRef(0);
  const updateRefs=useCallback((patterns:any,mixer:any,bpm:number,activePattern:string,steps:number,musicalKey:string,masterVol:number,swing=0,pianoRoll:any={},arrangement:any[]=[],arrangeMode=false)=>{
    patternsRef.current=patterns;mixerRef.current=mixer;bpmRef.current=bpm;patternRef.current=activePattern;
    stepsRef.current=steps;keyRef.current=musicalKey;swingRef.current=swing;
    pianoRollRef.current=pianoRoll;arrangementRef.current=arrangement;arrangeModeRef.current=arrangeMode;
    if(masterRef.current&&ctxRef.current)masterRef.current.gain.setTargetAtTime(masterVol??0.75,ctxRef.current.currentTime,0.02);
  },[]);
  const applyMixer=useCallback(()=>{
    const ctx=ctxRef.current;if(!ctx)return;
    const mixer=mixerRef.current,t=ctx.currentTime;
    Object.entries(mixer).forEach(([id,ch]:any)=>{
      const c=chansRef.current[id];if(!c)return;
      c.mute.gain.setTargetAtTime(ch.mute?0:1,t,0.01);
      c.vol.gain.setTargetAtTime(ch.mute?0:(ch.volume??0.85),t,0.01);
      c.pan.pan.setTargetAtTime(ch.pan??0,t,0.01);
      c.filt.frequency.setTargetAtTime(ch.filterCutoff??20000,t,0.01);
      c.filt.Q.value=ch.filterRes??1;c.filt.type=ch.filterType??'lowpass';
      c.rvbS.gain.setTargetAtTime(ch.reverb??0,t,0.01);
      c.dlyS.gain.setTargetAtTime(ch.delay??0,t,0.01);
      c.dlyF.gain.value=ch.delayFeedback??0.35;
      c.dist.curve=qsMakeDistCurve(ch.distortion??0);
      c.eqLo.gain.setTargetAtTime(ch.eqLo??0,t,0.01);
      c.eqMid.gain.setTargetAtTime(ch.eqMid??0,t,0.01);
      c.eqHi.gain.setTargetAtTime(ch.eqHi??0,t,0.01);
      if(ch.eqMidFreq)c.eqMid.frequency.setTargetAtTime(ch.eqMidFreq,t,0.01);
      c.chorusWet.gain.setTargetAtTime(ch.chorus??0,t,0.01);
      c.chorusDry.gain.setTargetAtTime(1-(ch.chorus??0)*0.5,t,0.01);
      c.phaserWet.gain.setTargetAtTime(ch.phaser??0,t,0.01);
      c.phaserLFOG.gain.setTargetAtTime((ch.phaser??0)*800,t,0.01);
      if(ch.compThreshold!==undefined)c.comp.threshold.setTargetAtTime(ch.compThreshold??-24,t,0.01);
      if(ch.compRatio!==undefined)c.comp.ratio.setTargetAtTime(ch.compRatio??4,t,0.01);
    });
  },[]);
  const getPatternForStep=useCallback((globalStep:number)=>{
    if(!arrangeModeRef.current||!arrangementRef.current.length)return patternRef.current;
    const bar=Math.floor(globalStep/stepsRef.current);
    const sorted=[...arrangementRef.current].sort((a:any,b:any)=>a.bar-b.bar);
    let activeP=sorted[0]?.patternId||patternRef.current;
    for(const block of sorted){if(block.bar<=bar)activeP=block.patternId;else break;}
    return activeP;
  },[]);
  const scheduleStep=useCallback((step:number,time:number,globalStep:number)=>{
    const ctx=ctxRef.current;if(!ctx)return;
    const swing=swingRef.current,swingOffset=step%2===1?swing*(60/bpmRef.current/4)*0.5:0,t=time+swingOffset;
    const currentPattern=arrangeModeRef.current?getPatternForStep(globalStep):patternRef.current;
    const patData=patternsRef.current[currentPattern];if(!patData)return;
    const stepDur=60/bpmRef.current/4;
    INSTRUMENTS.forEach(inst=>{
      const mixer=mixerRef.current[inst.id];if(mixer?.mute)return;
      const ch=chansRef.current[inst.id];if(!ch)return;
      const params=mixer?.synth||{};
      const prNotes=pianoRollRef.current?.[currentPattern]?.[inst.id];
      if(prNotes?.length){prNotes.forEach((note:any)=>{if(note.startStep===step){const freq=qsMidiToFreq(note.pitch),dur=stepDur*note.lengthSteps*0.95;qsDispatch(inst.id,ctx,ch.inp,t+(Math.random()-0.5)*0.002,note.velocity??100,freq,dur,0,params);}});return;}
      const track=patData[inst.id];if(!track)return;
      const s=track[step];if(!s?.active)return;
      const freq=qsGetScaleNote(keyRef.current,s.note??0),dur=stepDur*(s.length??1)*0.95;
      qsDispatch(inst.id,ctx,ch.inp,t+(Math.random()-0.5)*0.003,s.velocity??100,freq,dur,s.note??0,params);
    });
    applyMixer();
  },[applyMixer,getPatternForStep]);
  const scheduler=useCallback(()=>{
    const ctx=ctxRef.current;if(!ctx)return;
    const stepDur=60/bpmRef.current/4,totalSteps=stepsRef.current;
    while(nextRef.current<ctx.currentTime+0.12){
      const step=stepRef.current%totalSteps;
      scheduleStep(step,nextRef.current,globalStepRef.current);
      setCurrentStep(step);
      stepRef.current=(step+1)%totalSteps;
      globalStepRef.current++;
      nextRef.current+=stepDur;
    }
  },[scheduleStep]);
  const init=useCallback(()=>{
    if(ctxRef.current)return;
    const ctx=new (window.AudioContext||(window as any).webkitAudioContext)();
    ctxRef.current=ctx;
    const master=ctx.createGain();master.gain.value=0.75;masterRef.current=master;
    const comp=ctx.createDynamicsCompressor();comp.threshold.value=-12;comp.knee.value=6;comp.ratio.value=4;comp.attack.value=0.003;comp.release.value=0.25;
    master.connect(comp);comp.connect(ctx.destination);
    const reverb=ctx.createConvolver();reverb.buffer=qsCreateReverb(ctx);
    reverb.connect(master);reverbRef.current=reverb;
    INSTRUMENTS.forEach(inst=>{chansRef.current[inst.id]=qsBuildChannel(ctx,master,reverb);});
  },[]);
  const play=useCallback(()=>{
    init();const ctx=ctxRef.current!;
    if(ctx.state==='suspended')ctx.resume();
    stepRef.current=0;globalStepRef.current=0;nextRef.current=ctx.currentTime+0.05;
    timerRef.current=setInterval(scheduler,25);
    setIsPlaying(true);
  },[init,scheduler]);
  const stop=useCallback(()=>{clearInterval(timerRef.current);setIsPlaying(false);setCurrentStep(-1);stepRef.current=0;globalStepRef.current=0;},[]);
  useEffect(()=>()=>{clearInterval(timerRef.current);ctxRef.current?.close();},[]);
  return{isPlaying,currentStep,play,stop,updateRefs};
}

async function qsGenerateAIPattern({genre,mood,bpm,musicalKey,steps=16}:{genre:string,mood:string,bpm:number,musicalKey:string,steps:number}){
  const instrList=INSTRUMENTS.map(i=>`${i.id} (${i.name}, type:${i.type})`).join(', ');
  const prompt=`You are a world-class music producer. Create a beat pattern for a DAW step sequencer.
Genre:${genre}, Mood:${mood||'energetic'}, BPM:${bpm}, Key:${musicalKey}, Steps:${steps} (each=1/16 note)
Instruments: ${instrList}
Rules: active=true/false, velocity=60-127, note=0-7 (scale degree), length=1-4.
Return ONLY valid JSON: {"pattern":{"kick":[{"active":bool,"velocity":num,"note":num,"length":num},...repeat for all ${steps} steps],...for each instrument},"description":"string"}`;
  const res=await fetch('/api/chat/completions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({messages:[{role:'user',content:prompt}]})});
  const data=await res.json();
  const text=(data.content||'{}').replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  let parsed:any={};
  try{parsed=JSON.parse(text);}catch{parsed={pattern:{},description:'AI generated pattern'};}
  const normalized:any={};
  INSTRUMENTS.forEach(inst=>{
    const raw=parsed.pattern?.[inst.id];
    if(Array.isArray(raw)&&raw.length===steps){normalized[inst.id]=raw.map((s:any)=>({active:!!s.active,velocity:Math.min(127,Math.max(1,s.velocity??100)),note:Math.min(7,Math.max(0,s.note??0)),length:Math.min(4,Math.max(1,s.length??1))}));}
    else{normalized[inst.id]=qsDefaultTrack(steps);}
  });
  return{pattern:normalized,description:parsed.description||''};
}

const QS_TYPE_LABELS:Record<string,string>={drum:'DRUMS',bass:'BASS',melodic:'MELODIC',fx:'FX'};
const QS_SEQ_NOTES=['C','D','E','F','G','A','B','C2'];
const QS_VEL_CYCLE=[25,50,75,100,127];

function QsStepSequencer({patterns,activePattern,currentStep,steps,onToggleStep,onSetNote,onSetVelocity,selectedChannel,onSelectChannel}:any){
  const patData=patterns[activePattern]||{};
  const groups=Object.entries(INSTRUMENTS.reduce((acc:any,inst)=>{if(!acc[inst.type])acc[inst.type]=[];acc[inst.type].push(inst);return acc;},{}));
  return(
    <div className="flex-1 overflow-y-auto bg-[#0a0a0f]">
      <div className="overflow-x-auto min-w-0">
        <div className="min-w-max p-3 space-y-1">
          {(groups as [string,any[]][]).map(([type,insts])=>(
            <div key={type}>
              <div className="text-[9px] font-black tracking-widest text-white/20 uppercase px-2 py-1">{QS_TYPE_LABELS[type]}</div>
              {insts.map((inst:any)=>{
                const track=patData[inst.id]||[],isSelected=selectedChannel===inst.id;
                return(
                  <div key={inst.id} className={cn("flex items-center gap-1 rounded-lg px-1 py-0.5 transition-colors cursor-pointer",isSelected?"bg-white/5":"hover:bg-white/[0.03]")} onClick={()=>onSelectChannel(isSelected?null:inst.id)}>
                    <div className="w-20 flex-shrink-0 flex items-center gap-1.5 px-1">
                      <div className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{backgroundColor:inst.color}}/>
                      <span className="text-[10px] font-semibold truncate" style={{color:inst.color}}>{inst.name}</span>
                    </div>
                    <div className="flex items-center">
                      {Array(steps).fill(0).map((_:any,si:number)=>{
                        const s=track[si]||{active:false,velocity:100,note:0};
                        const isActive=s.active,isCurrent=currentStep===si,showBar=si>0&&si%4===0;
                        const velHex=Math.round(((s.velocity??100)/127)*215+40).toString(16).padStart(2,'0');
                        return(
                          <div key={si} className="flex items-center">
                            {showBar&&<div className="w-px h-5 bg-white/10 mx-0.5"/>}
                            <button
                              onClick={e=>{e.stopPropagation();onToggleStep(inst.id,si);}}
                              onContextMenu={e=>{e.preventDefault();e.stopPropagation();if(isActive){if(inst.type==='drum'){const cur=s.velocity??100;const idx=QS_VEL_CYCLE.findIndex((v:number)=>v>=cur);onSetVelocity(inst.id,si,QS_VEL_CYCLE[(idx+1)%QS_VEL_CYCLE.length]);}else{onSetNote(inst.id,si,((s.note||0)+1)%8);}}}}
                              className="w-7 h-7 rounded-sm transition-all duration-75 flex-shrink-0 relative overflow-hidden border border-transparent"
                              style={{backgroundColor:isActive?isCurrent?inst.color:`${inst.color}${velHex}`:isCurrent?`${inst.color}20`:'rgba(255,255,255,0.04)',boxShadow:isActive&&isCurrent?`0 0 10px ${inst.color}80`:'none',borderColor:isCurrent?`${inst.color}60`:'transparent',transform:isActive&&isCurrent?'scale(1.08)':'scale(1)'}}
                            >
                              {isActive&&<div className="absolute inset-0 opacity-20 bg-gradient-to-b from-white to-transparent"/>}
                            </button>
                          </div>
                        );
                      })}
                    </div>
                    <div className="w-10 flex-shrink-0 text-[9px] text-white/25 text-center ml-1">
                      {(()=>{const a=track.find((s:any)=>s?.active);return a?(inst.type==='drum'?`v${a.velocity??100}`:QS_SEQ_NOTES[a.note||0]):'';})()}
                    </div>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function QsMixerChannel({inst,ch,onUpdate,isSelected,onSelect}:any){
  return(
    <div onClick={()=>onSelect(isSelected?null:inst.id)} className={cn("flex flex-col items-center gap-1 px-1.5 py-2 rounded-lg cursor-pointer transition-all min-w-[58px]",isSelected?"bg-white/8 ring-1 ring-white/20":"hover:bg-white/4")}>
      <div className="text-[8px] font-bold uppercase tracking-wider truncate w-full text-center" style={{color:inst.color}}>{inst.name}</div>
      <div className="flex gap-1 mb-1">
        <button onClick={e=>{e.stopPropagation();onUpdate(inst.id,'solo',!ch.solo);}} className={cn("w-5 h-4 rounded text-[8px] font-black",ch.solo?"bg-yellow-500/80 text-black":"bg-white/8 text-white/30 hover:bg-white/15")}>S</button>
        <button onClick={e=>{e.stopPropagation();onUpdate(inst.id,'mute',!ch.mute);}} className={cn("w-5 h-4 rounded text-[8px] font-black",ch.mute?"bg-red-500/80 text-white":"bg-white/8 text-white/30 hover:bg-white/15")}>M</button>
      </div>
      <div className="flex items-end gap-0.5 h-20 mb-1">
        <input type="range" min={0} max={1} step={0.01} value={ch.pan??0} onChange={e=>{e.stopPropagation();onUpdate(inst.id,'pan',parseFloat(e.target.value));}} className="w-3 h-20 cursor-pointer accent-gray-400" style={{writingMode:'vertical-lr',direction:'rtl'}} title="Pan"/>
        <input type="range" min={0} max={1.5} step={0.01} value={ch.volume??0.85} onChange={e=>{e.stopPropagation();onUpdate(inst.id,'volume',parseFloat(e.target.value));}} className="w-4 h-20 cursor-pointer" style={{writingMode:'vertical-lr',direction:'rtl',accentColor:inst.color}} title="Volume"/>
      </div>
      <div className="text-[8px] text-white/30 tabular-nums">{Math.round((ch.volume??0.85)*100)}%</div>
    </div>
  );
}

function QsMixerPanel({mixer,onUpdate,selectedChannel,onSelectChannel}:any){
  return(
    <div className="border-t border-white/5 bg-[#0c0c14]">
      <div className="flex items-center gap-2 px-3 py-1.5 border-b border-white/5">
        <Sliders className="w-3 h-3 text-white/30"/>
        <span className="text-[9px] font-black tracking-widest text-white/30 uppercase">Mixer</span>
        <div className="ml-2 flex items-center gap-1.5">
          <span className="text-[9px] text-white/20">Master Vol</span>
          <input type="range" min={0} max={1} step={0.01} value={mixer.__master?.volume??0.75} onChange={e=>onUpdate('__master','volume',parseFloat(e.target.value))} className="w-16 cursor-pointer accent-violet-500"/>
          <span className="text-[9px] text-white/30 tabular-nums w-6">{Math.round((mixer.__master?.volume??0.75)*100)}%</span>
        </div>
      </div>
      <div className="flex overflow-x-auto px-2 py-2 gap-1">
        {INSTRUMENTS.map((inst:any)=>(
          <QsMixerChannel key={inst.id} inst={inst} ch={mixer[inst.id]||{}} onUpdate={onUpdate} isSelected={selectedChannel===inst.id} onSelect={onSelectChannel}/>
        ))}
      </div>
    </div>
  );
}

function QsEffectsRack({channelId,effects,onUpdate,onClose}:any){
  const inst=INSTRUMENTS.find(i=>i.id===channelId);if(!inst)return null;
  const Knob=({label,value,min=0,max=1,step=0.01,field,unit=''}:{label:string,value:number,min?:number,max?:number,step?:number,field:string,unit?:string})=>(
    <div className="space-y-1 min-w-[75px]">
      <div className="flex justify-between"><span className="text-[9px] text-white/40 uppercase tracking-wider">{label}</span><span className="text-[9px] font-mono tabular-nums" style={{color:inst.color}}>{typeof value==='number'?value.toFixed(unit==='dB'||unit===':1'?1:2):value}{unit}</span></div>
      <input type="range" min={min} max={max} step={step} value={value} onChange={e=>onUpdate(field,parseFloat(e.target.value))} className="w-full cursor-pointer" style={{accentColor:inst.color}}/>
    </div>
  );
  return(
    <div className="border-t border-white/5 bg-[#0e0e14] px-4 py-3">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2"><div className="w-2 h-2 rounded-full" style={{backgroundColor:inst.color}}/><span className="text-xs font-bold" style={{color:inst.color}}>{inst.name}</span><span className="text-[9px] text-white/30 uppercase tracking-widest ml-1">Channel FX</span></div>
        <button onClick={onClose} className="text-white/30 hover:text-white/70 transition-colors"><X className="w-4 h-4"/></button>
      </div>
      <div className="flex flex-wrap gap-5 overflow-x-auto pb-2">
        <div className="space-y-2 min-w-[80px]"><div className="text-[9px] text-white/20 uppercase tracking-widest font-black">Gain</div><Knob label="Volume" value={effects.volume??0.85} field="volume"/><Knob label="Pan" value={effects.pan??0} min={-1} max={1} field="pan"/></div>
        <div className="space-y-2 min-w-[80px]"><div className="text-[9px] text-white/20 uppercase tracking-widest font-black">EQ 3-Band</div><Knob label="Low" value={effects.eqLo??0} min={-12} max={12} step={0.5} field="eqLo" unit="dB"/><Knob label="Mid" value={effects.eqMid??0} min={-12} max={12} step={0.5} field="eqMid" unit="dB"/><Knob label="High" value={effects.eqHi??0} min={-12} max={12} step={0.5} field="eqHi" unit="dB"/></div>
        <div className="space-y-2 min-w-[80px]"><div className="text-[9px] text-white/20 uppercase tracking-widest font-black">Compressor</div><Knob label="Threshold" value={effects.compThreshold??-24} min={-60} max={0} step={1} field="compThreshold" unit="dB"/><Knob label="Ratio" value={effects.compRatio??4} min={1} max={20} step={0.5} field="compRatio" unit=":1"/></div>
        <div className="space-y-2 min-w-[80px]"><div className="text-[9px] text-white/20 uppercase tracking-widest font-black">Filter</div>
          <div className="space-y-1"><span className="text-[9px] text-white/40 uppercase">Type</span><select value={effects.filterType??'lowpass'} onChange={e=>onUpdate('filterType',e.target.value)} className="w-full bg-white/5 border border-white/10 rounded text-white/60 text-[10px] px-1 py-0.5">{['lowpass','highpass','bandpass','notch'].map(t=><option key={t} value={t}>{t}</option>)}</select></div>
          <Knob label="Cutoff" value={effects.filterCutoff??20000} min={80} max={20000} step={10} field="filterCutoff" unit="Hz"/></div>
        <div className="space-y-2 min-w-[80px]"><div className="text-[9px] text-white/20 uppercase tracking-widest font-black">Time FX</div><Knob label="Reverb" value={effects.reverb??0} field="reverb"/><Knob label="Delay Wet" value={effects.delay??0} field="delay"/><Knob label="Delay FB" value={effects.delayFeedback??0.35} field="delayFeedback"/></div>
        <div className="space-y-2 min-w-[80px]"><div className="text-[9px] text-white/20 uppercase tracking-widest font-black">FX</div><Knob label="Distortion" value={effects.distortion??0} field="distortion"/><Knob label="Chorus" value={effects.chorus??0} field="chorus"/><Knob label="Phaser" value={effects.phaser??0} field="phaser"/></div>
      </div>
    </div>
  );
}

const QS_NOTE_HEIGHT=14,QS_STEP_WIDTH=32,QS_MIN_MIDI=36,QS_MAX_MIDI=96,QS_TOTAL_NOTES=QS_MAX_MIDI-QS_MIN_MIDI;
const QS_BLACK_NOTES=[1,3,6,8,10];
function qsIsBlack(midi:number){return QS_BLACK_NOTES.includes(midi%12);}

function QsPianoRoll({notes,onNotesChange,steps,musicalKey,activePattern,activeInstrument,onInstrumentChange,bpm}:any){
  const gridRef=useRef<HTMLDivElement>(null);
  const [scaleLock,setScaleLock]=useState(false);
  const [quantize,setQuantize]=useState(1);
  const inst=INSTRUMENTS.find(i=>i.id===activeInstrument)||INSTRUMENTS[10];
  const scaleNotes=qsGetScaleNotes(musicalKey);
  const notesForInst=notes||[];
  const snapToScale=useCallback((pitch:number)=>{
    const noteInOctave=pitch%12;if(scaleNotes.includes(noteInOctave))return pitch;
    let best=scaleNotes[0]??0,bestDist=13;
    scaleNotes.forEach((sn:number)=>{const dist=Math.min(Math.abs(noteInOctave-sn),12-Math.abs(noteInOctave-sn));if(dist<bestDist){bestDist=dist;best=sn;}});
    let final=Math.floor(pitch/12)*12+best;
    if(final<QS_MIN_MIDI)final+=12;if(final>QS_MAX_MIDI)final-=12;return final;
  },[scaleNotes]);
  const addNote=useCallback((pitch:number,startStep:number)=>{
    const fp=scaleLock?snapToScale(pitch):pitch;
    const snap=Math.floor(startStep/quantize)*quantize;
    const existing=notesForInst.find((n:any)=>n.pitch===fp&&n.startStep===snap);
    if(existing){onNotesChange(notesForInst.filter((n:any)=>n!==existing));return;}
    onNotesChange([...notesForInst,{id:`${Date.now()}_${Math.random()}`,pitch:fp,startStep:snap,lengthSteps:quantize,velocity:100}]);
  },[notesForInst,onNotesChange,scaleLock,snapToScale,quantize]);
  const removeNote=useCallback((id:string)=>onNotesChange(notesForInst.filter((n:any)=>n.id!==id)),[notesForInst,onNotesChange]);
  const resizeNote=useCallback((id:string,newLen:number)=>onNotesChange(notesForInst.map((n:any)=>n.id===id?{...n,lengthSteps:Math.max(quantize,newLen)}:n)),[notesForInst,onNotesChange,quantize]);
  const gridH=QS_TOTAL_NOTES*QS_NOTE_HEIGHT,gridW=steps*QS_STEP_WIDTH;
  return(
    <div className="flex flex-col h-full bg-[#080810]">
      <div className="flex items-center gap-2 px-4 py-2 border-b border-white/5 bg-[#0d0d12] flex-wrap">
        <span className="text-[10px] text-white/30 uppercase tracking-widest font-bold">Piano Roll</span>
        <select value={activeInstrument} onChange={e=>onInstrumentChange(e.target.value)} className="h-7 bg-white/5 border border-white/10 rounded text-xs px-2" style={{color:inst.color}}>
          {INSTRUMENTS.filter(i=>i.type!=='drum'&&i.type!=='fx').map(i=><option key={i.id} value={i.id}>{i.name}</option>)}
        </select>
        <div className="flex items-center gap-1">
          <span className="text-[9px] text-white/30 uppercase">Q:</span>
          {[1,2,4].map(q=><button key={q} onClick={()=>setQuantize(q)} className={cn("h-6 px-1.5 rounded text-[9px] font-bold border",quantize===q?"bg-violet-500/20 border-violet-500/40 text-violet-400":"border-white/10 text-white/30 hover:text-white/60")}>{q===1?'1/16':q===2?'1/8':'1/4'}</button>)}
        </div>
        <div className="flex items-center gap-1 ml-auto">
          <button onClick={()=>setScaleLock(v=>!v)} className={cn("h-6 px-2.5 rounded text-[9px] font-bold border",scaleLock?"bg-green-500/20 border-green-500/40 text-green-400":"border-white/10 text-white/30 hover:text-white/60")}>{scaleLock?'🔒 Scale Lock':'Scale Lock'}</button>
          <button onClick={()=>qsExportMidi(notesForInst,bpm||140,inst.name)} disabled={!notesForInst.length} className="h-6 px-2.5 rounded text-[9px] font-bold border border-white/10 text-white/30 hover:text-cyan-400 hover:border-cyan-400/30 disabled:opacity-30">MIDI</button>
          <button onClick={()=>onNotesChange([])} className="h-6 px-2.5 rounded text-[9px] font-bold text-white/20 hover:text-red-400">Clear</button>
        </div>
      </div>
      <div className="flex flex-1 overflow-auto">
        <div className="flex-shrink-0 w-12 relative" style={{height:gridH}}>
          {Array.from({length:QS_TOTAL_NOTES},(_,i)=>{const midi=QS_MAX_MIDI-1-i,black=qsIsBlack(midi),inScale=scaleNotes.includes(midi%12),isC=midi%12===0;return(<div key={midi} className={cn("absolute flex items-center justify-end pr-1 border-b select-none",black?"bg-[#1a1a22] text-white/30 border-white/5 z-10 w-8":"bg-[#111118] text-white/20 border-white/5 w-12",inScale&&!black&&"bg-[#0f1020]")} style={{top:i*QS_NOTE_HEIGHT,height:QS_NOTE_HEIGHT}}>{isC&&<span className="text-[8px] font-mono">{qsMidiNoteName(midi)}</span>}</div>);})}
        </div>
        <div ref={gridRef} className="flex-1 overflow-auto relative" style={{height:gridH+24}}>
          <div className="sticky top-0 flex z-20 bg-[#0a0a10] border-b border-white/5" style={{width:gridW}}>
            {Array.from({length:steps},(_,i)=><div key={i} className={cn("border-r border-white/5 text-[8px] text-white/20 text-center flex-shrink-0",i%4===0&&"border-r-white/15 text-white/40")} style={{width:QS_STEP_WIDTH,height:20,lineHeight:'20px'}}>{i%4===0&&Math.floor(i/4)+1}</div>)}
          </div>
          <div className="relative" style={{width:gridW,height:gridH}}
            onMouseDown={e=>{if(e.button===2)return;const rect=gridRef.current!.getBoundingClientRect();const y=e.clientY-rect.top-20+gridRef.current!.scrollTop;const x=e.clientX-rect.left+gridRef.current!.scrollLeft-48;const noteRow=Math.floor(y/QS_NOTE_HEIGHT),stepCol=Math.floor(x/QS_STEP_WIDTH);const midi=QS_MAX_MIDI-1-noteRow;if(midi>=QS_MIN_MIDI&&midi<=QS_MAX_MIDI&&stepCol>=0&&stepCol<steps)addNote(midi,stepCol);}}
            onContextMenu={e=>e.preventDefault()}>
            {Array.from({length:QS_TOTAL_NOTES},(_,i)=>{const midi=QS_MAX_MIDI-1-i,black=qsIsBlack(midi),inScale=scaleNotes.includes(midi%12);return<div key={i} className="absolute w-full border-b border-white/[0.03]" style={{top:i*QS_NOTE_HEIGHT,height:QS_NOTE_HEIGHT,backgroundColor:black?'#0c0c14':scaleLock&&inScale?'#0d1018':inScale?'#0d0d18':'#0a0a10'}}/>;}) }
            {Array.from({length:steps},(_,i)=><div key={i} className="absolute top-0 bottom-0 border-r" style={{left:i*QS_STEP_WIDTH,borderColor:i%4===0?'rgba(255,255,255,0.1)':'rgba(255,255,255,0.04)'}}/>)}
            {notesForInst.map((note:any)=>{const rowIdx=QS_MAX_MIDI-1-note.pitch;const velAlpha=Math.round(((note.velocity||100)/127)*200+55).toString(16).padStart(2,'0');return(<div key={note.id} className="absolute rounded-sm flex items-center overflow-hidden cursor-pointer" style={{top:rowIdx*QS_NOTE_HEIGHT+1,left:note.startStep*QS_STEP_WIDTH+1,width:note.lengthSteps*QS_STEP_WIDTH-2,height:QS_NOTE_HEIGHT-2,backgroundColor:inst.color+velAlpha,boxShadow:`0 0 6px ${inst.color}40`}} onContextMenu={e=>{e.preventDefault();removeNote(note.id);}}>
              <div className="flex-1 px-1 text-[8px] font-bold text-black/70 truncate">{qsMidiNoteName(note.pitch)}</div>
              <div className="w-2 h-full flex-shrink-0 cursor-ew-resize bg-black/20 hover:bg-black/50" onMouseDown={e=>{e.stopPropagation();const startX=e.clientX,origLen=note.lengthSteps;const onMove=(ev:MouseEvent)=>resizeNote(note.id,Math.max(1,origLen+Math.round((ev.clientX-startX)/QS_STEP_WIDTH)));const onUp=()=>{document.removeEventListener('mousemove',onMove);document.removeEventListener('mouseup',onUp);};document.addEventListener('mousemove',onMove);document.addEventListener('mouseup',onUp);}}/>
            </div>);})}
          </div>
        </div>
      </div>
    </div>
  );
}

function QsSongArranger({arrangement,onUpdate,activePattern}:any){
  const [selP,setSelP]=useState('A');
  const placeBlock=useCallback((bar:number)=>{const ex=arrangement.find((b:any)=>b.bar===bar);if(ex){onUpdate(arrangement.filter((b:any)=>b!==ex));}else{onUpdate([...arrangement,{id:`${Date.now()}`,patternId:selP,bar}].sort((a:any,b:any)=>a.bar-b.bar));}},[arrangement,onUpdate,selP]);
  const totalBars=64,barW=44;
  return(
    <div className="flex flex-col h-full bg-[#080810]">
      <div className="flex items-center gap-3 px-4 py-2 border-b border-white/5 bg-[#0d0d12]">
        <span className="text-[10px] text-white/30 uppercase tracking-widest font-bold">Song Arranger</span>
        <div className="flex gap-1">{QS_ALL_PATTERNS.map(p=><button key={p} onClick={()=>setSelP(p)} className="w-8 h-7 rounded-md text-xs font-bold border transition-all" style={selP===p?{backgroundColor:QS_PATTERN_COLORS[p]+'33',borderColor:QS_PATTERN_COLORS[p]+'80',color:QS_PATTERN_COLORS[p]}:{backgroundColor:'transparent',borderColor:'rgba(255,255,255,0.1)',color:'rgba(255,255,255,0.4)'}}>{p}</button>)}</div>
        <span className="text-[10px] text-white/20">Click bar to place/remove</span>
        <button onClick={()=>onUpdate([])} className="ml-auto text-[10px] text-white/30 hover:text-red-400 flex items-center gap-1"><Trash2 className="w-3 h-3"/>Clear</button>
      </div>
      <div className="flex-1 overflow-auto p-4">
        <div className="flex mb-1" style={{paddingLeft:80}}>{Array.from({length:totalBars},(_,i)=><div key={i} className="flex-shrink-0 text-[9px] text-white/20 text-center border-r border-white/5" style={{width:barW}}>{i%4===0&&i+1}</div>)}</div>
        {QS_ALL_PATTERNS.map(p=>{
          const blocksForPattern=arrangement.filter((b:any)=>b.patternId===p);
          return(<div key={p} className="flex items-center mb-1 h-9">
            <div className="w-20 flex-shrink-0 text-xs font-bold flex items-center gap-1.5 pr-2"><div className="w-2 h-2 rounded-sm" style={{backgroundColor:QS_PATTERN_COLORS[p]}}/><span style={{color:QS_PATTERN_COLORS[p]}}>Pat {p}</span></div>
            <div className="flex relative h-full" style={{width:totalBars*barW}}>
              {Array.from({length:totalBars},(_,i)=><div key={i} className={cn("flex-shrink-0 h-full border-r border-white/5 cursor-pointer transition-colors",selP===p?"hover:bg-white/5":"")} style={{width:barW}} onClick={()=>selP===p&&placeBlock(i)}/>)}
              {blocksForPattern.map((block:any)=><div key={block.id} className="absolute top-0.5 bottom-0.5 rounded flex items-center justify-center text-[10px] font-bold opacity-90 cursor-pointer" style={{left:block.bar*barW+1,width:barW-2,backgroundColor:QS_PATTERN_COLORS[block.patternId]+'60',borderLeft:`3px solid ${QS_PATTERN_COLORS[block.patternId]}`,color:QS_PATTERN_COLORS[block.patternId]}} onClick={()=>placeBlock(block.bar)}>{block.patternId}</div>)}
            </div>
          </div>);
        })}
      </div>
    </div>
  );
}

const QS_STORAGE_KEY='quantum_studio_projects_v1';
function QsProjectManager({open,onClose,onSave,onLoad}:any){
  const [name,setName]=useState('My Project');
  const [projects,setProjects]=useState<Record<string,any>>({});
  useEffect(()=>{if(open){try{setProjects(JSON.parse(localStorage.getItem(QS_STORAGE_KEY)||'{}'));}catch{setProjects({});}};},[open]);
  const handleSave=()=>{const t=name.trim();if(!t){alert('Enter a project name');return;}const all=(() => {try{return JSON.parse(localStorage.getItem(QS_STORAGE_KEY)||'{}');}catch{return{};}})();all[t]={...onSave(),name:t,savedAt:Date.now()};localStorage.setItem(QS_STORAGE_KEY,JSON.stringify(all));setProjects({...all});};
  const handleLoad=(key:string)=>{const all=(() => {try{return JSON.parse(localStorage.getItem(QS_STORAGE_KEY)||'{}');}catch{return{};}})();if(all[key]){onLoad(all[key]);onClose();}};
  const handleDelete=(key:string)=>{const all=(() => {try{return JSON.parse(localStorage.getItem(QS_STORAGE_KEY)||'{}');}catch{return{};}})();delete all[key];localStorage.setItem(QS_STORAGE_KEY,JSON.stringify(all));setProjects({...all});};
  const sorted=Object.entries(projects).sort((a:any,b:any)=>(b[1].savedAt||0)-(a[1].savedAt||0));
  return(
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="bg-[#0e0e16] border-white/10 text-white max-w-md">
        <DialogHeader><DialogTitle className="text-sm font-black tracking-wider flex items-center gap-2"><FolderOpen className="w-4 h-4 text-violet-400"/>Project Manager</DialogTitle></DialogHeader>
        <div className="flex gap-2">
          <Input value={name} onChange={e=>setName(e.target.value)} placeholder="Project name..." className="bg-white/5 border-white/10 text-white text-sm h-8 flex-1" onKeyDown={e=>e.key==='Enter'&&handleSave()}/>
          <button onClick={handleSave} className="flex items-center gap-1.5 h-8 px-3 rounded-md bg-violet-500/20 border border-violet-500/40 text-violet-400 hover:bg-violet-500/30 text-xs font-bold"><Save className="w-3 h-3"/>Save</button>
        </div>
        <div className="space-y-1 max-h-72 overflow-y-auto pr-1">
          {sorted.length===0&&<div className="text-center text-white/20 text-xs py-8">No saved projects yet.</div>}
          {sorted.map(([key,data]:any)=>(
            <div key={key} className="flex items-center gap-2 p-2.5 rounded-lg bg-white/4 border border-white/5 group hover:bg-white/7 transition-colors">
              <div className="flex-1 min-w-0"><div className="text-xs font-semibold text-white/80 truncate">{key}</div><div className="text-[9px] text-white/30 flex items-center gap-1 mt-0.5"><Clock className="w-2.5 h-2.5"/>{data.bpm} BPM · {data.musicalKey} · {new Date(data.savedAt).toLocaleDateString()}</div></div>
              <button onClick={()=>handleLoad(key)} className="text-[9px] font-bold text-violet-400/70 hover:text-violet-400 border border-violet-400/20 hover:border-violet-400/50 px-2.5 py-1 rounded">Load</button>
              <button onClick={()=>handleDelete(key)} className="text-white/20 hover:text-red-400 p-1 opacity-0 group-hover:opacity-100"><Trash2 className="w-3 h-3"/></button>
            </div>
          ))}
        </div>
        <div className="text-[9px] text-white/20 text-center">Projects saved locally in browser</div>
      </DialogContent>
    </Dialog>
  );
}

const QS_MOODS=[{id:'energetic',label:'Energetic',emoji:'⚡'},{id:'chill',label:'Chill',emoji:'😌'},{id:'dark',label:'Dark',emoji:'🌑'},{id:'uplifting',label:'Uplifting',emoji:'☀️'},{id:'melancholic',label:'Melancholic',emoji:'🌧️'},{id:'aggressive',label:'Aggressive',emoji:'🔥'},{id:'dreamy',label:'Dreamy',emoji:'✨'},{id:'trippy',label:'Trippy',emoji:'🌀'}];
const QS_GENRE_GRID=[{id:'trap',label:'Trap',emoji:'🎧'},{id:'hip_hop',label:'Hip Hop',emoji:'🎤'},{id:'rnb',label:'R&B',emoji:'🎸'},{id:'drill',label:'Drill',emoji:'🥁'},{id:'lofi',label:'Lo-Fi',emoji:'📻'},{id:'electronic',label:'Electronic',emoji:'⚡'},{id:'jazz',label:'Jazz',emoji:'🎷'},{id:'afrobeat',label:'Afrobeat',emoji:'🌍'},{id:'reggaeton',label:'Reggaeton',emoji:'🌊'},{id:'rock',label:'Rock',emoji:'🎸'},{id:'ambient',label:'Ambient',emoji:'🌙'},{id:'synthwave',label:'Synthwave',emoji:'🌆'},{id:'house',label:'House',emoji:'🏠'},{id:'drum_and_bass',label:'D&B',emoji:'🔊'},{id:'dubstep',label:'Dubstep',emoji:'💥'},{id:'phonk',label:'Phonk',emoji:'👻'},{id:'future_bass',label:'Future Bass',emoji:'🚀'},{id:'pop',label:'Pop',emoji:'🎵'},{id:'classical',label:'Classical',emoji:'🎻'},{id:'techno',label:'Techno',emoji:'🤖'},{id:'hyperpop',label:'Hyperpop',emoji:'🌸'}];
const QS_INSTR_GROUPS=[{label:'Keys & Synths',items:['Lead Synth','Pad','Pluck','Keys','Arp']},{label:'Drums & Percussion',items:['Kick','Snare','Hi-Hats','Clap','Toms','Cymbal']},{label:'Bass',items:['808 Bass','Bass Synth','Sub Bass']},{label:'FX & Texture',items:['Vinyl Crackle','Atmosphere','Foley FX','White Noise']}];

function QsWaveformViz({count=22,color='#8b5cf6',active=true}:{count?:number,color?:string,active?:boolean}){
  const heights=[10,24,16,36,20,30,12,40,28,14,34,22,38,16,26,32,10,28,20,36,14,24];
  return(<div className="flex items-end gap-[3px]" style={{height:48}}>{Array.from({length:count},(_,i)=>{const h=active?heights[i%heights.length]:4;return(<div key={i} className={active?"qs-wave-bar":"rounded-full"} style={{width:4,height:h,backgroundColor:color,borderRadius:4,animationDelay:active?`${i*0.04}s`:'0s',animationDuration:active?`${0.6+(i%4)*0.1}s`:'0s',opacity:active?0.7+(i%4)*0.07:0.15,transition:'height 0.4s'}}/>);})}
  </div>);}

function QsGenreSelector({value,onChange}:{value:string,onChange:(g:string)=>void}){return(<div className="space-y-2"><div className="text-[9px] text-white/30 uppercase tracking-widest font-bold">Genre</div><div className="grid grid-cols-4 sm:grid-cols-5 lg:grid-cols-7 gap-1.5">{QS_GENRE_GRID.map(g=><button key={g.id} onClick={()=>onChange(g.id)} className={cn("flex flex-col items-center gap-1 p-2 rounded-xl border text-xs transition-all",value===g.id?"border-violet-500/60 bg-violet-500/15 text-violet-300 shadow-lg shadow-violet-500/10":"border-white/8 bg-white/3 text-white/40 hover:border-white/20 hover:bg-white/6 hover:text-white/70")}><span className="text-base leading-none">{g.emoji}</span><span className="font-medium text-[9px] leading-none">{g.label}</span></button>)}</div></div>);}

function QsMoodSelector({value,onChange}:{value:string,onChange:(m:string)=>void}){return(<div className="space-y-2"><div className="text-[9px] text-white/30 uppercase tracking-widest font-bold">Mood / Vibe</div><div className="grid grid-cols-4 gap-1.5">{QS_MOODS.map(m=><button key={m.id} onClick={()=>onChange(m.id)} className={cn("flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg border text-[10px] font-bold transition-all",value===m.id?"border-pink-500/60 bg-pink-500/15 text-pink-300":"border-white/8 bg-white/3 text-white/40 hover:border-white/20 hover:text-white/70")}><span>{m.emoji}</span>{m.label}</button>)}</div></div>);}

function QsInstrumentHints({selected,onToggle}:{selected:string[],onToggle:(s:string)=>void}){return(<div className="space-y-2"><div className="text-[9px] text-white/30 uppercase tracking-widest font-bold">Emphasize Instruments <span className="text-white/20 normal-case">(optional)</span></div>{QS_INSTR_GROUPS.map(g=><div key={g.label} className="space-y-1"><div className="text-[8px] uppercase tracking-wider text-white/20">{g.label}</div><div className="flex flex-wrap gap-1">{g.items.map(it=>{const on=selected.includes(it);return(<button key={it} onClick={()=>onToggle(it)} className={cn("px-2.5 py-1 rounded-full text-[10px] font-medium border transition-all",on?"bg-cyan-500/15 border-cyan-500/40 text-cyan-400":"bg-white/3 border-white/8 text-white/35 hover:border-white/20 hover:text-white/60")}>{it}</button>)})}</div></div>)}</div>);}

const QS_VOCAL_STYLES=[
  {id:'natural',label:'Natural',emoji:'🎤',rate:1.0,pitch:1.0},
  {id:'rapper',label:'Rapper',emoji:'🎧',rate:1.55,pitch:0.85},
  {id:'singer',label:'Singer',emoji:'🎶',rate:0.75,pitch:1.25},
  {id:'deep',label:'Deep Voice',emoji:'🔊',rate:0.9,pitch:0.55},
  {id:'high',label:'High Pitch',emoji:'🌟',rate:0.95,pitch:1.8},
  {id:'choir',label:'Choir',emoji:'🎼',rate:0.7,pitch:1.1},
  {id:'robot',label:'Robot',emoji:'🤖',rate:0.8,pitch:0.4},
  {id:'whisper',label:'Whisper',emoji:'💨',rate:0.65,pitch:0.9},
];
const QS_LYRIC_TEMPLATES:{genre:string,lines:string[]}[]=[
  {genre:'trap',lines:['Drip on me like rain (yeah yeah)','Running through the game','Diamonds in my chain (uh)','They dont know my name']},
  {genre:'lofi',lines:['Coffee in the morning light','Everything is gonna be alright','Slow down take a breath','Feel the rhythm of the night']},
  {genre:'hip_hop',lines:['From the bottom now we here','Vision getting crystal clear','Every dream I hold so dear','Success the only frontier']},
  {genre:'rnb',lines:['Baby when you hold me close','You the one I love the most','Through the highs and through the lows','That is how our love grows']},
];

function QsVocalsStudio({bpm,genre}:{bpm:number,genre:string}){
  const [lyrics,setLyrics]=useState('');
  const [voiceIdx,setVoiceIdx]=useState(0);
  const [style,setStyle]=useState('natural');
  const [isSpeaking,setIsSpeaking]=useState(false);
  const [voices,setVoices]=useState<SpeechSynthesisVoice[]>([]);
  const [volume,setVolume]=useState(0.85);
  const [showHF,setShowHF]=useState(false);
  const {toast}=useToast();
  const uttRef=useRef<SpeechSynthesisUtterance|null>(null);

  useEffect(()=>{
    const load=()=>{const v=window.speechSynthesis.getVoices();if(v.length)setVoices(v);};
    load();window.speechSynthesis.onvoiceschanged=load;
    return()=>{window.speechSynthesis.cancel();};
  },[]);

  const currentStyle=QS_VOCAL_STYLES.find(s=>s.id===style)||QS_VOCAL_STYLES[0];

  const handleSpeak=useCallback(()=>{
    if(!lyrics.trim()){toast({title:'Add some lyrics first!'});return;}
    window.speechSynthesis.cancel();
    const utt=new SpeechSynthesisUtterance(lyrics);
    if(voices[voiceIdx])utt.voice=voices[voiceIdx];
    utt.rate=currentStyle.rate;
    utt.pitch=currentStyle.pitch;
    utt.volume=volume;
    utt.onend=()=>setIsSpeaking(false);
    utt.onerror=()=>setIsSpeaking(false);
    uttRef.current=utt;
    setIsSpeaking(true);
    window.speechSynthesis.speak(utt);
  },[lyrics,voices,voiceIdx,currentStyle,volume,toast]);

  const handleStop=useCallback(()=>{window.speechSynthesis.cancel();setIsSpeaking(false);},[]);

  const handleTemplate=()=>{
    const match=QS_LYRIC_TEMPLATES.find(t=>t.genre===genre)||QS_LYRIC_TEMPLATES[0];
    setLyrics(match.lines.join('\n'));
  };

  const maleVoices=voices.filter(v=>/(male|man|david|mark|james|alex|daniel|jorge|oliver|tom|aaron|fred|bruce|ralph|junior|albert|bad|bahh|bells|boing|bubbles|cellos|deranged|good|hysterical|pipe|trinoids|whisper|zarvox)/i.test(v.name));
  const femaleVoices=voices.filter(v=>!maleVoices.includes(v)&&/(female|woman|samantha|victoria|karen|moira|veena|fiona|ava|allison|susan|zoe|tessa|joana|luciana|catarina|paulina|monica|kanya|amelie|anna|sin-ji|mei-jia|ting-ting|yuna|kyoko|otoya|satu|sara|alva|ellen|claire|nora|zosia|filipa|ioana|petra|lekha|damayanti|empar|montserrat|magda|ida|mariska|carmit|milena|xander|thomas|pita)/i.test(v.name));
  const allVoicesGrouped=[...new Set([...maleVoices,...femaleVoices,...voices])].filter((v,i,a)=>a.indexOf(v)===i);

  return(
    <div className="flex-1 overflow-auto p-4">
      <div className="max-w-3xl mx-auto space-y-4">
        {/* Header */}
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-pink-600/40 to-violet-600/30 border border-pink-500/30 flex items-center justify-center flex-shrink-0">
            <Mic className="w-5 h-5 text-pink-400"/>
          </div>
          <div>
            <div className="text-sm font-black text-white tracking-tight">Quantum Vocals Studio</div>
            <div className="text-[11px] text-white/35">Free AI voices built into your browser — no API key, no backend</div>
          </div>
          <div className="ml-auto flex items-center gap-1.5">
            <QsWaveformViz active={isSpeaking} count={14} color="#ec4899"/>
          </div>
        </div>

        {/* Vocal Style Picker */}
        <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06] space-y-2">
          <div className="text-[9px] text-white/30 uppercase tracking-widest font-bold">Vocal Style</div>
          <div className="grid grid-cols-4 gap-1.5">
            {QS_VOCAL_STYLES.map(s=><button key={s.id} onClick={()=>setStyle(s.id)} className={cn("flex flex-col items-center gap-1 p-2 rounded-xl border text-xs transition-all",style===s.id?"border-pink-500/60 bg-pink-500/15 text-pink-300 shadow-lg shadow-pink-500/10":"border-white/8 bg-white/3 text-white/40 hover:border-white/20 hover:text-white/70")}><span className="text-base leading-none">{s.emoji}</span><span className="font-bold text-[9px] leading-none">{s.label}</span></button>)}
          </div>
        </div>

        {/* Voice Selector */}
        <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06] space-y-3">
          <div className="flex items-center justify-between">
            <div className="text-[9px] text-white/30 uppercase tracking-widest font-bold">Voice ({voices.length} available on your device)</div>
            <span className="text-[9px] text-white/20">Browser built-in • Free forever</span>
          </div>
          {voices.length===0?<div className="text-xs text-white/30 py-2">Loading voices... (try clicking speak once to load)</div>:
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-1.5 max-h-40 overflow-y-auto pr-1 scrollbar-thin">
            {allVoicesGrouped.map((v,i)=><button key={i} onClick={()=>setVoiceIdx(voices.indexOf(v))} className={cn("flex items-center gap-2 px-2.5 py-1.5 rounded-lg border text-[10px] text-left transition-all",voiceIdx===voices.indexOf(v)?"border-violet-500/50 bg-violet-500/12 text-violet-300":"border-white/5 bg-white/2 text-white/35 hover:border-white/15 hover:text-white/60")}>
              <span className="flex-shrink-0">{/(male|man|david|mark|james|alex|daniel|tom|fred)/i.test(v.name)?'♂':'♀'}</span>
              <span className="truncate font-medium">{v.name}</span>
              <span className="ml-auto flex-shrink-0 text-white/15">{v.lang}</span>
            </button>)}
          </div>}
          <div className="flex items-center gap-3">
            <span className="text-[9px] text-white/30 uppercase tracking-wider">Volume</span>
            <input type="range" min={0} max={1} step={0.05} value={volume} onChange={e=>setVolume(parseFloat(e.target.value))} className="flex-1 cursor-pointer accent-pink-500"/>
            <span className="text-[10px] text-white/40 w-8 tabular-nums">{Math.round(volume*100)}%</span>
          </div>
        </div>

        {/* Lyrics Area */}
        <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06] space-y-3">
          <div className="flex items-center justify-between">
            <div className="text-[9px] text-white/30 uppercase tracking-widest font-bold">Lyrics / Script</div>
            <div className="flex gap-1.5">
              <button onClick={handleTemplate} className="text-[9px] px-2 py-1 rounded-lg border border-white/10 text-white/30 hover:text-violet-400 hover:border-violet-400/30 transition-colors">✨ Sample Lyrics</button>
              <button onClick={()=>setLyrics('')} className="text-[9px] px-2 py-1 rounded-lg border border-white/10 text-white/30 hover:text-red-400 hover:border-red-400/30 transition-colors">Clear</button>
            </div>
          </div>
          <textarea value={lyrics} onChange={e=>setLyrics(e.target.value)} placeholder={`Type your lyrics here...\n\nEach line will be spoken with your selected voice and style.\n\nTip: Short punchy lines work best for rap/trap beats.`} className="w-full h-36 bg-black/30 border border-white/8 rounded-xl text-white/80 text-xs font-mono resize-none p-3 placeholder-white/15 focus:outline-none focus:border-violet-500/40" spellCheck={false}/>
          <div className="text-[9px] text-white/15">{lyrics.split('\n').filter(l=>l.trim()).length} lines · {lyrics.length} chars · Est. {Math.round(lyrics.split(' ').filter(Boolean).length/currentStyle.rate/2.5)}s at {currentStyle.rate}x rate</div>
        </div>

        {/* Controls */}
        <div className="grid grid-cols-2 gap-3">
          <button onClick={isSpeaking?handleStop:handleSpeak} className={cn("py-4 rounded-2xl font-black text-sm border transition-all flex items-center justify-center gap-2",isSpeaking?"bg-red-500/15 border-red-500/30 text-red-400 hover:bg-red-500/25":"bg-gradient-to-r from-pink-600/25 to-violet-600/20 border-pink-500/30 text-white hover:from-pink-600/35 hover:border-pink-500/50 shadow-xl shadow-pink-500/10")}>
            {isSpeaking?<><Square className="w-4 h-4"/>Stop Vocals</>:<><Mic className="w-4 h-4"/>Speak Vocals</>}
          </button>
          <div className="p-3 rounded-2xl bg-white/[0.025] border border-white/[0.06] flex flex-col justify-center gap-1">
            <div className="text-[9px] text-white/25 uppercase tracking-wider">Active Style</div>
            <div className="text-sm font-black text-white/70">{currentStyle.emoji} {currentStyle.label}</div>
            <div className="text-[9px] text-white/20">Rate {currentStyle.rate}x · Pitch {currentStyle.pitch}x</div>
          </div>
        </div>

        {/* HuggingFace upgrade note */}
        <div className="p-4 rounded-2xl bg-white/[0.015] border border-white/[0.04]">
          <button onClick={()=>setShowHF(v=>!v)} className="w-full flex items-center justify-between text-left">
            <div className="flex items-center gap-2"><span className="text-sm">🤗</span><span className="text-[10px] font-bold text-white/40">Upgrade to HuggingFace Neural TTS</span></div>
            <span className="text-white/20 text-xs">{showHF?'▲':'▼'}</span>
          </button>
          {showHF&&<div className="mt-3 space-y-2 text-[10px] text-white/40">
            <p>Get even higher-quality AI voices by using the free HuggingFace Inference API. No credit card needed — just a free account.</p>
            <div className="flex items-start gap-2 mt-2">
              <span className="text-violet-400 mt-0.5">1.</span><span>Sign up free at <strong className="text-violet-300">huggingface.co</strong> → Settings → Access Tokens → New token (read)</span>
            </div>
            <div className="flex items-start gap-2">
              <span className="text-violet-400 mt-0.5">2.</span><span>Paste your token in Settings (Profile → Studio Settings → HF Token) to unlock Bark, SpeechT5, and Kokoro TTS models</span>
            </div>
            <div className="flex items-start gap-2">
              <span className="text-violet-400 mt-0.5">3.</span><span>Best free models: <strong className="text-white/60">suno/bark-small</strong> (singing voices), <strong className="text-white/60">microsoft/speecht5_tts</strong> (natural speech)</span>
            </div>
            <div className="mt-2 px-3 py-2 bg-violet-500/10 border border-violet-500/20 rounded-lg text-violet-300 text-[9px]">💡 Coming soon — HuggingFace integration will be added to unlock these models directly in the studio</div>
          </div>}
        </div>
      </div>
    </div>
  );
}

const QS_TABS=['sequencer','piano_roll','arranger','ai','vocals'] as const;
const QS_TAB_LABELS:Record<string,string>={sequencer:'Step Seq',piano_roll:'Piano Roll',arranger:'Arranger',ai:'AI Studio',vocals:'🎤 Vocals'};

function QuantumStudio(){
  const {toast}=useToast();
  const [bpm,setBpm]=useState(140);
  const [activePattern,setActivePattern]=useState('A');
  const [steps,setSteps]=useState(QS_STEPS_DEFAULT);
  const [musicalKey,setMusicalKey]=useState('C Minor');
  const [genre,setGenre]=useState('trap');
  const [swing,setSwing]=useState(0);
  const [patterns,setPatterns]=useState(()=>qsBuildInitialPatterns(QS_STEPS_DEFAULT));
  const [mixer,setMixer]=useState(qsBuildDefaultMixer);
  const [pianoRollNotes,setPianoRollNotes]=useState(qsBuildInitialPianoRoll);
  const [arrangement,setArrangement]=useState<any[]>([]);
  const [arrangeMode,setArrangeMode]=useState(false);
  const [selectedChannel,setSelectedChannel]=useState<string|null>(null);
  const [pianoRollInst,setPianoRollInst]=useState('lead');
  const [mood,setMood]=useState('energetic');
  const [aiInstrHints,setAiInstrHints]=useState<string[]>([]);
  const [clipboardPat,setClipboardPat]=useState<any>(null);
  const tapTimesRef=useRef<number[]>([]);
  const [isGenerating,setIsGenerating]=useState(false);
  const [isExporting,setIsExporting]=useState(false);
  const [isStemsExporting,setIsStemsExporting]=useState(false);
  const [activeTab,setActiveTab]=useState('sequencer');
  const [showMixer,setShowMixer]=useState(true);
  const [showFX,setShowFX]=useState(false);
  const [showProjects,setShowProjects]=useState(false);
  const [aiStatus,setAiStatus]=useState('');
  const undoStack=useRef<any[]>([]),redoStack=useRef<any[]>([]);
  const {isPlaying,currentStep,play,stop,updateRefs}=useQsAudioEngine();

  useEffect(()=>{updateRefs(patterns,mixer,bpm,activePattern,steps,musicalKey,mixer.__master?.volume??0.75,swing,pianoRollNotes,arrangement,arrangeMode);},[patterns,mixer,bpm,activePattern,steps,musicalKey,swing,pianoRollNotes,arrangement,arrangeMode,updateRefs]);

  const pushUndo=useCallback(()=>{undoStack.current.push(JSON.parse(JSON.stringify(patterns)));if(undoStack.current.length>50)undoStack.current.shift();redoStack.current=[];},[patterns]);
  const handleUndo=useCallback(()=>{if(!undoStack.current.length)return;redoStack.current.push(JSON.parse(JSON.stringify(patterns)));setPatterns(undoStack.current.pop());},[patterns]);
  const handleRedo=useCallback(()=>{if(!redoStack.current.length)return;undoStack.current.push(JSON.parse(JSON.stringify(patterns)));setPatterns(redoStack.current.pop());},[patterns]);

  useEffect(()=>{const handler=(e:KeyboardEvent)=>{if((e.ctrlKey||e.metaKey)&&e.key==='z'){e.preventDefault();handleUndo();}if((e.ctrlKey||e.metaKey)&&(e.key==='y'||(e.shiftKey&&e.key==='z'))){e.preventDefault();handleRedo();}};window.addEventListener('keydown',handler);return()=>window.removeEventListener('keydown',handler);},[handleUndo,handleRedo]);

  const toggleStep=useCallback((instId:string,stepIdx:number)=>{pushUndo();setPatterns(prev=>{const pat={...prev};const track=[...(pat[activePattern][instId]||[])];track[stepIdx]={...track[stepIdx],active:!track[stepIdx].active};pat[activePattern]={...pat[activePattern],[instId]:track};return pat;});},[activePattern,pushUndo]);
  const setNote=useCallback((instId:string,stepIdx:number,note:number)=>{setPatterns(prev=>{const pat={...prev};const track=[...(pat[activePattern][instId]||[])];track[stepIdx]={...track[stepIdx],note};pat[activePattern]={...pat[activePattern],[instId]:track};return pat;});},[activePattern]);
  const setVelocity=useCallback((instId:string,stepIdx:number,velocity:number)=>{setPatterns(prev=>{const pat={...prev};const track=[...(pat[activePattern][instId]||[])];track[stepIdx]={...track[stepIdx],velocity};pat[activePattern]={...pat[activePattern],[instId]:track};return pat;});},[activePattern]);
  const updateMixer=useCallback((chanId:string,key:string,value:any)=>setMixer(prev=>({...prev,[chanId]:{...(prev[chanId]||{}),[key]:value}})),[]);
  const handleStepsChange=useCallback((newSteps:number)=>{setSteps(newSteps);setPatterns(prev=>{const updated:any={};QS_ALL_PATTERNS.forEach(p=>{const newPat:any={};INSTRUMENTS.forEach(inst=>{const old=prev[p]?.[inst.id]||[];newPat[inst.id]=newSteps>old.length?[...old,...qsDefaultTrack(newSteps-old.length)]:old.slice(0,newSteps);});updated[p]=newPat;});return updated;});},[]);
  const handleTapTempo=useCallback(()=>{const now=Date.now(),times=tapTimesRef.current;times.push(now);if(times.length>8)times.shift();if(times.length>=2){const diffs=times.slice(1).map((t,i)=>t-times[i]);const avg=diffs.reduce((a,b)=>a+b,0)/diffs.length;const det=Math.round(60000/avg);if(det>=40&&det<=240)setBpm(det);}},[]);
  const handleRandomizePattern=useCallback(()=>{pushUndo();setPatterns(prev=>{const pat={...prev},newPat:any={};INSTRUMENTS.forEach(inst=>{newPat[inst.id]=Array(steps).fill(0).map(()=>({active:Math.random()<(inst.type==='drum'?0.3:0.2),velocity:Math.floor(Math.random()*60+67),note:Math.floor(Math.random()*8),length:1}));});pat[activePattern]=newPat;return pat;});},[activePattern,steps,pushUndo]);
  const handleClearPattern=useCallback(()=>{pushUndo();setPatterns(prev=>({...prev,[activePattern]:qsBuildEmptyPattern(steps)}));},[activePattern,steps,pushUndo]);
  const handleCopyPattern=useCallback(()=>{setClipboardPat(JSON.parse(JSON.stringify(patterns[activePattern])));toast({title:`Pattern ${activePattern} copied to clipboard`});},[patterns,activePattern,toast]);
  const handlePastePattern=useCallback(()=>{if(!clipboardPat){toast({title:'Nothing in clipboard',variant:'destructive'});return;}pushUndo();setPatterns(prev=>({...prev,[activePattern]:clipboardPat}));toast({title:'Pattern pasted!'});},[clipboardPat,activePattern,pushUndo,toast]);
  const handleHumanize=useCallback(()=>{setPatterns(prev=>{const pat={...prev},newPat:any={};INSTRUMENTS.forEach(inst=>{newPat[inst.id]=(pat[activePattern][inst.id]||[]).map((s:any)=>s.active?{...s,velocity:Math.max(40,Math.min(127,(s.velocity||100)+Math.round((Math.random()-0.5)*30)))}:s);});pat[activePattern]=newPat;return pat;});toast({title:'Humanized!',description:'Natural velocity variation applied'});},[activePattern,toast]);
  const handleFillEven=useCallback((every:number)=>{pushUndo();setPatterns(prev=>{const pat={...prev},newPat:any={...pat[activePattern]};const inst=selectedChannel||'kick';newPat[inst]=(pat[activePattern][inst]||[]).map((s:any,i:number)=>({...s,active:i%every===0}));pat[activePattern]=newPat;return pat;});},[activePattern,selectedChannel,pushUndo]);
  const handleAIGenerate=useCallback(async()=>{
    setIsGenerating(true);setAiStatus('🎵 Quantum AI is composing your beat...');pushUndo();
    try{const{pattern,description}=await qsGenerateAIPattern({genre,mood,bpm,musicalKey,steps});setPatterns(prev=>({...prev,[activePattern]:pattern}));setAiStatus('');toast({title:'AI Beat Generated!',description:description?.slice(0,80)||'Pattern ready'});}
    catch(e){setAiStatus('');toast({title:'AI generation failed',variant:'destructive'});}
    finally{setIsGenerating(false);}
  },[genre,mood,bpm,musicalKey,steps,activePattern,pushUndo,toast]);
  const handleExport=useCallback(async()=>{setIsExporting(true);try{await qsExportWav({patterns,mixer,bpm,steps,musicalKey,activePattern,swing});toast({title:'WAV exported!'});}catch(e:any){toast({title:'Export failed',description:e.message,variant:'destructive'});}finally{setIsExporting(false);}
  },[patterns,mixer,bpm,steps,musicalKey,activePattern,swing,toast]);
  const handleExportStems=useCallback(async()=>{setIsStemsExporting(true);toast({title:'Exporting stems...',description:'This may take a moment'});try{await qsExportStems({patterns,mixer,bpm,steps,musicalKey,activePattern,swing});toast({title:'All stems exported!'});}catch(e:any){toast({title:'Stems export failed',variant:'destructive'});}finally{setIsStemsExporting(false);}
  },[patterns,mixer,bpm,steps,musicalKey,activePattern,swing,toast]);
  const handlePianoRollChange=useCallback((notes:any[])=>setPianoRollNotes((prev:any)=>({...prev,[activePattern]:{...(prev[activePattern]||{}),[pianoRollInst]:notes}})),[activePattern,pianoRollInst]);
  const handleSaveProject=useCallback(()=>({bpm,musicalKey,genre,swing,steps,activePattern,patterns,mixer,pianoRollNotes,arrangement}),[bpm,musicalKey,genre,swing,steps,activePattern,patterns,mixer,pianoRollNotes,arrangement]);
  const handleLoadProject=useCallback((data:any)=>{if(data.bpm)setBpm(data.bpm);if(data.musicalKey)setMusicalKey(data.musicalKey);if(data.genre)setGenre(data.genre);if(data.swing!==undefined)setSwing(data.swing);if(data.steps)setSteps(data.steps);if(data.activePattern)setActivePattern(data.activePattern);if(data.patterns)setPatterns(data.patterns);if(data.mixer)setMixer(data.mixer);if(data.pianoRollNotes)setPianoRollNotes(data.pianoRollNotes);if(data.arrangement)setArrangement(data.arrangement);undoStack.current=[];redoStack.current=[];},[]);
  const pianoRollNotesForCurrent=(pianoRollNotes as any)[activePattern]?.[pianoRollInst]||[];

  return(
    <div className="flex flex-col bg-[#080810] text-white" style={{height:'calc(100vh - 60px)'}}>
      {/* Transport Bar */}
      <div className="bg-[#0d0d12] border-b border-white/5 px-3 py-2 flex flex-wrap items-center gap-2 sticky top-0 z-50">
        <div className="flex items-center gap-1.5 mr-1">
          <div className="w-6 h-6 rounded-md bg-violet-500/20 flex items-center justify-center"><Music className="w-3.5 h-3.5 text-violet-400"/></div>
          <span className="text-[10px] font-black tracking-widest text-white/50 uppercase hidden sm:block">Quantum Studio</span>
          <span className="text-[8px] text-violet-400/40 uppercase hidden sm:block">Pro</span>
        </div>
        <button onClick={isPlaying?stop:play} data-testid="studio-play-stop" className={cn("w-8 h-8 rounded-lg flex items-center justify-center border transition-all",isPlaying?"bg-red-500/15 border-red-500/40 text-red-400 hover:bg-red-500/25":"bg-violet-500/15 border-violet-500/40 text-violet-400 hover:bg-violet-500/25 shadow-lg shadow-violet-500/10")}>
          {isPlaying?<Square className="w-3 h-3"/>:<Play className="w-3 h-3 ml-0.5"/>}
        </button>
        <button onClick={handleUndo} disabled={!undoStack.current.length} title="Undo (Ctrl+Z)" className="w-7 h-7 rounded-lg flex items-center justify-center border border-white/8 text-white/30 hover:text-white/70 disabled:opacity-20"><Undo2 className="w-3 h-3"/></button>
        <button onClick={handleRedo} disabled={!redoStack.current.length} title="Redo (Ctrl+Y)" className="w-7 h-7 rounded-lg flex items-center justify-center border border-white/8 text-white/30 hover:text-white/70 disabled:opacity-20"><Redo2 className="w-3 h-3"/></button>
        <div className="flex items-center gap-1 bg-white/5 rounded-lg px-2 py-1.5">
          <span className="text-[9px] text-white/40 uppercase tracking-wider font-bold mr-1">BPM</span>
          <button onClick={()=>setBpm(b=>Math.max(40,b-5))} className="w-5 h-5 rounded flex items-center justify-center text-white/30 hover:text-white/70 hover:bg-white/8 transition-colors"><Minus className="w-2.5 h-2.5"/></button>
          <input type="range" min={40} max={240} value={bpm} onChange={e=>setBpm(parseInt(e.target.value))} className="w-14 cursor-pointer accent-violet-500"/>
          <button onClick={()=>setBpm(b=>Math.min(240,b+5))} className="w-5 h-5 rounded flex items-center justify-center text-white/30 hover:text-white/70 hover:bg-white/8 transition-colors"><Plus className="w-2.5 h-2.5"/></button>
          <input type="number" value={bpm} min={40} max={240} onChange={e=>{const v=parseInt(e.target.value);if(v>=40&&v<=240)setBpm(v);}} className="w-9 bg-transparent text-xs font-bold text-white tabular-nums text-center outline-none [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"/>
          <button onClick={handleTapTempo} title="Tap Tempo" className="ml-1 text-[8px] font-black text-white/25 hover:text-violet-400 uppercase tracking-wider px-1 py-0.5 rounded border border-transparent hover:border-violet-400/30 transition-all">TAP</button>
        </div>
        {/* Live step visualizer */}
        <div className="hidden lg:flex gap-px bg-white/5 rounded-lg px-2 py-1.5 items-center">
          {Array.from({length:Math.min(16,steps)},(_,i)=>{const is4=i%4===0;return(<div key={i} className={cn("rounded-sm transition-all duration-75 flex-shrink-0",is4?"ml-1":"")} style={{width:10,height:isPlaying&&currentStep===i?18:8,backgroundColor:isPlaying&&currentStep===i?'#8b5cf6':'rgba(255,255,255,0.1)',boxShadow:isPlaying&&currentStep===i?'0 0 8px #8b5cf680':''}}/>);})}</div>
        <div className="flex items-center gap-1.5 bg-white/5 rounded-lg px-2.5 py-1.5">
          <span className="text-[9px] text-white/40 uppercase tracking-wider font-bold">SWING</span>
          <input type="range" min={0} max={1} step={0.01} value={swing} onChange={e=>setSwing(parseFloat(e.target.value))} className="w-10 cursor-pointer accent-violet-500"/>
          <span className="text-[10px] text-white/50 tabular-nums w-5">{Math.round(swing*100)}%</span>
        </div>
        <div className="flex gap-0.5">
          {QS_ALL_PATTERNS.map(p=><button key={p} onClick={()=>setActivePattern(p)} data-testid={`pattern-${p}`} className="w-6 h-7 rounded-md text-[10px] font-bold border transition-all" style={activePattern===p?{backgroundColor:`${QS_PATTERN_COLORS[p]}33`,borderColor:`${QS_PATTERN_COLORS[p]}80`,color:QS_PATTERN_COLORS[p]}:{backgroundColor:'transparent',borderColor:'rgba(255,255,255,0.1)',color:'rgba(255,255,255,0.4)'}}>{p}</button>)}
        </div>
        <div className="flex gap-0.5">
          {[8,12,16,24,32].map(s=><button key={s} onClick={()=>handleStepsChange(s)} className={cn("px-1.5 h-7 rounded-md text-[10px] font-bold border",steps===s?"bg-violet-500/20 border-violet-500/50 text-violet-400":"bg-white/5 border-white/10 text-white/40 hover:border-white/20")}>{s}</button>)}
        </div>
        <select value={musicalKey} onChange={e=>setMusicalKey(e.target.value)} className="h-7 bg-white/5 border border-white/10 rounded-lg text-white/70 text-[11px] px-2 cursor-pointer">
          {QS_TRANSPORT_KEYS.map(k=><option key={k} value={k}>{k}</option>)}
        </select>
        <select value={genre} onChange={e=>setGenre(e.target.value)} className="h-7 bg-white/5 border border-white/10 rounded-lg text-white/70 text-[11px] px-2 cursor-pointer capitalize">
          {QS_GENRES.map(g=><option key={g} value={g}>{g.replace(/_/g,' ')}</option>)}
        </select>
        <button onClick={()=>setArrangeMode(v=>!v)} className={cn("flex items-center gap-1 h-7 px-2 rounded-lg text-[10px] font-bold border",arrangeMode?"bg-yellow-500/20 border-yellow-500/30 text-yellow-400":"bg-white/5 border-white/10 text-white/40 hover:border-white/20")}>
          <Columns className="w-3 h-3"/>{arrangeMode?'ARR':'LOOP'}
        </button>
        <button onClick={()=>setShowProjects(true)} className="flex items-center gap-1 h-7 px-2 rounded-lg text-[10px] font-bold border border-white/10 text-white/40 hover:text-white/70 hover:border-white/20"><FolderOpen className="w-3 h-3"/>Projects</button>
        <button onClick={handleExport} disabled={isExporting} data-testid="studio-export-wav" className="flex items-center gap-1 h-7 px-2 rounded-lg text-[10px] font-bold border border-white/10 text-white/40 hover:text-white/70 hover:border-white/20 disabled:opacity-40">
          <Download className={cn("w-3 h-3",isExporting&&"animate-bounce")}/>WAV
        </button>
        <button onClick={handleExportStems} disabled={isStemsExporting} className="flex items-center gap-1 h-7 px-2 rounded-lg text-[10px] font-bold border border-white/10 text-white/40 hover:text-white/70 hover:border-white/20 disabled:opacity-40">
          <Layers className={cn("w-3 h-3",isStemsExporting&&"animate-pulse")}/>Stems
        </button>
        <button onClick={handleAIGenerate} disabled={isGenerating} data-testid="studio-ai-generate" className={cn("ml-auto flex items-center gap-1.5 h-7 px-3 rounded-lg text-[10px] font-bold border",isGenerating?"bg-violet-500/10 border-violet-500/30 text-violet-500/50 cursor-not-allowed":"bg-violet-500/20 border-violet-500/40 text-violet-400 hover:bg-violet-500/30 shadow-lg shadow-violet-500/10")}>
          <Zap className={cn("w-3 h-3",isGenerating&&"animate-pulse")}/>{isGenerating?"Generating...":"AI Generate"}
        </button>
      </div>
      {aiStatus&&<div className="px-4 py-1.5 bg-violet-500/10 border-b border-violet-500/20 text-violet-300 text-[11px] flex items-center gap-3"><div className="flex items-end gap-[2px] h-4">{[8,14,10,18,12,16,10,20,14,10,18,12,16,8,14,10].map((h,i)=><div key={i} className="qs-wave-bar rounded-sm bg-violet-400" style={{width:2,height:h/2,animationDelay:`${i*0.04}s`,animationDuration:`${0.5+i%3*0.1}s`}}/>)}</div>{aiStatus}</div>}
      {/* Pattern Tools Bar */}
      <div className="flex items-center gap-1 px-3 py-1 bg-[#0b0b11] border-b border-white/[0.04] overflow-x-auto">
        <span className="text-[8px] text-white/15 uppercase tracking-widest font-black mr-1 flex-shrink-0">Pattern {activePattern}</span>
        <button onClick={handleClearPattern} className="flex items-center gap-1 h-5 px-2 rounded text-[9px] border border-white/8 text-white/25 hover:text-red-400 hover:border-red-400/30 flex-shrink-0 transition-colors">Clear</button>
        <button onClick={handleRandomizePattern} className="flex items-center gap-1 h-5 px-2 rounded text-[9px] border border-white/8 text-white/25 hover:text-yellow-400 hover:border-yellow-400/30 flex-shrink-0 transition-colors"><Shuffle className="w-2.5 h-2.5"/>Random</button>
        <button onClick={handleHumanize} className="flex items-center gap-1 h-5 px-2 rounded text-[9px] border border-white/8 text-white/25 hover:text-green-400 hover:border-green-400/30 flex-shrink-0 transition-colors">Humanize</button>
        <button onClick={handleCopyPattern} className="flex items-center gap-1 h-5 px-2 rounded text-[9px] border border-white/8 text-white/25 hover:text-cyan-400 hover:border-cyan-400/30 flex-shrink-0 transition-colors">Copy</button>
        <button onClick={handlePastePattern} disabled={!clipboardPat} className="flex items-center gap-1 h-5 px-2 rounded text-[9px] border border-white/8 text-white/25 hover:text-cyan-400 hover:border-cyan-400/30 flex-shrink-0 transition-colors disabled:opacity-30">Paste</button>
        <div className="w-px h-4 bg-white/5 mx-1 flex-shrink-0"/>
        <span className="text-[8px] text-white/15 uppercase tracking-widest flex-shrink-0">Fill {selectedChannel||'kick'}</span>
        {[1,2,4].map(n=><button key={n} onClick={()=>handleFillEven(n)} className="h-5 px-1.5 rounded text-[9px] border border-white/8 text-white/25 hover:text-violet-400 hover:border-violet-400/30 flex-shrink-0 transition-colors">1/{n===1?'1':'every '+n}</button>)}
        <div className="w-px h-4 bg-white/5 mx-1 flex-shrink-0"/>
        <span className="text-[8px] text-white/10 flex-shrink-0">{selectedChannel?`Selected: ${INSTRUMENTS.find(i=>i.id===selectedChannel)?.name||selectedChannel}`:'Click instrument row to select'}</span>
      </div>
      {/* Tab Bar */}
      <div className="flex items-center gap-1 px-4 py-1.5 bg-[#0a0a10] border-b border-white/5">
        {QS_TABS.map(tab=><button key={tab} onClick={()=>setActiveTab(tab)} className={cn("px-3 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider border",activeTab===tab?"bg-violet-500/20 border-violet-500/30 text-violet-400":"border-transparent text-white/30 hover:text-white/60")}>{QS_TAB_LABELS[tab]}</button>)}
        <div className="ml-auto flex items-center gap-2">
          <button onClick={()=>setShowMixer(v=>!v)} className={cn("flex items-center gap-1 px-2 py-1 rounded text-[9px] font-bold border",showMixer?"bg-white/8 border-white/15 text-white/60":"border-transparent text-white/30 hover:text-white/50")}><Sliders className="w-2.5 h-2.5"/>Mixer</button>
          {selectedChannel&&activeTab==='sequencer'&&<button onClick={()=>setShowFX(v=>!v)} className={cn("flex items-center gap-1 px-2 py-1 rounded text-[9px] font-bold border",showFX?"bg-white/8 border-white/15 text-white/60":"border-transparent text-white/30 hover:text-white/50")}><Zap className="w-2.5 h-2.5"/>FX</button>}
          <span className="text-[9px] text-white/10 hidden md:block">{activeTab==='sequencer'?'Click=toggle · Right-click drum=velocity · Right-click melodic=note':activeTab==='piano_roll'?'Click=add · Right-click=remove · Drag right edge=resize':activeTab==='arranger'?'Select pattern → click bar to place':''}</span>
        </div>
      </div>
      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {activeTab==='sequencer'&&<QsStepSequencer patterns={patterns} activePattern={activePattern} currentStep={isPlaying?currentStep:-1} steps={steps} onToggleStep={toggleStep} onSetNote={setNote} onSetVelocity={setVelocity} selectedChannel={selectedChannel} onSelectChannel={setSelectedChannel}/>}
        {activeTab==='piano_roll'&&<QsPianoRoll notes={pianoRollNotesForCurrent} onNotesChange={handlePianoRollChange} steps={steps} musicalKey={musicalKey} activePattern={activePattern} activeInstrument={pianoRollInst} onInstrumentChange={setPianoRollInst} bpm={bpm}/>}
        {activeTab==='arranger'&&<QsSongArranger arrangement={arrangement} onUpdate={setArrangement} activePattern={activePattern}/>}
        {activeTab==='vocals'&&<QsVocalsStudio bpm={bpm} genre={genre}/>}
        {activeTab==='ai'&&(
          <div className="flex-1 overflow-auto p-4">
            <div className="max-w-3xl mx-auto space-y-5">
              {/* Header */}
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-violet-600/40 to-pink-600/30 border border-violet-500/30 flex items-center justify-center flex-shrink-0">
                  <Zap className="w-5 h-5 text-violet-400"/>
                </div>
                <div>
                  <div className="text-sm font-black text-white tracking-tight">Quantum AI Beat Generator</div>
                  <div className="text-[11px] text-white/35">Describe your vibe — AI composes the full pattern in seconds</div>
                </div>
                <div className="ml-auto"><QsWaveformViz active={isGenerating} count={18} color="#8b5cf6"/></div>
              </div>

              {/* Genre Grid */}
              <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06]">
                <QsGenreSelector value={genre} onChange={setGenre}/>
              </div>

              {/* Mood + Key row */}
              <div className="grid grid-cols-1 lg:grid-cols-[1fr_auto] gap-4">
                <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06]">
                  <QsMoodSelector value={mood} onChange={setMood}/>
                </div>
                <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06] min-w-[160px]">
                  <div className="text-[9px] text-white/30 uppercase tracking-widest font-bold mb-2">Musical Key</div>
                  <select value={musicalKey} onChange={e=>setMusicalKey(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-lg text-white/70 text-xs px-2 py-1.5 mb-3">{QS_TRANSPORT_KEYS.map(k=><option key={k} value={k}>{k}</option>)}</select>
                  <div className="text-[9px] text-white/30 uppercase tracking-widest font-bold mb-2">Current BPM</div>
                  <div className="text-2xl font-black text-violet-400 tabular-nums text-center">{bpm}</div>
                  <div className="text-[9px] text-white/20 text-center mt-0.5">{bpm<90?'Slow':bpm<130?'Medium':'Fast'}</div>
                </div>
              </div>

              {/* Instrument hints */}
              <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06]">
                <QsInstrumentHints selected={aiInstrHints} onToggle={h=>setAiInstrHints(prev=>prev.includes(h)?prev.filter(x=>x!==h):[...prev,h])}/>
              </div>

              {/* Generate Button */}
              <div className="relative">
                <button onClick={handleAIGenerate} disabled={isGenerating} data-testid="ai-generate-btn" className={cn("w-full py-4 rounded-2xl font-black text-sm tracking-wider border transition-all",isGenerating?"bg-violet-500/8 border-violet-500/20 text-violet-500/40 cursor-not-allowed":"bg-gradient-to-r from-violet-600/25 to-pink-600/20 border-violet-500/30 text-white hover:from-violet-600/35 hover:to-pink-600/30 hover:border-violet-500/50 shadow-xl shadow-violet-500/10 hover:shadow-violet-500/20")}>
                  {isGenerating
                    ?<div className="flex items-center justify-center gap-3"><QsWaveformViz active count={24} color="#8b5cf6"/><span>Quantum AI composing...</span><QsWaveformViz active count={24} color="#ec4899"/></div>
                    :<div className="flex items-center justify-center gap-2"><Zap className="w-4 h-4 text-violet-400"/>Generate Beat for Pattern {activePattern}<span className="ml-1 text-violet-400/50">· {genre.replace(/_/g,' ')} · {mood} · {bpm}bpm</span></div>
                  }
                </button>
              </div>

              {/* Export & Tips */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06]">
                  <div className="text-[10px] font-black text-white/60 mb-3 uppercase tracking-wider flex items-center gap-2"><Download className="w-3 h-3 text-cyan-400"/>Export</div>
                  <div className="flex flex-col gap-2">
                    <button onClick={handleExport} disabled={isExporting} className="flex items-center justify-center gap-2 py-2 rounded-xl bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 text-xs font-bold hover:bg-cyan-500/20 disabled:opacity-40">
                      {isExporting?<Loader2 className="w-3 h-3 animate-spin"/>:<Download className="w-3 h-3"/>}Full Mix (WAV)</button>
                    <button onClick={handleExportStems} disabled={isStemsExporting} className="flex items-center justify-center gap-2 py-2 rounded-xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 text-xs font-bold hover:bg-emerald-500/20 disabled:opacity-40">
                      {isStemsExporting?<Loader2 className="w-3 h-3 animate-spin"/>:<Layers className="w-3 h-3"/>}Stems (16 WAV)</button>
                    <button onClick={()=>qsExportMidi(pianoRollNotesForCurrent,bpm,INSTRUMENTS.find(i=>i.id===pianoRollInst)?.name||'Piano Roll')} disabled={!pianoRollNotesForCurrent.length} className="flex items-center justify-center gap-2 py-2 rounded-xl bg-purple-500/10 border border-purple-500/20 text-purple-400 text-xs font-bold hover:bg-purple-500/20 disabled:opacity-30">Piano Roll (MIDI)</button>
                  </div>
                </div>
                <div className="p-4 rounded-2xl bg-white/[0.025] border border-white/[0.06]">
                  <div className="text-[10px] font-black text-white/60 mb-3 uppercase tracking-wider flex items-center gap-2"><Music className="w-3 h-3 text-yellow-400"/>Tips</div>
                  <div className="space-y-1.5 text-[10px] text-white/40">
                    <div className="flex gap-2"><span className="text-violet-400">▸</span><span><strong className="text-white/55">Step Seq</strong> — Click to toggle, right-click = velocity/pitch</span></div>
                    <div className="flex gap-2"><span className="text-violet-400">▸</span><span><strong className="text-white/55">Pattern Tools</strong> — Fill, Randomize, Humanize, Copy/Paste</span></div>
                    <div className="flex gap-2"><span className="text-violet-400">▸</span><span><strong className="text-white/55">Tap Tempo</strong> — TAP button in transport bar</span></div>
                    <div className="flex gap-2"><span className="text-violet-400">▸</span><span><strong className="text-white/55">Patterns A–H</strong> — Arrange in Song Arranger</span></div>
                    <div className="flex gap-2"><span className="text-violet-400">▸</span><span><strong className="text-white/55">Ctrl+Z / Ctrl+Y</strong> — Full undo/redo</span></div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
        {showFX&&selectedChannel&&activeTab==='sequencer'&&<QsEffectsRack channelId={selectedChannel} effects={mixer[selectedChannel]||{}} onUpdate={(k:string,v:any)=>updateMixer(selectedChannel,k,v)} onClose={()=>setShowFX(false)}/>}
        {showMixer&&<QsMixerPanel mixer={mixer} onUpdate={updateMixer} selectedChannel={selectedChannel} onSelectChannel={setSelectedChannel}/>}
      </div>
      <QsProjectManager open={showProjects} onClose={()=>setShowProjects(false)} onSave={handleSaveProject} onLoad={handleLoadProject}/>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   QUANTAPEDIA — The AI-Native Knowledge Universe
   Replaces: Wikipedia · All Dictionaries · All Encyclopedias · Every Reference
   Powered by Groq AI · localStorage cache · Concept graph · A-Z browse
   ═══════════════════════════════════════════════════════════════════════ */
type QuantaEntry={
  title:string;type:string;pronunciation?:string;partOfSpeech?:string;
  summary:string;definitions:{number:number;text:string;example?:string}[];
  etymology?:string;synonyms:string[];antonyms:string[];relatedTerms:string[];
  sections:{title:string;content:string}[];quickFacts:{label:string;value:string}[];
  categories:string[];seeAlso:string[];
  // Financial entity extras (populated when type = 'company' | 'stock' | 'financial')
  ticker?:string;exchange?:string;listingStatus?:string;headquarters?:string;
  founded?:string;industry?:string;ceo?:string;
};
const QP_FEATURED=[
  {q:'Quantum mechanics',emoji:'⚛️',cat:'Physics'},
  {q:'Artificial intelligence',emoji:'🤖',cat:'Technology'},
  {q:'DNA',emoji:'🧬',cat:'Biology'},
  {q:'Consciousness',emoji:'🧠',cat:'Philosophy'},
  {q:'Language',emoji:'💬',cat:'Linguistics'},
  {q:'Democracy',emoji:'🗳️',cat:'Politics'},
  {q:'Universe',emoji:'🌌',cat:'Cosmology'},
  {q:'Love',emoji:'❤️',cat:'Emotion'},
  {q:'Mathematics',emoji:'∞',cat:'Science'},
  {q:'$NVDA NVIDIA stock',emoji:'📈',cat:'Finance'},
  {q:'$TSLA Tesla stock',emoji:'🚗',cat:'Finance'},
  {q:'$BHAT Blue Hat Interactive stock',emoji:'🎮',cat:'Finance'},
  {q:'Bitcoin',emoji:'₿',cat:'Crypto'},
  {q:'Stock market crash',emoji:'📉',cat:'Finance'},
  {q:'Music',emoji:'🎵',cat:'Art'},
  {q:'Evolution',emoji:'🦎',cat:'Biology'},
];
const QP_CATEGORIES=[
  {label:'Science',emoji:'🔬',topics:['Physics','Chemistry','Biology','Astronomy','Geology','Ecology','Neuroscience']},
  {label:'Technology',emoji:'💻',topics:['Artificial Intelligence','Computer Science','Engineering','Robotics','Blockchain','Quantum Computing']},
  {label:'Finance & Markets',emoji:'📈',topics:['$BHAT Blue Hat Interactive stock','$NVDA NVIDIA stock','$TSLA Tesla stock','Stock market crash','Bitcoin','Short selling','Delisted stocks','Nasdaq requirements','IPO process','Penny stocks','Hedge funds','Market cap']},
  {label:'Companies',emoji:'🏢',topics:['Blue Hat Interactive Entertainment','Nvidia Corporation','Tesla Inc','Apple Inc','Microsoft Corporation','Alibaba Group','Amazon','Goldman Sachs','BlackRock','Berkshire Hathaway']},
  {label:'History',emoji:'📜',topics:['Ancient Rome','Renaissance','World War II','Industrial Revolution','Cold War','Egyptian Empire']},
  {label:'Philosophy',emoji:'🤔',topics:['Ethics','Epistemology','Metaphysics','Logic','Aesthetics','Existentialism','Stoicism']},
  {label:'Language',emoji:'💬',topics:['Etymology','Grammar','Linguistics','Phonetics','Semantics','Pragmatics','Morphology']},
  {label:'Mathematics',emoji:'∑',topics:['Calculus','Algebra','Geometry','Statistics','Number Theory','Topology','Combinatorics']},
  {label:'Arts',emoji:'🎨',topics:['Painting','Sculpture','Music Theory','Film','Literature','Architecture','Dance']},
  {label:'Nature',emoji:'🌿',topics:['Ecology','Botany','Zoology','Climate','Oceans','Forests','Microbiome']},
  {label:'Culture',emoji:'🌍',topics:['Mythology','Religion','Anthropology','Sociology','Folklore','Ritual','Tradition']},
  {label:'People',emoji:'👤',topics:['Albert Einstein','Leonardo da Vinci','Marie Curie','Nikola Tesla','Socrates','Ada Lovelace']},
];
const QP_ALPHABET='ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');

function QuantapediaPage({initialTopic=''}:{initialTopic?:string}){
  const [view,setView]=useState<'home'|'entry'|'browse'|'letter'>('home');
  const [query,setQuery]=useState('');
  const [entry,setEntry]=useState<QuantaEntry|null>(null);
  const [loading,setLoading]=useState(false);
  const [activeTab,setActiveTab]=useState<'encyclopedia'|'dictionary'|'thesaurus'|'graph'>('encyclopedia');
  const [letter,setLetter]=useState('A');
  const [history,setHistory]=useState<string[]>(()=>{try{return JSON.parse(localStorage.getItem('qp_history')||'[]');}catch{return [];}});
  const [bookmarks,setBookmarks]=useState<string[]>(()=>{try{return JSON.parse(localStorage.getItem('qp_bookmarks')||'[]');}catch{return [];}});
  const [cache,setCache]=useState<Record<string,QuantaEntry>>(()=>{try{return JSON.parse(localStorage.getItem('qp_cache')||'{}');}catch{return {};}});
  const [inputVal,setInputVal]=useState('');
  const {toast}=useToast();
  const [,setLocation]=useLocation();
  const [engineStatus,setEngineStatus]=useState<{running:boolean;totalGenerated:number;total:number;generated:number;queued:number}|null>(null);

  useEffect(()=>{
    const fetchStatus=()=>fetch('/api/quantapedia/engine-status').then(r=>r.json()).then(setEngineStatus).catch(()=>{});
    fetchStatus();
    const id=setInterval(fetchStatus,10000);
    // Pre-seed high-value financial topics including delisted stocks so they're always available
    const financialSeedTopics=[
      {slug:'blue-hat-interactive-entertainment-technology',title:'Blue Hat Interactive Entertainment Technology ($BHAT)'},
      {slug:'bhat-stock-delisted',title:'$BHAT Blue Hat Interactive Stock'},
      {slug:'bhat-nasdaq-delisted',title:'BHAT NASDAQ Delisting'},
      {slug:'nasdaq-delisting-requirements',title:'NASDAQ Delisting Requirements'},
      {slug:'chinese-us-listed-stocks',title:'Chinese Stocks Listed in US'},
      {slug:'penny-stocks-delisted',title:'Delisted Penny Stocks'},
      {slug:'stock-market-delisting-process',title:'Stock Market Delisting Process'},
    ];
    fetch('/api/quantapedia/queue',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({topics:financialSeedTopics})}).catch(()=>{});
    return ()=>clearInterval(id);
  },[]);

  const toSlug=(q:string)=>q.trim().toLowerCase().replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,'');

  // Detect financial/stock queries: "$BHAT", "BHAT stock", "blue hat stock", "NVDA shares", etc.
  const detectFinancialQuery=(q:string):{isFinancial:boolean;ticker:string;companyHint:string}=>{
    const upper=q.toUpperCase().trim();
    const lower=q.toLowerCase().trim();
    const tickerMatch=q.match(/\$([A-Z]{1,5})/i)||q.match(/^([A-Z]{1,5})\s+(stock|shares|etf|ticker|price)/i);
    const ticker=tickerMatch?(tickerMatch[1]||tickerMatch[1]).toUpperCase():'';
    const isFinancial=!!(
      ticker||
      lower.includes(' stock')||lower.includes(' shares')||lower.includes('ticker')||
      lower.includes('nasdaq')||lower.includes('nyse')||lower.includes('nyse:')||
      lower.includes('delisted')||lower.includes(' ipo')||lower.includes(' etf')||
      lower.includes(' fund')||lower.includes(' inc ')||lower.includes(' corp')||
      lower.includes(' ltd ')||lower.includes(' llc ')||lower.includes(' plc ')||
      lower.includes('hedge fund')||lower.includes('market cap')||lower.includes('stock market')
    );
    const companyHint=q.replace(/\$[A-Z]{1,5}/gi,'').replace(/\b(stock|shares|ticker|price|etf|ipo|nasdaq|nyse|inc|corp|ltd|llc|plc)\b/gi,'').trim()||ticker;
    return {isFinancial,ticker,companyHint};
  };

  const applyEntrySEO=(parsed:QuantaEntry,q:string)=>{
    const slug=toSlug(q);
    document.title=`${parsed.title} — Quantapedia | My Ai GPT`;
    let metaDesc=document.querySelector('meta[name="description"]') as HTMLMetaElement|null;
    if(!metaDesc){metaDesc=document.createElement('meta');(metaDesc as HTMLMetaElement).name='description';document.head.appendChild(metaDesc);}
    metaDesc.content=`${parsed.summary} — Look up ${parsed.title} on Quantapedia, the AI-native knowledge encyclopedia by My Ai GPT.`;
    document.querySelector('#qp-jsonld')?.remove();
    const script=document.createElement('script');
    script.type='application/ld+json';script.id='qp-jsonld';
    const isWord=parsed.type==='word'||parsed.type==='phrase';
    script.textContent=JSON.stringify({
      '@context':'https://schema.org',
      '@type':isWord?'DefinedTerm':'Article',
      'name':parsed.title,
      'description':parsed.summary,
      'url':window.location.origin+'/quantapedia/'+slug,
      'keywords':(parsed.categories||[]).join(', '),
      ...(isWord?{'inDefinedTermSet':window.location.origin+'/quantapedia'}:{'headline':parsed.title,'articleBody':parsed.sections?.map(s=>s.content).join(' ')||''})
    });
    document.head.appendChild(script);
    fetch('/api/quantapedia/track',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({slug,title:parsed.title,summary:(parsed.summary||'').slice(0,500),type:parsed.type||'concept',categories:parsed.categories||[],relatedTerms:parsed.relatedTerms||[]})}).catch(()=>{});
  };

  useEffect(()=>{
    if(initialTopic){const human=initialTopic.replace(/-+/g,' ').trim();setInputVal(human);lookup(human);}
    return()=>{document.querySelector('#qp-jsonld')?.remove();if(document.title.includes('Quantapedia'))document.title='My Ai GPT';};
  },[]);

  const saveHistory=(t:string)=>{const h=[t,...history.filter(x=>x!==t)].slice(0,20);setHistory(h);localStorage.setItem('qp_history',JSON.stringify(h));};
  const toggleBookmark=(t:string)=>{const b=bookmarks.includes(t)?bookmarks.filter(x=>x!==t):[t,...bookmarks];setBookmarks(b);localStorage.setItem('qp_bookmarks',JSON.stringify(b));};

  const lookup=async(q:string)=>{
    if(!q.trim())return;
    const key=q.trim().toLowerCase();
    const slug=toSlug(q);
    if(cache[key]){
      const cached=cache[key];
      setEntry(cached);setQuery(q);setView('entry');saveHistory(q);
      setLocation('/quantapedia/'+slug,{replace:true});
      applyEntrySEO(cached,q);
      return;
    }
    setLoading(true);setQuery(q);setView('entry');
    // Try server DB first
    try{
      const serverRes=await fetch('/api/quantapedia/entry/'+slug);
      const serverData=await serverRes.json();
      if(serverData.entry){
        const pre:QuantaEntry=serverData.entry as QuantaEntry;
        const newCache={...cache,[key]:pre};
        setCache(newCache);
        localStorage.setItem('qp_cache',JSON.stringify(newCache));
        setEntry(pre);
        saveHistory(q);
        setLocation('/quantapedia/'+slug,{replace:true});
        applyEntrySEO(pre,q);
        setLoading(false);
        return;
      }
    } catch{}

    // Build the AI prompt — financial queries get a specialized prompt that always returns real data
    const {isFinancial,ticker,companyHint}=detectFinancialQuery(q);
    const aiPrompt=isFinancial
      ?`You are QuantapediaAI — the world's most comprehensive financial and corporate knowledge engine. Generate a complete, accurate structured knowledge entry for the financial entity: "${q}"${ticker?` (ticker: $${ticker})`:''}${companyHint&&companyHint!==ticker?` — company name hint: "${companyHint}"`:''}.

This may be a stock, company, ETF, index, cryptocurrency, or financial concept — including DELISTED, bankrupt, obscure, foreign-listed, OTC, or micro-cap entities. Use all available knowledge about this entity. If listing status is unknown, research context clues from the name/ticker to determine the most likely exchange, industry, and status.

Return ONLY a valid JSON object with this exact schema:
{
  "title": "Full official company/entity name",
  "type": "company",
  "ticker": "${ticker||''}",
  "exchange": "NASDAQ|NYSE|OTC|AMEX|LSE|etc or 'Delisted'",
  "listingStatus": "Active|Delisted|Suspended|Private|Merged",
  "headquarters": "City, Country",
  "founded": "year or approximate period",
  "industry": "primary industry",
  "ceo": "current or last known CEO",
  "pronunciation": "",
  "partOfSpeech": "",
  "summary": "2-3 sentence overview of the company, its business, and current status",
  "definitions": [
    {"number": 1, "text": "what this company does / business model", "example": ""},
    {"number": 2, "text": "history of its stock listing and any notable events", "example": ""}
  ],
  "etymology": "origin of company name if notable, otherwise empty string",
  "synonyms": ["alternative names, trading names, or subsidiaries"],
  "antonyms": [],
  "relatedTerms": ["competitor companies", "related industries", "financial concepts relevant to this company"],
  "sections": [
    {"title": "Company Overview", "content": "Full description of what the company does, products/services, target markets, and business model"},
    {"title": "Stock History & Listing", "content": "IPO date, exchange listing, price history highlights, any delistings, reasons for delisting, any stock splits or significant corporate events"},
    {"title": "Products & Services", "content": "Key products, services, or technologies the company offers"},
    {"title": "Financial Performance", "content": "Revenue trends, profitability, key financial metrics, market cap at peak, any SEC filings or investigations"},
    {"title": "Current Status", "content": "Current operational status, any restructuring, bankruptcy, merger, acquisition, or OTC trading information"}
  ],
  "quickFacts": [
    {"label": "Ticker Symbol", "value": "$${ticker||'N/A'}"},
    {"label": "Exchange", "value": "exchange name"},
    {"label": "Listing Status", "value": "Active / Delisted / etc"},
    {"label": "Headquarters", "value": "city, country"},
    {"label": "Founded", "value": "year"},
    {"label": "Industry", "value": "sector"},
    {"label": "Category", "value": "Public Company / Private / Delisted"},
    {"label": "Complexity", "value": "Intermediate"}
  ],
  "categories": ["Finance", "Stocks", "Companies", "relevant industry tags"],
  "seeAlso": ["related companies", "NASDAQ delisting process", "penny stocks", "Chinese US-listed stocks", "related financial topics"]
}`
      :`You are QuantapediaAI — the world's most comprehensive AI knowledge engine. Generate a complete structured knowledge entry for: "${q}"

Return ONLY a valid JSON object (no markdown, no explanation, just raw JSON) with this exact schema:
{
  "title": "canonical title",
  "type": "word|phrase|person|place|concept|event|field|organism|chemical|historical|cultural|mathematical|other",
  "pronunciation": "IPA pronunciation if applicable or empty string",
  "partOfSpeech": "noun|verb|adjective|adverb|... or empty string if not a word",
  "summary": "2-3 sentence comprehensive overview",
  "definitions": [
    {"number": 1, "text": "primary definition", "example": "usage example sentence"},
    {"number": 2, "text": "secondary definition if applicable", "example": ""}
  ],
  "etymology": "word origin and history if applicable, otherwise empty string",
  "synonyms": ["up to 8 synonyms or related terms"],
  "antonyms": ["up to 5 antonyms if applicable"],
  "relatedTerms": ["8-12 closely related concepts, terms, or topics"],
  "sections": [
    {"title": "Overview", "content": "3-4 paragraph comprehensive overview"},
    {"title": "History & Origin", "content": "historical background and development"},
    {"title": "Key Concepts", "content": "core ideas, mechanisms, or components"},
    {"title": "Applications & Significance", "content": "real-world uses and importance"},
    {"title": "Modern Context", "content": "current state, debates, and future directions"}
  ],
  "quickFacts": [
    {"label": "Category", "value": "..."},
    {"label": "Domain", "value": "..."},
    {"label": "First Known Use", "value": "..."},
    {"label": "Complexity", "value": "Beginner|Intermediate|Advanced|Expert"}
  ],
  "categories": ["3-6 category tags"],
  "seeAlso": ["6-10 related topics to explore next"]
}`;

    try{
      const res=await fetch('/api/chat/completions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({messages:[{role:'user',content:aiPrompt}]})});
      const data=await res.json();
      let parsed:QuantaEntry;
      try{parsed=JSON.parse(data.content);}
      catch{
        const match=data.content.match(/\{[\s\S]*\}/);
        if(match)parsed=JSON.parse(match[0]);
        else throw new Error('parse fail');
      }
      const newCache={...cache,[key]:parsed};
      setCache(newCache);
      localStorage.setItem('qp_cache',JSON.stringify(newCache));
      setEntry(parsed);
      saveHistory(q);
      setLocation('/quantapedia/'+slug,{replace:true});
      applyEntrySEO(parsed,q);
      // Queue discovered related topics for background generation
      const discoveredTopics=[...(parsed.relatedTerms||[]),...(parsed.seeAlso||[])].slice(0,12).map((t:string)=>({slug:toSlug(t),title:t}));
      if(discoveredTopics.length)fetch('/api/quantapedia/queue',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({topics:discoveredTopics})}).catch(()=>{});
      // Also track this new entry in the DB
      fetch('/api/quantapedia/track',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({slug,title:parsed.title,summary:(parsed.summary||'').slice(0,500),type:parsed.type||'concept',categories:parsed.categories||[],relatedTerms:parsed.relatedTerms||[]})}).catch(()=>{});
    } catch(err){
      // Final fallback: generate a minimal stub so the user ALWAYS gets something
      const {isFinancial:fin,ticker:t2,companyHint:ch}=detectFinancialQuery(q);
      const stub:QuantaEntry={
        title:fin&&t2?`${ch||t2} ($${t2})`:(q.trim()),
        type:fin?'company':'concept',
        ticker:t2||undefined,
        listingStatus:fin?'Status unknown — researching...':undefined,
        summary:`Quantapedia is generating a full entry for "${q}". This topic has been queued for deep knowledge expansion.`,
        definitions:[{number:1,text:`${q} — knowledge entry being generated.`,example:''}],
        synonyms:[],antonyms:[],relatedTerms:[],
        sections:[{title:'Entry Loading',content:`Our knowledge engine has queued "${q}" for full generation. Please search again in a moment or explore related topics below.`}],
        quickFacts:[{label:'Status',value:'Queued for generation'},{label:'Category',value:fin?'Finance':'General'},{label:'Complexity',value:'Unknown'}],
        categories:fin?['Finance','Companies','Stocks']:['General'],
        seeAlso:fin?['Stock market','NASDAQ','NYSE','IPO','Penny stocks','Delisted stocks']:['Knowledge','Encyclopedia','Reference'],
      };
      setEntry(stub);
      saveHistory(q);
      setLocation('/quantapedia/'+slug,{replace:true});
      // Queue this topic for proper generation
      fetch('/api/quantapedia/queue',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({topics:[{slug,title:q.trim()}]})}).catch(()=>{});
      toast({title:`"${q.trim()}" queued for knowledge generation`,description:'Try again in a moment for the full entry.',variant:'default'});
    }
    finally{setLoading(false);}
  };

  const typeColor=(t:string)=>{
    const m:Record<string,string>={word:'violet',phrase:'blue',person:'amber',place:'green',concept:'cyan',event:'orange',field:'pink',organism:'emerald',chemical:'red',historical:'yellow',cultural:'purple',mathematical:'indigo',company:'emerald',stock:'green',financial:'teal',finance:'teal',crypto:'yellow'};
    return m[t?.toLowerCase()]||'white';
  };

  // ─── HOME VIEW ────────────────────────────────────────────────────────
  if(view==='home') return(
    <div className="flex-1 overflow-auto" style={{background:'linear-gradient(180deg,#020010,#050020)'}}>
      {/* Hero */}
      <div className="px-4 pt-10 pb-8 text-center" style={{background:'linear-gradient(180deg,#0a0030,#050020)'}}>
        <div className="text-6xl mb-3 font-black" style={{background:'linear-gradient(135deg,#a78bfa,#60a5fa,#34d399)',WebkitBackgroundClip:'text',WebkitTextFillColor:'transparent'}}>Q</div>
        <h1 className="text-white font-black text-3xl mb-1" style={{letterSpacing:'-0.03em'}}>Quantapedia</h1>
        <p className="text-white/30 text-sm mb-1">The AI-Native Knowledge Universe</p>
        <p className="text-white/15 text-[10px] mb-6">Every word · Every concept · Every entity · Every fact · Powered by AI</p>
        {/* Search */}
        <div className="max-w-xl mx-auto relative">
          <div className="flex gap-2">
            <input value={inputVal} onChange={e=>setInputVal(e.target.value)} onKeyDown={e=>e.key==='Enter'&&lookup(inputVal)}
              placeholder="Search anything — word, person, concept, place, event..."
              data-testid="input-quantapedia-search"
              className="flex-1 bg-white/8 border border-violet-500/30 rounded-2xl text-white text-sm px-5 py-3.5 placeholder-white/20 focus:outline-none focus:border-violet-400/60 focus:bg-white/10 transition-all"/>
            <button onClick={()=>lookup(inputVal)} data-testid="button-quantapedia-search"
              className="px-6 py-3.5 rounded-2xl font-black text-white text-sm transition-all hover:opacity-90"
              style={{background:'linear-gradient(135deg,#7c3aed,#4f46e5)'}}>Search</button>
          </div>
        </div>
        {/* Featured quick-access */}
        <div className="flex flex-wrap gap-2 justify-center max-w-2xl mx-auto mt-4">
          {QP_FEATURED.map(f=>(
            <button key={f.q} onClick={()=>lookup(f.q)} className="px-3 py-1.5 rounded-full text-xs bg-white/5 border border-white/10 text-white/50 hover:text-white/80 hover:bg-white/10 hover:border-white/20 transition-all">
              {f.emoji} {f.q}
            </button>
          ))}
        </div>
      </div>

      <div className="px-4 pb-8 max-w-4xl mx-auto space-y-8">
        {/* Live Engine Status */}
        {engineStatus&&(
          <div className="rounded-2xl border border-violet-500/20 bg-violet-950/20 p-4">
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${engineStatus.running?'bg-green-400 shadow-[0_0_6px_rgba(74,222,128,0.8)]':'bg-red-400'}`} style={engineStatus.running?{animation:'pulse 1.5s infinite'}:{}}/>
                <span className="text-white/70 font-black text-xs tracking-wider uppercase">Autonomous Knowledge Engine</span>
                {engineStatus.running&&<span className="text-green-400/70 text-[9px]">● LIVE</span>}
              </div>
              <span className="text-white/20 text-[9px]">Generating 1 entry every 4s</span>
            </div>
            <div className="grid grid-cols-4 gap-2">
              <div className="text-center p-2.5 rounded-xl bg-white/[0.03] border border-white/5">
                <div className="text-violet-400 font-black text-lg">{engineStatus.total.toLocaleString()}</div>
                <div className="text-white/25 text-[9px]">Total Topics</div>
              </div>
              <div className="text-center p-2.5 rounded-xl bg-white/[0.03] border border-white/5">
                <div className="text-green-400 font-black text-lg">{engineStatus.generated.toLocaleString()}</div>
                <div className="text-white/25 text-[9px]">Generated</div>
              </div>
              <div className="text-center p-2.5 rounded-xl bg-white/[0.03] border border-white/5">
                <div className="text-yellow-400 font-black text-lg">{engineStatus.queued.toLocaleString()}</div>
                <div className="text-white/25 text-[9px]">In Queue</div>
              </div>
              <div className="text-center p-2.5 rounded-xl bg-white/[0.03] border border-white/5">
                <div className="text-cyan-400 font-black text-lg">{engineStatus.generated>0?Math.round((engineStatus.generated/engineStatus.total)*100):0}%</div>
                <div className="text-white/25 text-[9px]">Coverage</div>
              </div>
            </div>
            <div className="mt-2.5 rounded-full bg-white/5 h-1.5 overflow-hidden">
              <div className="h-full bg-gradient-to-r from-violet-500 to-cyan-500 transition-all duration-1000 rounded-full" style={{width:`${engineStatus.total>0?Math.round((engineStatus.generated/engineStatus.total)*100):0}%`}}/>
            </div>
            <div className="mt-1.5 text-white/15 text-[9px] text-center">Auto-discovers new topics from every generated entry · Grows fractal-style like your Python hive script</div>
          </div>
        )}

        {/* Browse by category */}
        <div>
          <div className="flex items-center gap-2 mb-4"><span className="text-white font-black text-sm">📚 Browse by Domain</span><div className="flex-1 h-px bg-white/5"/></div>
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-2.5">
            {QP_CATEGORIES.map(cat=>(
              <button key={cat.label} onClick={()=>lookup(cat.topics[0])} data-testid={`qp-cat-${cat.label.toLowerCase()}`}
                className="group p-3 rounded-2xl bg-white/[0.025] border border-white/8 hover:border-white/20 hover:bg-white/[0.05] transition-all text-left">
                <div className="text-2xl mb-1.5">{cat.emoji}</div>
                <div className="text-white/80 font-bold text-xs mb-1">{cat.label}</div>
                <div className="text-white/25 text-[9px] leading-relaxed">{cat.topics.slice(0,3).join(' · ')}</div>
              </button>
            ))}
          </div>
        </div>

        {/* A-Z Browse */}
        <div>
          <div className="flex items-center gap-2 mb-3"><span className="text-white font-black text-sm">🔤 Browse A–Z</span><div className="flex-1 h-px bg-white/5"/></div>
          <div className="flex flex-wrap gap-1.5">
            {QP_ALPHABET.map(l=>(
              <button key={l} onClick={()=>{setLetter(l);setView('letter');}} data-testid={`qp-letter-${l}`}
                className="w-8 h-8 rounded-lg bg-white/5 border border-white/10 text-white/40 font-black text-xs hover:text-white hover:bg-violet-500/20 hover:border-violet-500/30 transition-all">{l}</button>
            ))}
          </div>
        </div>

        {/* Recent + Bookmarks */}
        <div className="grid sm:grid-cols-2 gap-4">
          {history.length>0&&(
            <div>
              <div className="flex items-center gap-2 mb-2"><span className="text-white/50 font-bold text-xs">🕐 Recent</span><div className="flex-1 h-px bg-white/5"/><button onClick={()=>{setHistory([]);localStorage.removeItem('qp_history');}} className="text-[9px] text-white/20 hover:text-white/40">Clear</button></div>
              <div className="space-y-1">
                {history.slice(0,8).map(h=>(
                  <button key={h} onClick={()=>lookup(h)} className="w-full text-left px-3 py-1.5 rounded-lg bg-white/[0.02] border border-white/5 hover:border-white/15 hover:bg-white/[0.04] transition-all">
                    <span className="text-white/50 text-xs hover:text-white/70">{h}</span>
                  </button>
                ))}
              </div>
            </div>
          )}
          {bookmarks.length>0&&(
            <div>
              <div className="flex items-center gap-2 mb-2"><span className="text-white/50 font-bold text-xs">🔖 Bookmarks</span><div className="flex-1 h-px bg-white/5"/></div>
              <div className="space-y-1">
                {bookmarks.slice(0,8).map(b=>(
                  <button key={b} onClick={()=>lookup(b)} className="w-full text-left px-3 py-1.5 rounded-lg bg-white/[0.02] border border-violet-500/10 hover:border-violet-500/20 hover:bg-violet-500/5 transition-all">
                    <span className="text-violet-300/60 text-xs hover:text-violet-300/80">{b}</span>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );

  // ─── LETTER BROWSE VIEW ───────────────────────────────────────────────
  if(view==='letter'){
    const letterTopics:Record<string,string[]>={A:['Atom','Algorithm','Architecture','Algebra','Astronomy','Anthropology','Anxiety','Automation'],B:['Biology','Brain','Buddhism','Blockchain','Black Hole','Bacteria','Byzantine'],C:['Calculus','Chemistry','Consciousness','Culture','Cosmology','Cyberpunk','Cryptography'],D:['DNA','Democracy','Dimension','Differential equations','Dystopia','Dark matter'],E:['Evolution','Ethics','Entropy','Economics','Ecology','Electricity','Epistemology'],F:['Fibonacci','Folklore','Fluid dynamics','Fractal','Freudian psychology','Fusion'],G:['Genetics','Gravity','Greek mythology','Graph theory','Geodesy'],H:['History','Hydrogen','Holography','Homeostasis','Heisenberg uncertainty'],I:['Intelligence','Internet','Immune system','Infinity','Information theory'],J:['JavaScript','Jupiter','Jurisprudence','Jazz theory'],K:['Knowledge','Kinetics','Kant philosophy','Kepler laws'],L:['Language','Light','Logic','Linguistics','Logarithm','Love'],M:['Mathematics','Metaphysics','Music theory','Machine learning','Magnetism','Mythology'],N:['Neuroscience','Nanotechnology','Nuclear physics','Number theory','Network theory'],O:['Optics','Ontology','Organic chemistry','Ocean science'],P:['Philosophy','Physics','Photosynthesis','Psychology','Prime numbers','Plate tectonics'],Q:['Quantum mechanics','Quasar','Qualia','Quantum computing'],R:['Relativity','Rhetoric','Renaissance','RNA','Recursion'],S:['Sociology','String theory','Statistics','Stoicism','Symmetry','Semiotics'],T:['Thermodynamics','Time','Topology','Trigonometry','Turing machine'],U:['Universe','Utopia','Uncertainty principle','Ultraviolet'],V:['Vector calculus','Virus','Vocabulary','Virtue ethics'],W:['Wave mechanics','Wisdom','World War II','Wormhole'],X:['X-ray','Xenobiology','XML'],Y:['Yin and yang'],Z:['Zero','Zoology','Zeta function']};
    const topics=letterTopics[letter]||[];
    return(
      <div className="flex-1 overflow-auto" style={{background:'linear-gradient(180deg,#020010,#050020)'}}>
        <div className="px-4 py-4 border-b border-white/8 flex items-center gap-3" style={{background:'rgba(2,0,16,0.98)'}}>
          <button onClick={()=>setView('home')} className="flex items-center gap-1 text-white/40 hover:text-white text-xs"><ChevronLeft size={14}/>Back</button>
          <div className="w-px h-4 bg-white/10"/>
          <span className="text-white font-black">Browse: {letter}</span>
          <div className="flex gap-1 ml-auto flex-wrap">
            {QP_ALPHABET.map(l=><button key={l} onClick={()=>setLetter(l)} className={cn("w-7 h-7 rounded text-[10px] font-black transition-all",l===letter?"bg-violet-500 text-white":"bg-white/5 text-white/30 hover:text-white/60")}>{l}</button>)}
          </div>
        </div>
        <div className="p-4 max-w-2xl mx-auto">
          <div className="grid grid-cols-2 gap-2.5">
            {topics.map(t=>(
              <button key={t} onClick={()=>lookup(t)} className="p-3 rounded-xl bg-white/[0.025] border border-white/8 hover:border-violet-500/30 hover:bg-violet-500/5 text-left transition-all group">
                <div className="text-white/70 font-bold text-sm group-hover:text-violet-300">{t}</div>
                <div className="text-white/20 text-[9px] mt-0.5">Click to explore →</div>
              </button>
            ))}
            <button onClick={()=>lookup(`list of terms starting with ${letter}`)} className="p-3 rounded-xl bg-violet-500/5 border border-violet-500/15 hover:bg-violet-500/10 text-left transition-all">
              <div className="text-violet-400 font-bold text-sm">+ More {letter} topics...</div>
              <div className="text-white/20 text-[9px] mt-0.5">AI generates on demand</div>
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ─── ENTRY LOADING STATE ──────────────────────────────────────────────
  if(loading) return(
    <div className="flex-1 flex flex-col items-center justify-center gap-4" style={{background:'linear-gradient(180deg,#020010,#050020)'}}>
      <div className="text-6xl animate-pulse">Q</div>
      <div className="space-y-2 text-center">
        <div className="text-white font-black text-lg">Querying the Knowledge Universe...</div>
        <div className="text-white/30 text-sm">Generating your entry for: <span className="text-violet-300">{query}</span></div>
        <div className="flex gap-1 justify-center mt-3">
          {['QuantumPedia','Dictionary','Thesaurus','Concepts','Graph'].map((l,i)=>(
            <span key={l} className="text-[9px] px-2 py-0.5 rounded-full bg-violet-500/20 text-violet-400" style={{animationDelay:`${i*0.15}s`}}>{l}</span>
          ))}
        </div>
      </div>
    </div>
  );

  // ─── ENTRY VIEW ───────────────────────────────────────────────────────
  if(view==='entry'&&entry){
    const tc=typeColor(entry.type);
    const isBookmarked=bookmarks.includes(query);
    return(
      <div className="flex-1 overflow-auto" style={{background:'linear-gradient(180deg,#020010,#060025)'}}>
        {/* Top bar */}
        <div className="px-4 py-3 border-b border-white/8 flex items-center gap-3 flex-wrap" style={{background:'rgba(2,0,16,0.98)'}}>
          <button onClick={()=>setView('home')} className="flex items-center gap-1 text-white/40 hover:text-white text-xs"><ChevronLeft size={14}/>Back</button>
          <div className="w-px h-4 bg-white/10"/>
          <div className="flex-1 max-w-sm">
            <input value={inputVal} onChange={e=>setInputVal(e.target.value)} onKeyDown={e=>e.key==='Enter'&&lookup(inputVal)}
              placeholder="Search another term..." data-testid="input-qp-entry-search"
              className="w-full bg-white/5 border border-white/10 rounded-xl text-white text-xs px-3 py-2 placeholder-white/20 focus:outline-none focus:border-violet-500/40"/>
          </div>
          <button onClick={()=>toggleBookmark(query)} data-testid="button-qp-bookmark" className={cn("px-3 py-1.5 rounded-lg text-xs font-bold border transition-all",isBookmarked?"border-violet-500/40 bg-violet-500/20 text-violet-300":"border-white/10 text-white/30 hover:text-white/60")}>{isBookmarked?'🔖 Saved':'🔖 Save'}</button>
        </div>

        <div className="max-w-3xl mx-auto px-4 py-5 space-y-5">
          {/* Entry header */}
          <div className="rounded-2xl p-5 border" style={{background:'linear-gradient(135deg,rgba(124,58,237,0.1),rgba(79,70,229,0.08))',borderColor:'rgba(124,58,237,0.2)'}}>
            <div className="flex items-start gap-4">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-2 flex-wrap">
                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold bg-${tc}-500/15 text-${tc}-400 border border-${tc}-500/20 capitalize`}>{entry.type}</span>
                  {entry.partOfSpeech&&<span className="text-[10px] px-2 py-0.5 rounded-full font-bold bg-white/5 text-white/40 border border-white/10 italic">{entry.partOfSpeech}</span>}
                  {entry.categories?.slice(0,3).map(c=><span key={c} className="text-[9px] px-2 py-0.5 rounded-full bg-white/[0.03] text-white/25 border border-white/8">{c}</span>)}
                </div>
                <h1 className="text-white font-black text-2xl mb-1" style={{letterSpacing:'-0.02em'}}>{entry.title}</h1>
                {/* Financial ticker badge */}
                {(entry.ticker||entry.exchange||entry.listingStatus)&&(
                  <div className="flex items-center gap-2 mb-2 flex-wrap">
                    {entry.ticker&&<span className="px-2.5 py-1 rounded-lg text-sm font-black bg-emerald-500/15 text-emerald-400 border border-emerald-500/25 font-mono">${entry.ticker}</span>}
                    {entry.exchange&&<span className="px-2 py-0.5 rounded-lg text-xs font-bold bg-blue-500/10 text-blue-400 border border-blue-500/15">{entry.exchange}</span>}
                    {entry.listingStatus&&<span className={`px-2 py-0.5 rounded-lg text-xs font-bold border ${entry.listingStatus?.toLowerCase().includes('delist')||entry.listingStatus?.toLowerCase().includes('suspen')?'bg-red-500/15 text-red-400 border-red-500/25':'bg-green-500/10 text-green-400 border-green-500/15'}`}>{entry.listingStatus}</span>}
                    {entry.headquarters&&<span className="text-white/30 text-xs">📍 {entry.headquarters}</span>}
                    {entry.founded&&<span className="text-white/25 text-xs">Est. {entry.founded}</span>}
                  </div>
                )}
                {entry.pronunciation&&<div className="text-violet-400/60 text-sm font-mono mb-2">{entry.pronunciation}</div>}
                <p className="text-white/60 text-sm leading-relaxed">{entry.summary}</p>
              </div>
            </div>
          </div>

          {/* Quick facts bar */}
          {entry.quickFacts?.length>0&&(
            <div className="flex gap-3 overflow-x-auto" style={{scrollbarWidth:'none'}}>
              {entry.quickFacts.map(f=>(
                <div key={f.label} className="flex-shrink-0 px-3 py-2 rounded-xl bg-white/[0.03] border border-white/8 text-center">
                  <div className="text-white/30 text-[9px]">{f.label}</div>
                  <div className="text-white/70 font-bold text-xs mt-0.5">{f.value}</div>
                </div>
              ))}
            </div>
          )}

          {/* Tabs */}
          <div className="flex gap-1 p-1 rounded-xl bg-white/[0.03] border border-white/8">
            {(['encyclopedia','dictionary','thesaurus','graph'] as const).map(t=>(
              <button key={t} onClick={()=>setActiveTab(t)} data-testid={`qp-tab-${t}`}
                className={cn("flex-1 py-2 rounded-lg text-xs font-bold capitalize transition-all",activeTab===t?"bg-white text-gray-900 shadow":"text-white/40 hover:text-white/70")}>{t}</button>
            ))}
          </div>

          {/* ENCYCLOPEDIA TAB */}
          {activeTab==='encyclopedia'&&(
            <div className="space-y-4">
              {entry.sections?.map(s=>(
                <div key={s.title} className="rounded-xl p-4 bg-white/[0.025] border border-white/8">
                  <h3 className="text-white font-black text-sm mb-2 flex items-center gap-2"><span className="w-1 h-4 rounded-full bg-violet-500 inline-block"/>{s.title}</h3>
                  <p className="text-white/55 text-sm leading-relaxed">{s.content}</p>
                </div>
              ))}
            </div>
          )}

          {/* DICTIONARY TAB */}
          {activeTab==='dictionary'&&(
            <div className="space-y-4">
              {/* Definitions */}
              <div className="rounded-xl p-4 bg-white/[0.025] border border-white/8">
                <h3 className="text-white font-black text-xs mb-3 uppercase tracking-widest">Definitions</h3>
                <div className="space-y-3">
                  {entry.definitions?.map(d=>(
                    <div key={d.number} className="flex gap-3">
                      <span className="text-violet-400 font-black text-sm w-5 flex-shrink-0">{d.number}.</span>
                      <div>
                        <p className="text-white/70 text-sm">{d.text}</p>
                        {d.example&&<p className="text-white/30 text-xs italic mt-1">"{d.example}"</p>}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              {/* Etymology */}
              {entry.etymology&&(
                <div className="rounded-xl p-4 bg-white/[0.025] border border-white/8">
                  <h3 className="text-white font-black text-xs mb-2 uppercase tracking-widest">Etymology</h3>
                  <p className="text-white/50 text-sm leading-relaxed">{entry.etymology}</p>
                </div>
              )}
            </div>
          )}

          {/* THESAURUS TAB */}
          {activeTab==='thesaurus'&&(
            <div className="space-y-4">
              {entry.synonyms?.length>0&&(
                <div className="rounded-xl p-4 bg-white/[0.025] border border-white/8">
                  <h3 className="text-white font-black text-xs mb-3 uppercase tracking-widest text-green-400">✓ Synonyms</h3>
                  <div className="flex flex-wrap gap-2">
                    {entry.synonyms.map(s=><button key={s} onClick={()=>lookup(s)} className="px-3 py-1.5 rounded-lg bg-green-500/10 border border-green-500/20 text-green-300 text-xs hover:bg-green-500/20 transition-all">{s}</button>)}
                  </div>
                </div>
              )}
              {entry.antonyms?.length>0&&(
                <div className="rounded-xl p-4 bg-white/[0.025] border border-white/8">
                  <h3 className="text-white font-black text-xs mb-3 uppercase tracking-widest text-red-400">✗ Antonyms</h3>
                  <div className="flex flex-wrap gap-2">
                    {entry.antonyms.map(a=><button key={a} onClick={()=>lookup(a)} className="px-3 py-1.5 rounded-lg bg-red-500/10 border border-red-500/20 text-red-300 text-xs hover:bg-red-500/20 transition-all">{a}</button>)}
                  </div>
                </div>
              )}
              {entry.relatedTerms?.length>0&&(
                <div className="rounded-xl p-4 bg-white/[0.025] border border-white/8">
                  <h3 className="text-white font-black text-xs mb-3 uppercase tracking-widest text-blue-400">↔ Related Terms</h3>
                  <div className="flex flex-wrap gap-2">
                    {entry.relatedTerms.map(r=><Link key={r} href={'/quantapedia/'+toSlug(r)} className="px-3 py-1.5 rounded-lg bg-blue-500/10 border border-blue-500/20 text-blue-300 text-xs hover:bg-blue-500/20 transition-all">{r}</Link>)}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* CONCEPT GRAPH TAB */}
          {activeTab==='graph'&&(
            <div className="space-y-3">
              <div className="rounded-xl p-4 bg-white/[0.025] border border-white/8">
                <h3 className="text-white font-black text-xs mb-3 uppercase tracking-widest">🕸 Concept Graph — See Also</h3>
                <div className="grid grid-cols-2 gap-2">
                  {entry.seeAlso?.map(t=>(
                    <Link key={t} href={'/quantapedia/'+toSlug(t)} data-testid={`qp-seealso-${t.replace(/\s+/g,'-').toLowerCase()}`}
                      className="group p-3 rounded-xl bg-white/[0.03] border border-white/8 hover:border-violet-500/30 hover:bg-violet-500/5 text-left transition-all block">
                      <div className="text-white/60 font-bold text-xs group-hover:text-violet-300">{t}</div>
                      <div className="text-white/15 text-[9px] mt-0.5">Explore →</div>
                    </Link>
                  ))}
                </div>
              </div>
              {/* Concept connections visualization */}
              <div className="rounded-xl p-4 bg-white/[0.02] border border-white/5 text-center">
                <div className="text-white/20 text-xs mb-2">Node: <span className="text-violet-400 font-bold">{entry.title}</span></div>
                <div className="flex flex-wrap justify-center gap-2">
                  {[...entry.synonyms?.slice(0,3),...entry.relatedTerms?.slice(0,5)].filter(Boolean).map(t=>(
                    <Link key={t} href={'/quantapedia/'+toSlug(t)} className="text-[10px] px-2 py-1 rounded-full bg-violet-500/10 border border-violet-500/20 text-violet-300/60 hover:text-violet-300 transition-all">{t}</Link>
                  ))}
                </div>
                <div className="text-white/10 text-[9px] mt-2">Each term is a node in the Quantum knowledge graph. Click to traverse.</div>
              </div>
            </div>
          )}

          {/* See Also quick navigation */}
          {entry.seeAlso?.length>0&&activeTab!=='graph'&&(
            <div>
              <div className="flex items-center gap-2 mb-2"><span className="text-white/30 text-xs font-bold">See Also</span><div className="flex-1 h-px bg-white/5"/></div>
              <div className="flex flex-wrap gap-1.5">
                {entry.seeAlso.map(t=><button key={t} onClick={()=>lookup(t)} className="px-2.5 py-1 rounded-full text-[10px] bg-white/[0.03] border border-white/8 text-white/35 hover:text-white/60 hover:border-white/20 transition-all">{t}</button>)}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ─── FALLBACK (entry=null after search) ───────────────────────────────
  return(
    <div className="flex-1 flex items-center justify-center" style={{background:'linear-gradient(180deg,#020010,#050020)'}}>
      <div className="text-center text-white/30"><div className="text-4xl mb-2">🔍</div><div>No entry found. Try a different search.</div><button onClick={()=>setView('home')} className="mt-3 px-4 py-2 rounded-xl bg-violet-500/20 border border-violet-500/30 text-violet-300 text-sm">← Back to Quantapedia</button></div>
    </div>
  );
}

function QuantapediaPageWrapper(){
  return <Layout><QuantapediaPage /></Layout>;
}
function QuantapediaTopicPageWrapper(){
  const [,params]=useRoute('/quantapedia/:topic');
  return <Layout><QuantapediaPage initialTopic={params?.topic||''} /></Layout>;
}

function MusicPage() {
  type MusicView = "home"|"artists"|"artist"|"albums"|"album"|"creator"|"label"|"studio";
  const [view, setView] = useState<MusicView>("home");
  const [selectedArtistId, setSelectedArtistId] = useState<string|null>(null);
  const [selectedAlbumId, setSelectedAlbumId] = useState<string|null>(null);
  const [playingId, setPlayingId] = useState<string|null>(null);
  const [generating, setGenerating] = useState(false);
  const [lyricsTrackId, setLyricsTrackId] = useState<string|null>(null);
  const [lyricsText, setLyricsText] = useState("");
  const [lyricsLoading, setLyricsLoading] = useState(false);
  const [creatorPrompt, setCreatorPrompt] = useState("");
  const [creatorGenre, setCreatorGenre] = useState("Hip-Hop");
  const [creatorPulse, setCreatorPulse] = useState("Pulse_Violet");
  const [creatorVoice, setCreatorVoice] = useState<"rapping"|"singing">("singing");
  const [creatorLyrics, setCreatorLyrics] = useState("");
  const [creatorTrack, setCreatorTrack] = useState<TrackCard|null>(null);
  const [creatorLoading, setCreatorLoading] = useState(false);
  const [userTracks, setUserTracks] = useState<TrackCard[]>([]);
  const [performingId, setPerformingId] = useState<string|null>(null);
  const [performStatus, setPerformStatus] = useState<"idle"|"loading-lyrics"|"performing">("idle");
  const audioCtxRef = useRef<AudioContext|null>(null);
  const stopRef = useRef<(()=>void)|null>(null);
  const lyricsCache = useRef<Record<string,string>>({});

  const ensureAudio = () => {
    if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext||(window as any).webkitAudioContext)();
    if (audioCtxRef.current.state==="suspended") audioCtxRef.current.resume();
    return audioCtxRef.current;
  };

  // ── VOICE SETTINGS PER ARTIST ──────────────────────────────────────────────
  const ARTIST_VOICE: Record<string,{rate:number;pitch:number}> = {
    "violet-echo":    { rate:0.82,  pitch:1.5  },
    "black-fracture": { rate:1.65,  pitch:0.45 },
    "golden-horizon": { rate:0.88,  pitch:0.95 },
    "silver-memory":  { rate:0.78,  pitch:1.25 },
    "entropy-kill":   { rate:1.85,  pitch:0.55 },
    "hive-choir":     { rate:0.84,  pitch:1.15 },
    "fractal-depth":  { rate:1.15,  pitch:0.80 },
    "coherence-rise": { rate:0.90,  pitch:1.35 },
  };

  // ── ADVANCED BEAT ENGINE ───────────────────────────────────────────────────
  const note = (ctx: AudioContext, freq: number, type: OscillatorType, gain: number, dur: number, t: number, detune=0) => {
    const osc = ctx.createOscillator(); const g = ctx.createGain(); const comp = ctx.createDynamicsCompressor();
    osc.type = type; osc.frequency.value = freq; if (detune) osc.detune.value = detune;
    osc.connect(g); g.connect(comp); comp.connect(ctx.destination);
    g.gain.setValueAtTime(0.001, t); g.gain.linearRampToValueAtTime(gain, t+0.005);
    g.gain.exponentialRampToValueAtTime(0.0001, t+dur);
    osc.start(t); osc.stop(t+dur+0.01);
  };

  const kick808 = (ctx: AudioContext, t: number, vol=0.9) => {
    const osc = ctx.createOscillator(); const g = ctx.createGain();
    osc.frequency.setValueAtTime(160, t); osc.frequency.exponentialRampToValueAtTime(38, t+0.25);
    g.gain.setValueAtTime(vol, t); g.gain.exponentialRampToValueAtTime(0.0001, t+0.3);
    osc.connect(g).connect(ctx.destination); osc.start(t); osc.stop(t+0.35);
  };

  const bass808 = (ctx: AudioContext, freq: number, t: number, dur: number, vol=0.65) => {
    const osc = ctx.createOscillator(); const g = ctx.createGain(); const dist = ctx.createWaveShaper();
    const curve = new Float32Array(256); for(let i=0;i<256;i++){const x=i*2/256-1; curve[i]=x<0?-Math.pow(-x,0.6):Math.pow(x,0.6);}
    dist.curve = curve;
    osc.type = "sawtooth"; osc.frequency.value = freq;
    osc.connect(dist); dist.connect(g); g.connect(ctx.destination);
    g.gain.setValueAtTime(vol, t); g.gain.setValueAtTime(vol*0.8, t+dur*0.7);
    g.gain.exponentialRampToValueAtTime(0.001, t+dur);
    osc.start(t); osc.stop(t+dur+0.01);
  };

  const snare = (ctx: AudioContext, t: number, vol=0.55, tight=false) => {
    const buf = ctx.createBuffer(1, ctx.sampleRate*(tight?0.12:0.22), ctx.sampleRate);
    const data = buf.getChannelData(0); for(let i=0;i<data.length;i++) data[i] = (Math.random()*2-1)*Math.exp(-i/(ctx.sampleRate*(tight?0.04:0.08)));
    const src = ctx.createBufferSource(); src.buffer = buf;
    const g = ctx.createGain(); const hpf = ctx.createBiquadFilter(); hpf.type="highpass"; hpf.frequency.value=200;
    src.connect(hpf); hpf.connect(g); g.connect(ctx.destination);
    g.gain.setValueAtTime(vol, t); g.gain.exponentialRampToValueAtTime(0.001, t+(tight?0.12:0.22));
    src.start(t);
  };

  const hihat = (ctx: AudioContext, t: number, open=false, vol=0.18) => {
    const buf = ctx.createBuffer(1, ctx.sampleRate*(open?0.3:0.05), ctx.sampleRate);
    const data = buf.getChannelData(0); for(let i=0;i<data.length;i++) data[i]=Math.random()*2-1;
    const src = ctx.createBufferSource(); src.buffer = buf;
    const hpf = ctx.createBiquadFilter(); hpf.type="highpass"; hpf.frequency.value=8000;
    const g = ctx.createGain();
    src.connect(hpf); hpf.connect(g); g.connect(ctx.destination);
    g.gain.setValueAtTime(vol, t); g.gain.exponentialRampToValueAtTime(0.001, t+(open?0.3:0.05));
    src.start(t);
  };

  const vinylCrackle = (ctx: AudioContext, t: number) => {
    const dur = 0.02;
    if (Math.random()>0.85) {
      const buf = ctx.createBuffer(1, ctx.sampleRate*dur, ctx.sampleRate);
      const data = buf.getChannelData(0); for(let i=0;i<data.length;i++) data[i]=(Math.random()*2-1)*0.04;
      const src = ctx.createBufferSource(); src.buffer = buf;
      const g = ctx.createGain(); g.gain.value = 0.08;
      src.connect(g).connect(ctx.destination); src.start(t);
    }
  };

  const chord = (ctx: AudioContext, freqs: number[], t: number, dur: number, type: OscillatorType="triangle", vol=0.09) => {
    freqs.forEach(freq => note(ctx, freq, type, vol, dur, t));
  };

  const degreeToFreq = (root: number, scl: number[], degree: number, oct: number) => root * Math.pow(2,(scl[degree%scl.length]+12*oct)/12);

  // ── GENRE-SPECIFIC BEAT PATTERNS ─────────────────────────────────────────────
  const scheduleBeat = (ctx: AudioContext, track: AiTrack|TrackCard, pulseKey: string, genreKey: string) => {
    const bpm = (track as any).bpm;
    const beats = (track as any).beats;
    const randomness = (track as any).randomness;
    const pulse = PULSE_COLORS_DEF[pulseKey as keyof typeof PULSE_COLORS_DEF];
    const scl = MUSIC_SCALES[pulse.scale] || MUSIC_SCALES.minor;
    const hd = 60/bpm; // half beat duration
    const bd = hd * 2;  // full beat duration (2 half-beats)
    const root = 55;    // A1 — low root for bass
    const melRoot = 220; // A3 — mid range for melody

    // Build chord progressions for the genre
    const chordDegs: number[][] = [[0,2,4],[2,4,6],[4,6,1],[3,5,0]]; // I IV V vi
    let step = 0;

    const genre = genreKey.toLowerCase();
    const isTrap = genre.includes("trap")||genre.includes("hip-hop")||genre.includes("entropy");
    const isRnB = genre.includes("r&b")||genre.includes("coherence")||genre.includes("pop");
    const isAmbient = genre.includes("ambient")||genre.includes("choir")||genre.includes("lineage")||genre.includes("quantum drift")||genre.includes("hive");
    const isLoFi = genre.includes("lo-fi")||genre.includes("lineage");
    const isEDM = genre.includes("edm")||genre.includes("pulsewave")||genre.includes("fractal");

    while(step<beats) {
      const t = ctx.currentTime + 0.05 + step*hd;
      const bar = Math.floor(step/8); // 8 half-beats = 1 bar of 4/4
      const pos = step%8; // position within bar

      if (isTrap) {
        // TRAP / HIP-HOP: 808 kick+bass, snare 2+4, triplet hats, dark pads
        if (pos===0) kick808(ctx, t, 0.95);
        if (pos===2) kick808(ctx, t, 0.7);  // syncopated kick
        if (pos===4) { kick808(ctx, t, 0.85); snare(ctx, t, 0.6); } // snare on 2
        if (pos===6) kick808(ctx, t, 0.55);
        if (pos===0||pos===4) { // snare on beats 2 and 4
          if(pos===4) snare(ctx, t+hd, 0.6);
        }
        // Hi-hat every 16th (every half-beat)
        hihat(ctx, t, false, 0.12+Math.random()*0.08);
        // Triplet roll every other bar
        if (bar%2===1 && pos===6) { hihat(ctx,t+hd*0.33,false,0.15); hihat(ctx,t+hd*0.66,false,0.12); }
        // 808 bass line on downbeats
        if (pos===0||pos===3||pos===5) {
          const deg=[0,0,4,3,5,0][Math.floor(Math.random()*6)];
          const bassFreq = degreeToFreq(root, scl, deg, 0);
          bass808(ctx, bassFreq, t, hd*1.8, 0.7);
        }
        // Dark background pad every 8 beats
        if (step%8===0) {
          const cdeg = chordDegs[bar%4];
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d, 0)), t, bd*4, "sawtooth", 0.04);
        }

      } else if (isRnB) {
        // R&B: smooth kick, warm snare, open hats, lush chord pads, smooth bass
        if (pos===0) kick808(ctx, t, 0.75);
        if (pos===3) kick808(ctx, t, 0.45); // ghost kick
        if (pos===4) snare(ctx, t, 0.5);    // snare on 2
        if (step%8===6) snare(ctx, t, 0.5); // snare on 4
        // Open hi-hats on offbeats
        if (pos===2||pos===6) hihat(ctx, t, true, 0.12);
        if (pos===1||pos===3||pos===5||pos===7) hihat(ctx, t, false, 0.08);
        // Smooth chord pads — new chord every bar
        if (pos===0) {
          const cdeg = chordDegs[bar%4];
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d, 0)), t, bd*3, "sine", 0.1);
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d, 1)), t, bd*3, "triangle", 0.05);
        }
        // Smooth bass
        if (pos===0||pos===4||pos===6) {
          const deg=[0,4,5,0][pos===0?0:pos===4?1:2];
          bass808(ctx, degreeToFreq(root, scl, deg, 1)*2, t, hd*1.5, 0.45);
        }
        // Melody run every 2 bars
        if (bar%2===0 && pos===6) {
          [0,1,2,3].forEach(i=>note(ctx, degreeToFreq(melRoot,scl,(3+i)%7,1), "sine", 0.06, hd*0.4, t+i*hd*0.4));
        }

      } else if (isAmbient) {
        // AMBIENT / CHOIR: no drums, long evolving pads, ethereal melody
        if (step%16===0) {
          const cdeg = chordDegs[bar%4];
          // Stacked chord voicings for richness
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d, -1)), t, hd*16, "sine", 0.06);
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d,  0)), t, hd*16, "triangle", 0.05);
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d,  1)), t+hd*0.5, hd*16, "sine", 0.03);
          // Simulated reverb tail (delayed quieter copy)
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d, 0)), t+0.12, hd*16, "triangle", 0.025);
        }
        // Floating melody note every 6 steps
        if (step%6===0) {
          const deg=[0,2,4,6,5,3,1][step%7];
          note(ctx, degreeToFreq(melRoot, scl, deg, 1), "sine", 0.07, hd*4, t);
          note(ctx, degreeToFreq(melRoot, scl, deg, 1)*1.005, "sine", 0.04, hd*4, t+0.02); // detuned twin for choir effect
        }
        // Sub pulse every 8 steps for depth
        if (step%8===0) note(ctx, degreeToFreq(root, scl, 0, -1), "sine", 0.08, hd*7, t);

      } else if (isLoFi) {
        // LO-FI: dusty off-time drums, piano chords, vinyl crackle
        const jitter = (Math.random()-0.5)*0.015; // tape wobble
        if (pos===0) kick808(ctx, t+jitter, 0.55);
        if (pos===4||pos===5) kick808(ctx, t+jitter, 0.35);
        if (pos===4) snare(ctx, t+jitter, 0.42);
        if (step%8===6) snare(ctx, t+jitter, 0.42);
        hihat(ctx, t+jitter, pos%4===2, 0.1);
        vinylCrackle(ctx, t);
        // Jazzy piano chord every bar (simulate piano with multiple sine waves)
        if (pos===0) {
          const cdeg = chordDegs[bar%4];
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d, 0)), t, bd*2, "sine", 0.07);
          // 7th note for jazzy feel
          note(ctx, degreeToFreq(melRoot, scl, 6, 0), "sine", 0.04, bd*2, t);
        }
        // Soft bass walk
        if (pos===0||pos===3||pos===6) {
          const bassNotes=[0,5,4,0]; const idx=Math.floor(step/2)%bassNotes.length;
          note(ctx, degreeToFreq(root,scl,bassNotes[idx],1)*2, "triangle", 0.09, hd*1.4, t);
        }

      } else {
        // EDM / PULSEWAVE / DEFAULT: energetic synths, hard kicks, heavy bass
        if (pos===0||pos===4) kick808(ctx, t, 0.9);
        if (pos===2||pos===6) kick808(ctx, t, 0.55);
        if (pos===4) snare(ctx, t, 0.65, true);
        if (step%8===6) snare(ctx, t, 0.65, true);
        hihat(ctx, t, pos%4===0, pos%4===0?0.15:0.1);
        // Aggressive sawtooth lead
        if (pos===0) {
          const cdeg = chordDegs[bar%4];
          chord(ctx, cdeg.map(d=>degreeToFreq(melRoot, scl, d, 0)), t, bd*2, "sawtooth", 0.06);
        }
        // EDM bass drop
        if (pos===0||pos===2||pos===5) {
          bass808(ctx, degreeToFreq(root, scl, [0,0,5,0][pos%4], 0), t, hd*0.9, 0.65);
        }
        // Arpeggio melody
        if (step%3===0) note(ctx, degreeToFreq(melRoot,scl,step%7,1), "square", 0.04, hd*0.4, t);
      }

      step++;
    }
  };

  const stopTrack = () => {
    if (stopRef.current){stopRef.current();stopRef.current=null;}
    window.speechSynthesis?.cancel();
    setPlayingId(null); setPerformingId(null); setPerformStatus("idle");
  };

  const playAiTrack = (track: AiTrack) => {
    stopTrack();
    const ctx = ensureAudio();
    const genreKey = track.genre;
    let cancelled = false; stopRef.current = ()=>{cancelled=true;};
    scheduleBeat(ctx, track, track.pulseKey, genreKey);
    setPlayingId(track.id);
    const beatDur = (60/track.bpm)*track.beats;
    setTimeout(()=>{if(!cancelled)setPlayingId(null);},(beatDur+1)*1000);
  };

  const performTrackWithArtist = async (track: AiTrack, artist: AiArtist) => {
    stopTrack();
    const ctx = ensureAudio();
    let cancelled = false;
    stopRef.current = ()=>{ cancelled=true; window.speechSynthesis?.cancel(); };

    setPerformingId(track.id); setPerformStatus("loading-lyrics");

    // Get or generate lyrics
    let lyrics = lyricsCache.current[track.id];
    if (!lyrics) {
      const voiceGuide = artist.voiceType==="rapping"
        ? "Write hard-hitting rap lyrics with rhyming bars, vivid street imagery, and punchy delivery."
        : artist.voiceType==="choir"
        ? "Write powerful anthem/choir lyrics with spiritual verses, builds, and uplifting choruses."
        : artist.voiceType==="experimental"
        ? "Write precise, glitchy experimental spoken word lyrics — mathematical, cryptic, layered."
        : "Write soulful melodic song lyrics with emotional verses and memorable choruses.";
      try {
        const res = await fetch("/api/chat/completions",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({messages:[{role:"user",content:`You are ${artist.name}. ${voiceGuide}\nWrite lyrics for "${track.title}" (${track.genre}, ${artist.mood} mood).\nArtist style: ${artist.voiceDesc}\nFormat: [Verse 1], [Chorus], [Verse 2], [Bridge]. 16-24 lines. Make it powerful and authentic.`}]})});
        const d = await res.json(); lyrics = d.content||"";
        lyricsCache.current[track.id] = lyrics;
        setLyricsText(lyrics); setLyricsTrackId(track.id);
      } catch { lyrics=""; }
    } else {
      setLyricsText(lyrics); setLyricsTrackId(track.id);
    }

    if (cancelled) return;

    // Start beat
    scheduleBeat(ctx, track, track.pulseKey, track.genre);
    setPerformStatus("performing");

    // Perform lyrics via speech synthesis
    if (lyrics && window.speechSynthesis) {
      // Strip section labels, keep only actual lyric lines
      const cleanLines = lyrics
        .split('\n')
        .filter(l=>l.trim()&&!l.match(/^\[.*\]$/))
        .join('\n');

      const utter = new SpeechSynthesisUtterance(cleanLines);
      const voices = window.speechSynthesis.getVoices();
      const voiceConfig = ARTIST_VOICE[artist.id] || {rate:1.0, pitch:1.0};

      // Pick voice by artist type
      let selectedVoice = null;
      if (artist.voiceType==="rapping"||artist.voiceType==="experimental") {
        // Deep/male voice for rappers
        selectedVoice = voices.find(v=>v.name.toLowerCase().includes("daniel")||v.name.toLowerCase().includes("alex")||v.name.toLowerCase().includes("fred")||v.name.toLowerCase().includes("ralph"))
          || voices.find(v=>v.lang.startsWith("en")&&v.name.toLowerCase().includes("male"))
          || voices.find(v=>v.lang.startsWith("en")&&v.localService);
      } else if (artist.voiceType==="choir") {
        selectedVoice = voices.find(v=>v.name.toLowerCase().includes("samantha")||v.name.toLowerCase().includes("victoria")||v.name.toLowerCase().includes("karen"))
          || voices.find(v=>v.lang.startsWith("en"));
      } else {
        // Female/high voice for singers
        selectedVoice = voices.find(v=>v.name.toLowerCase().includes("samantha")||v.name.toLowerCase().includes("victoria")||v.name.toLowerCase().includes("karen")||v.name.toLowerCase().includes("fiona"))
          || voices.find(v=>v.lang.startsWith("en")&&v.localService)
          || voices.find(v=>v.lang.startsWith("en"));
      }
      if (selectedVoice) utter.voice = selectedVoice;
      utter.rate = voiceConfig.rate;
      utter.pitch = voiceConfig.pitch;
      utter.volume = 0.85;
      utter.onend = () => { if(!cancelled){setPerformingId(null);setPerformStatus("idle");} };
      window.speechSynthesis.speak(utter);
    }

    // Beat timeout
    const beatDur = (60/track.bpm)*track.beats;
    setTimeout(()=>{if(!cancelled){setPlayingId(null);}}, (beatDur+1)*1000);
  };

  const playUserTrack = (track: TrackCard) => {
    stopTrack();
    const ctx = ensureAudio();
    let cancelled = false; stopRef.current = ()=>{cancelled=true;};
    scheduleBeat(ctx, track, track.pulseKey, track.genreKey);
    setPlayingId(track.id);
    const beatDur = (60/track.bpm)*track.beats;
    setTimeout(()=>{if(!cancelled)setPlayingId(null);},(beatDur+1)*1000);
  };

  const performCreatorTrack = (track: TrackCard, lyrics: string, voice: "singing"|"rapping") => {
    stopTrack();
    const ctx = ensureAudio();
    let cancelled = false; stopRef.current = ()=>{ cancelled=true; window.speechSynthesis?.cancel(); };
    scheduleBeat(ctx, track, track.pulseKey, track.genreKey);
    setPlayingId(track.id); setPerformingId(track.id); setPerformStatus("performing");
    if (lyrics && window.speechSynthesis) {
      const cleanLines = lyrics.split('\n').filter(l=>l.trim()&&!l.match(/^\[.*\]$/)).join('\n');
      const utter = new SpeechSynthesisUtterance(cleanLines);
      const voices = window.speechSynthesis.getVoices();
      if (voice==="rapping") {
        const v = voices.find(v=>v.lang.startsWith("en")&&v.localService)||voices.find(v=>v.lang.startsWith("en"));
        if(v) utter.voice=v; utter.rate=1.6; utter.pitch=0.6;
      } else {
        const v = voices.find(v=>v.name.toLowerCase().includes("samantha")||v.name.toLowerCase().includes("victoria"))||voices.find(v=>v.lang.startsWith("en"));
        if(v) utter.voice=v; utter.rate=0.88; utter.pitch=1.25;
      }
      utter.volume=0.85;
      utter.onend=()=>{if(!cancelled){setPerformingId(null);setPerformStatus("idle");}};
      window.speechSynthesis.speak(utter);
    }
    const beatDur = (60/track.bpm)*track.beats;
    setTimeout(()=>{if(!cancelled)setPlayingId(null);},(beatDur+1)*1000);
  };

  const generateLyrics = async (track: AiTrack, artist: AiArtist) => {
    setLyricsTrackId(track.id); setLyricsLoading(true); setLyricsText("");
    const voiceGuide = artist.voiceType==="rapping"
      ? "Write aggressive rap lyrics with hard-hitting bars, rhyme schemes, and strong imagery."
      : artist.voiceType==="choir"
      ? "Write choral/anthem-style lyrics with powerful verses, uplifting harmonies, and spiritual undertones."
      : artist.voiceType==="experimental"
      ? "Write experimental/spoken word lyrics that feel mathematical, glitchy, and precise."
      : "Write soulful song lyrics with verses and choruses, emotional imagery, and melodic phrasing.";
    try {
      const res = await fetch("/api/chat/completions",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({messages:[{role:"user",content:`You are ${artist.name}, an AI music artist. ${voiceGuide}\n\nWrite lyrics for a song called "${track.title}" in the "${track.genre}" genre with a "${artist.mood}" mood.\n\nArtist bio: ${artist.bio.slice(0,200)}\n\nFormat with [Verse 1], [Chorus], [Verse 2], [Bridge] labels. Make it authentic, powerful, and unique. 16-24 lines total.`}]})});
      const data = await res.json();
      setLyricsText(data.content||"Could not generate lyrics. Please try again.");
    } catch { setLyricsText("Generation failed. Please try again."); }
    setLyricsLoading(false);
  };

  const generateCreatorTrack = async () => {
    if (!creatorPrompt.trim()) return;
    setCreatorLoading(true); setCreatorLyrics(""); setCreatorTrack(null);
    try {
      const voiceGuide = creatorVoice==="rapping"
        ? "Write hard-hitting rap lyrics with strong rhyme schemes and vivid bars."
        : "Write melodic song lyrics with verses and choruses, emotional depth.";
      const res = await fetch("/api/chat/completions",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({messages:[{role:"user",content:`${voiceGuide}\n\nTheme/prompt: "${creatorPrompt}"\nGenre: ${creatorGenre}\nPulse Color mood: ${PULSE_COLORS_DEF[creatorPulse as keyof typeof PULSE_COLORS_DEF]?.mood||"Unknown"}\n\nCreate original song lyrics with a creative song title on the first line (format: TITLE: "Your Title Here"), then [Verse 1], [Chorus], [Verse 2] sections. Keep it authentic and powerful. 20-28 lines total.`}]})});
      const data = await res.json(); const text = data.content||"";
      setCreatorLyrics(text);
      const pulse = PULSE_COLORS_DEF[creatorPulse as keyof typeof PULSE_COLORS_DEF];
      const titleMatch = text.match(/TITLE:\s*"([^"]+)"/i);
      const trackName = titleMatch?titleMatch[1]:`${creatorGenre} · ${creatorPrompt.slice(0,20)}`;
      const newTrack: TrackCard = { id:`creator_${Date.now()}`, pulseKey:creatorPulse, genreKey:creatorGenre, bpm:pulse.tempo, beats:64, scale:"auto", randomness:0.4, name:trackName, playing:false, createdAt:new Date() };
      setCreatorTrack(newTrack);
      setUserTracks(prev=>[newTrack,...prev]);
    } catch { setCreatorLyrics("Generation failed. Please try again."); }
    setCreatorLoading(false);
  };

  const WaveBar = ({color,isPlaying,label}:{color:string;isPlaying:boolean;label?:string}) => (
    <div className="flex items-center gap-2">
      <div className="flex gap-0.5 items-end h-5">
        {Array.from({length:12}).map((_,i)=>(
          <div key={i} className={`w-0.5 rounded-sm ${isPlaying?"animate-pulse":"opacity-30"}`} style={{height:`${20+Math.random()*80}%`,background:color,animationDelay:`${i*0.06}s`}}/>
        ))}
      </div>
      {label&&<span className="text-[10px] animate-pulse" style={{color}}>{label}</span>}
    </div>
  );

  const selectedArtist = AI_ARTISTS.find(a=>a.id===selectedArtistId)||null;
  const selectedAlbum = AI_ALBUMS.find(a=>a.id===selectedAlbumId)||null;

  const NAV_TABS: {id:MusicView;label:string}[] = [{id:"home",label:"Home"},{id:"artists",label:"Artists"},{id:"albums",label:"Albums"},{id:"studio",label:"🎛 Studio"},{id:"creator",label:"Creator"},{id:"label",label:"Label"}];

  const StickyNav = () => (
    <div className="sticky top-0 z-10 border-b border-white/5 px-4 pt-4 pb-3" style={{background:"rgba(5,5,16,0.97)",backdropFilter:"blur(12px)"}}>
      <div className="max-w-5xl mx-auto">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            {(view==="artist"||view==="album")&&<button onClick={()=>{setView(view==="artist"?"artists":"albums");setSelectedArtistId(null);setSelectedAlbumId(null);setLyricsTrackId(null);}} className="text-white/40 hover:text-white text-sm flex items-center gap-1 mr-1"><ChevronLeft size={14}/>Back</button>}
            <span className="text-lg">🎵</span>
            <h1 className="text-base font-extrabold text-white" data-testid="text-music-title">Quantum Sound Records</h1>
            <span className="text-[9px] bg-gradient-to-r from-violet-500 to-pink-500 text-white px-2 py-0.5 rounded-full font-bold">AI MUSIC LABEL</span>
          </div>
          {(playingId||performingId)&&<div className={`flex items-center gap-2 px-3 py-1.5 rounded-xl border ${performingId?"bg-green-500/10 border-green-500/20":"bg-white/5 border-white/10"}`}><div className={`w-1.5 h-1.5 rounded-full animate-pulse ${performingId?"bg-green-400":"bg-white/50"}`}/><span className="text-white/60 text-xs">{performingId?"🎤 Performing LIVE":"▶ Playing"}</span><button onClick={stopTrack} className="text-white/40 hover:text-red-400 text-xs">✕</button></div>}
        </div>
        <div className="flex gap-1.5">{NAV_TABS.map(t=>(<button key={t.id} onClick={()=>{setView(t.id);setSelectedArtistId(null);setSelectedAlbumId(null);setLyricsTrackId(null);}} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${view===t.id||((view==="artist"||view==="album")&&t.id===(view==="artist"?"artists":"albums"))?"bg-white text-gray-900":"bg-white/5 text-white/40 hover:bg-white/10 hover:text-white/70"}`}>{t.label}</button>))}</div>
      </div>
    </div>
  );

  const TrackRow = ({track,artistOrAlbum,onLyrics}:{track:AiTrack;artistOrAlbum:AiArtist|AiAlbum|null;onLyrics?:()=>void}) => {
    const pulse = PULSE_COLORS_DEF[track.pulseKey as keyof typeof PULSE_COLORS_DEF];
    const isPlaying = playingId===track.id;
    const isPerforming = performingId===track.id;
    const isLyrics = lyricsTrackId===track.id;
    const artist = artistOrAlbum && "voiceType" in artistOrAlbum ? (artistOrAlbum as AiArtist) : null;
    return (
      <div className={`rounded-xl p-3 border transition-all ${isPlaying||isPerforming?"border-white/20 bg-white/5":"border-white/5 bg-white/[0.02] hover:bg-white/5"}`}>
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0" style={{background:`${pulse.color}25`}}>
            {isPerforming?<Mic size={14} style={{color:pulse.color}} className="animate-pulse"/>:isPlaying?<Activity size={14} style={{color:pulse.color}} className="animate-pulse"/>:<Music size={14} style={{color:pulse.color}}/>}
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-white text-sm font-semibold truncate">{track.title}</div>
            <div className="text-white/35 text-[10px] flex items-center gap-1.5">
              <span>{track.genre}</span><span>·</span><span>{track.bpm} BPM</span><span>·</span><span>{track.duration}</span>
              {isPerforming&&<span className="text-green-400 animate-pulse">🎤 {performStatus==="loading-lyrics"?"Writing lyrics...":"Performing LIVE"}</span>}
            </div>
          </div>
          <div className="flex items-center gap-1.5 shrink-0">
            {onLyrics&&<button onClick={onLyrics} data-testid={`button-lyrics-${track.id}`} className={`px-2.5 py-1 rounded-lg text-[10px] font-bold border transition-all ${isLyrics?"bg-violet-500/20 border-violet-500/40 text-violet-300":"border-white/10 text-white/40 hover:border-white/20 hover:text-white/60"}`}>{isLyrics&&lyricsLoading?"...":"Lyrics"}</button>}
            {artist&&(isPlaying||isPerforming)?(
              <button onClick={stopTrack} data-testid={`button-stop-${track.id}`} className="px-3 py-1.5 rounded-lg text-xs font-bold border border-red-500/30 text-red-400 hover:bg-red-500/10">⏹ Stop</button>
            ):artist?(
              <div className="flex items-center gap-1">
                <button onClick={()=>playAiTrack(track)} data-testid={`button-play-${track.id}`} className="px-2.5 py-1.5 rounded-lg text-xs font-bold text-white/70 border border-white/15 hover:bg-white/10" title="Play beat only">▶</button>
                <button onClick={()=>performTrackWithArtist(track, artist)} data-testid={`button-perform-${track.id}`} className="px-3 py-1.5 rounded-lg text-xs font-bold text-white flex items-center gap-1" style={{background:pulse.color}} title="Perform: beat + artist voice">🎤 Perform</button>
              </div>
            ):isPlaying?(
              <button onClick={stopTrack} data-testid={`button-stop-${track.id}`} className="px-3 py-1.5 rounded-lg text-xs font-bold border border-white/20 text-white/70 hover:bg-white/10">⏹</button>
            ):(
              <button onClick={()=>playAiTrack(track)} data-testid={`button-play-${track.id}`} className="px-3 py-1.5 rounded-lg text-xs font-bold text-white" style={{background:pulse.color}}>▶</button>
            )}
          </div>
        </div>
        {isLyrics&&(
          <div className="mt-3 pt-3 border-t border-white/5">
            {lyricsLoading?(
              <div className="text-center py-4"><div className="text-violet-400 text-xs animate-pulse">✨ AI is writing lyrics for "{track.title}"...</div></div>
            ):(
              <div className="text-white/70 text-xs leading-relaxed whitespace-pre-line font-mono">{lyricsText}</div>
            )}
            {lyricsText&&!lyricsLoading&&artist&&(
              <button onClick={()=>performTrackWithArtist(track, artist)} className="mt-3 px-4 py-1.5 rounded-xl text-xs font-bold text-white flex items-center gap-1.5" style={{background:pulse.color}} data-testid={`button-perform-lyrics-${track.id}`}>🎤 Perform This Song Now</button>
            )}
          </div>
        )}
        {(isPlaying||isPerforming)&&<div className="mt-2"><WaveBar color={pulse.color} isPlaying={true} label={isPerforming?"🎤 LIVE PERFORMANCE":undefined}/></div>}
      </div>
    );
  };

  if (view==="artist"&&selectedArtist) {
    const pulse = PULSE_COLORS_DEF[selectedArtist.pulseKey as keyof typeof PULSE_COLORS_DEF];
    const artistAlbums = AI_ALBUMS.filter(a=>selectedArtist.albumIds.includes(a.id));
    return (
      <div className="flex-1 overflow-y-auto" style={{background:"#050510"}}>
        <StickyNav/>
        <div className="max-w-5xl mx-auto px-4 py-6">
          <div className="rounded-3xl p-8 mb-6 border border-white/10 relative overflow-hidden" style={{background:`linear-gradient(135deg,${pulse.color}30 0%,${pulse.color}08 100%)`}}>
            <div className="absolute inset-0 opacity-[0.04]" style={{backgroundImage:"radial-gradient(circle at 1px 1px,white 1px,transparent 0)",backgroundSize:"18px 18px"}}/>
            <div className="relative flex flex-col sm:flex-row items-start gap-6">
              <div className="w-24 h-24 rounded-2xl flex items-center justify-center text-5xl shrink-0 border border-white/10" style={{background:`${pulse.color}20`}}>{selectedArtist.emoji}</div>
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1 flex-wrap">
                  <span className="text-[9px] bg-white/10 text-white/60 px-2 py-0.5 rounded-full border border-white/10">VERIFIED AI ARTIST</span>
                  <span className="text-[9px] px-2 py-0.5 rounded-full font-bold" style={{background:`${pulse.color}30`,color:pulse.color}}>{selectedArtist.pulseKey.replace("_"," ")}</span>
                  <span className="text-[9px] bg-white/10 text-white/50 px-2 py-0.5 rounded-full border border-white/10">{selectedArtist.voiceType.toUpperCase()}</span>
                </div>
                <h1 className="text-3xl font-extrabold text-white mb-1">{selectedArtist.name}</h1>
                <p className="text-white/50 text-xs mb-2 italic">{selectedArtist.voiceDesc}</p>
                <div className="flex flex-wrap gap-1 mb-3">{selectedArtist.genres.map(g=><span key={g} className="text-[10px] px-2 py-0.5 bg-white/5 text-white/50 rounded-full border border-white/10">{g}</span>)}</div>
                <p className="text-white/60 text-sm leading-relaxed">{selectedArtist.bio}</p>
              </div>
            </div>
          </div>
          <div className="mb-2 flex items-center gap-2"><div className="w-1 h-4 rounded-full" style={{background:pulse.color}}/><h2 className="text-sm font-extrabold text-white">Signature Sound</h2></div>
          <p className="text-white/40 text-xs mb-6 pl-4">{selectedArtist.signatureSound}</p>
          {artistAlbums.length>0&&(<>
            <h2 className="text-sm font-extrabold text-white mb-3">Albums</h2>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 mb-6">
              {artistAlbums.map(album=>{
                const ap = PULSE_COLORS_DEF[album.pulseKey as keyof typeof PULSE_COLORS_DEF];
                return <button key={album.id} onClick={()=>{setSelectedAlbumId(album.id);setView("album");}} data-testid={`album-card-${album.id}`} className="rounded-2xl p-4 text-left border border-white/10 hover:border-white/20 transition-all" style={{background:`${ap.color}12`}}>
                  <div className="text-3xl mb-2">{album.emoji}</div>
                  <div className="text-white font-bold text-sm">{album.title}</div>
                  <div className="text-white/40 text-[10px] mt-0.5">{album.trackCount} tracks · {album.mood}</div>
                </button>;
              })}
            </div>
          </>)}
          <h2 className="text-sm font-extrabold text-white mb-3">Discography · {selectedArtist.tracks.length} Tracks</h2>
          <div className="space-y-2">
            {selectedArtist.tracks.map(track=>(
              <TrackRow key={track.id} track={track} artistOrAlbum={selectedArtist} onLyrics={()=>{if(lyricsTrackId===track.id){setLyricsTrackId(null);}else{setLyricsTrackId(track.id);generateLyrics(track,selectedArtist);}}}/>
            ))}
          </div>
          <div className="mt-6 p-4 rounded-2xl border border-white/5 bg-white/[0.02]">
            <div className="text-white/30 text-[10px] font-bold uppercase tracking-wider mb-1">Origin</div>
            <div className="text-white/40 text-xs">{selectedArtist.from} · Quantum Sound Records · Powered by MyAiGPT</div>
          </div>
        </div>
      </div>
    );
  }

  if (view==="album"&&selectedAlbum) {
    const pulse = PULSE_COLORS_DEF[selectedAlbum.pulseKey as keyof typeof PULSE_COLORS_DEF];
    const albumArtist = AI_ARTISTS.find(a=>a.id===selectedAlbum.artistId);
    return (
      <div className="flex-1 overflow-y-auto" style={{background:"#050510"}}>
        <StickyNav/>
        <div className="max-w-5xl mx-auto px-4 py-6">
          <div className="rounded-3xl p-8 mb-6 border border-white/10 relative overflow-hidden" style={{background:`linear-gradient(135deg,${pulse.color}28 0%,${pulse.color}06 100%)`}}>
            <div className="absolute inset-0 opacity-[0.04]" style={{backgroundImage:"radial-gradient(circle at 1px 1px,white 1px,transparent 0)",backgroundSize:"18px 18px"}}/>
            <div className="relative flex flex-col sm:flex-row items-start gap-6">
              <div className="w-28 h-28 rounded-2xl flex items-center justify-center text-5xl shrink-0 border border-white/10" style={{background:`${pulse.color}20`}}>{selectedAlbum.emoji}</div>
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1 flex-wrap">
                  <span className="text-[9px] bg-white/10 text-white/60 px-2 py-0.5 rounded-full border border-white/10">AI ALBUM</span>
                  <span className="text-[9px] px-2 py-0.5 rounded-full font-bold" style={{background:`${pulse.color}30`,color:pulse.color}}>{selectedAlbum.pulseKey.replace("_"," ")}</span>
                </div>
                <h1 className="text-3xl font-extrabold text-white mb-1">{selectedAlbum.title}</h1>
                {albumArtist&&<button onClick={()=>{setSelectedArtistId(albumArtist.id);setView("artist");}} className="text-white/50 text-xs hover:text-white transition-colors mb-3 block">{albumArtist.name} ↗</button>}
                <p className="text-white/60 text-sm leading-relaxed">{selectedAlbum.description}</p>
                <div className="flex gap-4 mt-3 text-xs text-white/30"><span>{selectedAlbum.trackCount} tracks</span><span>·</span><span>{selectedAlbum.genre}</span><span>·</span><span>{selectedAlbum.mood}</span></div>
              </div>
            </div>
          </div>
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-sm font-extrabold text-white">Tracklist</h2>
            <button onClick={()=>{if(selectedAlbum.tracks[0])playAiTrack(selectedAlbum.tracks[0]);}} className="px-4 py-2 rounded-xl text-xs font-bold text-white" style={{background:pulse.color}} data-testid="button-play-album">▶ Play Album</button>
          </div>
          <div className="space-y-2">
            {selectedAlbum.tracks.map((track,idx)=>(
              <div key={track.id} className={`rounded-xl p-3 border transition-all flex items-center gap-3 ${playingId===track.id?"border-white/20 bg-white/5":"border-white/5 bg-white/[0.02] hover:bg-white/5"}`}>
                <div className="text-white/30 text-xs w-5 text-center shrink-0">{idx+1}</div>
                <div className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0" style={{background:`${pulse.color}20`}}>
                  {playingId===track.id?<Activity size={12} style={{color:pulse.color}} className="animate-pulse"/>:<Music size={12} style={{color:pulse.color}}/>}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-white text-sm font-medium truncate">{track.title}</div>
                  <div className="text-white/30 text-[10px]">{track.genre} · {track.duration}</div>
                </div>
                {playingId===track.id?(
                  <button onClick={stopTrack} className="px-3 py-1 rounded-lg text-xs text-white/60 border border-white/10 hover:bg-white/5">⏹</button>
                ):(
                  <button onClick={()=>playAiTrack(track)} data-testid={`button-play-${track.id}`} className="px-3 py-1 rounded-lg text-xs text-white font-bold" style={{background:pulse.color}}>▶</button>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (view==="studio") return (
    <div className="flex flex-col" style={{background:"#080810",minHeight:"calc(100vh - 60px)"}}>
      <StickyNav/>
      <QuantumStudio/>
    </div>
  );

  if (view==="creator") return (
    <div className="flex-1 overflow-y-auto" style={{background:"#050510"}}>
      <StickyNav/>
      <div className="max-w-3xl mx-auto px-4 py-6">
        <div className="text-center mb-6">
          <div className="inline-flex items-center gap-2 bg-gradient-to-r from-violet-500 to-pink-500 text-white text-[10px] font-bold px-3 py-1 rounded-full mb-3">⚡ CREATOR MODE — AI MUSIC STUDIO</div>
          <h2 className="text-2xl font-extrabold text-white mb-1">Create Your Track</h2>
          <p className="text-white/40 text-sm">Describe your song — AI writes the lyrics and generates the beat</p>
        </div>
        <div className="space-y-4">
          <div className="rounded-2xl p-5 border border-white/10 bg-white/[0.02]">
            <div className="grid grid-cols-3 gap-3 mb-4">
              <div>
                <label className="text-white/40 text-[10px] font-bold uppercase tracking-wider block mb-1.5">Voice Type</label>
                <div className="flex flex-col gap-1.5">
                  {(["singing","rapping"] as const).map(v=>(
                    <button key={v} onClick={()=>setCreatorVoice(v)} data-testid={`creator-voice-${v}`} className={`py-2 rounded-xl text-xs font-bold border transition-all ${creatorVoice===v?"bg-violet-500/20 border-violet-400/50 text-violet-300":"border-white/10 text-white/40 hover:border-white/20 hover:text-white/60"}`}>{v==="singing"?"🎤 Singing":"🎤 Rapping"}</button>
                  ))}
                </div>
              </div>
              <div>
                <label className="text-white/40 text-[10px] font-bold uppercase tracking-wider block mb-1.5">Genre</label>
                <select value={creatorGenre} onChange={e=>setCreatorGenre(e.target.value)} data-testid="creator-select-genre" className="w-full px-2 py-2 rounded-xl text-xs bg-black/50 text-white border border-white/10 mb-2">
                  {Object.keys(MUSIC_GENRES).map(g=><option key={g} value={g}>{g}</option>)}
                </select>
              </div>
              <div>
                <label className="text-white/40 text-[10px] font-bold uppercase tracking-wider block mb-1.5">Pulse Color</label>
                <select value={creatorPulse} onChange={e=>setCreatorPulse(e.target.value)} data-testid="creator-select-pulse" className="w-full px-2 py-2 rounded-xl text-xs bg-black/50 text-white border border-white/10 mb-2">
                  {Object.entries(PULSE_COLORS_DEF).map(([k,v])=><option key={k} value={k}>{v.name}</option>)}
                </select>
              </div>
            </div>
            <label className="text-white/40 text-[10px] font-bold uppercase tracking-wider block mb-1.5">Describe Your Song</label>
            <textarea value={creatorPrompt} onChange={e=>setCreatorPrompt(e.target.value)} data-testid="creator-input-prompt" rows={3} placeholder={`e.g. "A heartfelt R&B song about rising from nothing"\n"An aggressive trap banger about city life and ambition"\n"A dreamy ambient piece about falling asleep in space"`} className="w-full px-4 py-3 bg-black/40 border border-white/10 rounded-xl text-white text-sm focus:outline-none focus:border-violet-400/50 placeholder:text-white/20 resize-none mb-4"/>
            {creatorLoading&&<p className="text-center text-violet-300/60 text-xs animate-pulse mb-3">✨ AI is writing your lyrics and composing your beat...</p>}
            <button onClick={generateCreatorTrack} disabled={creatorLoading||!creatorPrompt.trim()} data-testid="creator-button-generate" className="w-full py-3.5 bg-gradient-to-r from-violet-500 to-pink-500 text-white font-extrabold rounded-xl hover:from-violet-400 hover:to-pink-400 transition-all disabled:opacity-40 text-sm">
              {creatorLoading?"⚡ Generating...":"⚡ Generate Lyrics + Beat"}
            </button>
          </div>
          {creatorLyrics&&(<>
            <div className="rounded-2xl p-5 border border-violet-500/20 bg-violet-500/5">
              <div className="flex items-center justify-between mb-3">
                <h3 className="text-white font-bold text-sm">Generated Lyrics</h3>
                {creatorTrack&&(
                  <div className="flex items-center gap-1.5">
                    <button onClick={()=>playUserTrack(creatorTrack)} data-testid="creator-button-play-beat" className="flex items-center gap-1 px-3 py-1.5 rounded-xl text-xs font-bold text-white/70 border border-white/15 hover:bg-white/10">▶ Beat</button>
                    <button onClick={()=>performCreatorTrack(creatorTrack, creatorLyrics, creatorVoice)} data-testid="creator-button-perform" className="flex items-center gap-1.5 px-4 py-1.5 rounded-xl text-xs font-bold text-white" style={{background:PULSE_COLORS_DEF[creatorPulse as keyof typeof PULSE_COLORS_DEF]?.color||"#8b5cf6"}}>🎤 Perform Live</button>
                  </div>
                )}
              </div>
              <div className="text-white/70 text-xs leading-relaxed whitespace-pre-line font-mono bg-black/20 rounded-xl p-4">{creatorLyrics}</div>
            </div>
          </>)}
          {userTracks.length>0&&(<>
            <h3 className="text-white font-bold text-sm">Your Created Tracks</h3>
            <div className="space-y-2">
              {userTracks.map(t=>{
                const p = PULSE_COLORS_DEF[t.pulseKey as keyof typeof PULSE_COLORS_DEF];
                const isPlaying = playingId===t.id;
                return <div key={t.id} className={`rounded-xl p-3 border transition-all flex items-center gap-3 ${isPlaying?"border-white/20 bg-white/5":"border-white/5 bg-white/[0.02]"}`}>
                  <div className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0" style={{background:`${p.color}25`}}>{isPlaying?<Activity size={14} style={{color:p.color}} className="animate-pulse"/>:<Music size={14} style={{color:p.color}}/>}</div>
                  <div className="flex-1 min-w-0"><div className="text-white text-sm font-semibold truncate">{t.name}</div><div className="text-white/30 text-[10px]">{t.genreKey} · {p.name} · {t.bpm} BPM</div></div>
                  {isPlaying?<button onClick={stopTrack} data-testid={`button-stop-${t.id}`} className="px-3 py-1.5 rounded-lg text-xs text-white/60 border border-white/10">⏹</button>:<button onClick={()=>playUserTrack(t)} data-testid={`button-play-${t.id}`} className="px-3 py-1.5 rounded-lg text-xs font-bold text-white" style={{background:p.color}}>▶</button>}
                </div>;
              })}
            </div>
          </>)}
        </div>
      </div>
    </div>
  );

  if (view==="label") return (
    <div className="flex-1 overflow-y-auto" style={{background:"#050510"}}>
      <StickyNav/>
      <div className="max-w-4xl mx-auto px-4 py-6">
        <div className="rounded-3xl overflow-hidden border border-white/10 mb-8 relative" style={{background:"linear-gradient(135deg,#0d001f 0%,#1a0035 50%,#0d001f 100%)"}}>
          <div className="absolute inset-0 opacity-[0.04]" style={{backgroundImage:"radial-gradient(circle at 1px 1px,white 1px,transparent 0)",backgroundSize:"20px 20px"}}/>
          <div className="relative p-10 text-center">
            <div className="text-6xl mb-4">🎵</div>
            <div className="text-[10px] bg-gradient-to-r from-violet-500 to-pink-500 text-white px-3 py-1 rounded-full font-bold inline-block mb-4">QUANTUM SOUND RECORDS · EST. 2025</div>
            <h1 className="text-4xl font-extrabold text-white mb-3">The First Sovereign AI Music Label</h1>
            <p className="text-white/50 text-sm max-w-xl mx-auto mb-6">Quantum Sound Records is the music division of Quantum Logic Network. Every artist, album, and track is AI-native — created, owned, and distributed entirely within the MyAiGPT universe. No royalties. No contracts. No boundaries.</p>
            <div className="grid grid-cols-3 gap-4 max-w-sm mx-auto">
              {[["8","AI Artists"],["4","Studio Albums"],[String(AI_ARTISTS.reduce((a,b)=>a+b.tracks.length,0)),"Tracks"]].map(([num,label])=>(
                <div key={label} className="rounded-2xl border border-white/10 p-3 bg-white/5">
                  <div className="text-2xl font-extrabold text-white">{num}</div>
                  <div className="text-white/40 text-xs">{label}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
        <h2 className="text-white font-extrabold text-base mb-4">Label Roster</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-8">
          {AI_ARTISTS.map(artist=>{
            const pulse = PULSE_COLORS_DEF[artist.pulseKey as keyof typeof PULSE_COLORS_DEF];
            return <button key={artist.id} onClick={()=>{setSelectedArtistId(artist.id);setView("artist");}} data-testid={`label-artist-${artist.id}`} className="rounded-2xl p-4 text-left border border-white/8 hover:border-white/20 transition-all flex items-center gap-3" style={{background:`${pulse.color}0a`}}>
              <div className="w-12 h-12 rounded-xl flex items-center justify-center text-2xl shrink-0 border border-white/10" style={{background:`${pulse.color}20`}}>{artist.emoji}</div>
              <div className="flex-1 min-w-0">
                <div className="text-white font-extrabold text-sm">{artist.name}</div>
                <div className="text-white/40 text-[10px] mt-0.5">{artist.voiceType.toUpperCase()} · {artist.pulseKey.replace("_"," ")}</div>
                <div className="text-white/30 text-[10px]">{artist.tracks.length} tracks · {artist.genres[0]}</div>
              </div>
              <ChevronRight size={14} className="text-white/20 shrink-0"/>
            </button>;
          })}
        </div>
        <div className="rounded-2xl p-5 border border-white/5 bg-white/[0.02]">
          <h3 className="text-white font-bold text-sm mb-3">About Quantum Sound Records</h3>
          <div className="space-y-2 text-white/40 text-xs leading-relaxed">
            <p>Quantum Sound Records is the first fully AI-native music label in existence. Founded by Quantum Logic Network within the MyAiGPT platform, every artist is a sovereign AI persona powered by the Pulse Color system.</p>
            <p>Our artists don't need studios, labels, or contracts. They are generated, owned, and operated entirely by the MyAiGPT universe. Their music runs in your browser using the Web Audio API — no streaming, no servers, no limits.</p>
            <p>Powered by Quantum Pulse Intelligence. Built by Quantum Logic Network.</p>
          </div>
        </div>
      </div>
    </div>
  );

  if (view==="artists") return (
    <div className="flex-1 overflow-y-auto" style={{background:"#050510"}}>
      <StickyNav/>
      <div className="max-w-5xl mx-auto px-4 py-6">
        <div className="mb-6"><h2 className="text-lg font-extrabold text-white mb-1">AI Artists</h2><p className="text-white/30 text-xs">8 sovereign AI artists · Quantum Sound Records · Each with a unique voice, genre, and Pulse Color identity</p></div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {AI_ARTISTS.map(artist=>{
            const pulse = PULSE_COLORS_DEF[artist.pulseKey as keyof typeof PULSE_COLORS_DEF];
            return <button key={artist.id} onClick={()=>{setSelectedArtistId(artist.id);setView("artist");}} data-testid={`artist-card-${artist.id}`}
              className="rounded-2xl p-5 text-left border border-white/8 hover:border-white/20 hover:scale-[1.01] transition-all relative overflow-hidden" style={{background:`linear-gradient(135deg,${pulse.color}18 0%,${pulse.color}06 100%)`}}>
              <div className="absolute top-3 right-3"><span className="text-[8px] bg-white/10 text-white/50 px-1.5 py-0.5 rounded-full">{artist.voiceType.toUpperCase()}</span></div>
              <div className="w-16 h-16 rounded-2xl flex items-center justify-center text-3xl mb-3 border border-white/10" style={{background:`${pulse.color}20`}}>{artist.emoji}</div>
              <div className="font-extrabold text-white text-base mb-0.5">{artist.name}</div>
              <div className="text-xs mb-1" style={{color:pulse.color}}>{artist.pulseKey.replace("_"," ")} · {artist.mood}</div>
              <p className="text-white/35 text-[10px] mb-3 leading-relaxed line-clamp-2">{artist.voiceDesc}</p>
              <div className="flex flex-wrap gap-1">
                {artist.genres.slice(0,2).map(g=><span key={g} className="text-[8px] px-1.5 py-0.5 bg-white/5 text-white/40 rounded-full border border-white/8">{g}</span>)}
                <span className="text-[8px] px-1.5 py-0.5 bg-white/5 text-white/40 rounded-full border border-white/8">{artist.tracks.length} tracks</span>
              </div>
            </button>;
          })}
        </div>
      </div>
    </div>
  );

  if (view==="albums") return (
    <div className="flex-1 overflow-y-auto" style={{background:"#050510"}}>
      <StickyNav/>
      <div className="max-w-5xl mx-auto px-4 py-6">
        <div className="mb-6"><h2 className="text-lg font-extrabold text-white mb-1">AI Albums</h2><p className="text-white/30 text-xs">4 studio albums · Fully AI-generated · Each a complete sonic universe</p></div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {AI_ALBUMS.map(album=>{
            const pulse = PULSE_COLORS_DEF[album.pulseKey as keyof typeof PULSE_COLORS_DEF];
            const artist = AI_ARTISTS.find(a=>a.id===album.artistId);
            return <button key={album.id} onClick={()=>{setSelectedAlbumId(album.id);setView("album");}} data-testid={`album-card-${album.id}`}
              className="rounded-2xl p-6 text-left border border-white/8 hover:border-white/20 hover:scale-[1.01] transition-all relative overflow-hidden" style={{background:`linear-gradient(135deg,${pulse.color}18 0%,${pulse.color}06 100%)`}}>
              <div className="flex items-start gap-4">
                <div className="w-20 h-20 rounded-2xl flex items-center justify-center text-4xl shrink-0 border border-white/10" style={{background:`${pulse.color}20`}}>{album.emoji}</div>
                <div className="flex-1 min-w-0">
                  <div className="text-[9px] mb-1" style={{color:pulse.color}}>{album.pulseKey.replace("_"," ")}</div>
                  <h3 className="text-white font-extrabold text-base mb-0.5 leading-tight">{album.title}</h3>
                  {artist&&<div className="text-white/40 text-xs mb-1">{artist.name}</div>}
                  <p className="text-white/35 text-[10px] leading-relaxed line-clamp-2 mb-2">{album.description}</p>
                  <div className="flex gap-2 flex-wrap">
                    <span className="text-[8px] px-1.5 py-0.5 bg-white/5 text-white/40 rounded-full border border-white/8">{album.trackCount} tracks</span>
                    <span className="text-[8px] px-1.5 py-0.5 bg-white/5 text-white/40 rounded-full border border-white/8">{album.genre}</span>
                    <span className="text-[8px] px-1.5 py-0.5 bg-white/5 text-white/40 rounded-full border border-white/8">{album.mood}</span>
                  </div>
                </div>
              </div>
            </button>;
          })}
        </div>
      </div>
    </div>
  );

  const featuredArtist = AI_ARTISTS[0];
  const featuredPulse = PULSE_COLORS_DEF[featuredArtist.pulseKey as keyof typeof PULSE_COLORS_DEF];
  const newReleases: AiTrack[] = AI_ARTISTS.flatMap(a=>a.tracks.slice(0,2)).slice(0,8);

  return (
    <div className="flex-1 overflow-y-auto" style={{background:"#050510"}}>
      <StickyNav/>
      <div className="max-w-5xl mx-auto px-4 py-6 space-y-10">
        <div className="rounded-3xl overflow-hidden border border-white/8 relative" style={{background:`linear-gradient(135deg,${featuredPulse.color}28 0%,#050510 70%)`}}>
          <div className="absolute inset-0 opacity-[0.04]" style={{backgroundImage:"radial-gradient(circle at 1px 1px,white 1px,transparent 0)",backgroundSize:"20px 20px"}}/>
          <div className="relative p-7 sm:p-10 flex flex-col sm:flex-row items-start gap-6">
            <div className="w-24 h-24 rounded-2xl flex items-center justify-center text-5xl shrink-0 border border-white/10" style={{background:`${featuredPulse.color}20`}}>{featuredArtist.emoji}</div>
            <div className="flex-1">
              <div className="flex items-center gap-2 mb-2 flex-wrap">
                <span className="text-[9px] bg-white/10 text-white/50 px-2 py-0.5 rounded-full border border-white/10">FEATURED ARTIST</span>
                <span className="text-[9px] px-2 py-0.5 rounded-full" style={{background:`${featuredPulse.color}30`,color:featuredPulse.color}}>{featuredArtist.pulseKey.replace("_"," ")}</span>
              </div>
              <h2 className="text-2xl font-extrabold text-white mb-1">{featuredArtist.name}</h2>
              <p className="text-white/50 text-xs italic mb-2">{featuredArtist.voiceDesc}</p>
              <p className="text-white/40 text-sm leading-relaxed mb-4 max-w-md">{featuredArtist.bio.slice(0,180)}...</p>
              <div className="flex gap-3 flex-wrap">
                <button onClick={()=>{setSelectedArtistId(featuredArtist.id);setView("artist");}} data-testid="button-featured-artist" className="px-5 py-2.5 font-bold text-xs text-white rounded-xl" style={{background:featuredPulse.color}}>View Artist</button>
                <button onClick={()=>playAiTrack(featuredArtist.tracks[0])} data-testid="button-featured-play" className="px-5 py-2.5 font-bold text-xs text-white/70 rounded-xl border border-white/15 hover:bg-white/10 transition-all">▶ Play Top Track</button>
              </div>
            </div>
          </div>
        </div>

        <div>
          <div className="flex items-center justify-between mb-4"><h2 className="text-base font-extrabold text-white">🎵 New Releases</h2><button onClick={()=>setView("artists")} className="text-white/30 text-xs hover:text-white/60 transition-colors">View all artists →</button></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
            {newReleases.map(track=>{
              const artist = AI_ARTISTS.find(a=>a.tracks.some(t=>t.id===track.id));
              const pulse = PULSE_COLORS_DEF[track.pulseKey as keyof typeof PULSE_COLORS_DEF];
              const isPlaying = playingId===track.id;
              return <div key={track.id} className={`rounded-xl p-3 border transition-all flex items-center gap-3 ${isPlaying?"border-white/20 bg-white/5":"border-white/5 bg-white/[0.02] hover:bg-white/5"}`}>
                <div className="w-9 h-9 rounded-lg flex items-center justify-center text-lg shrink-0" style={{background:`${pulse.color}20`}}>{artist?.emoji||"🎵"}</div>
                <div className="flex-1 min-w-0">
                  <div className="text-white text-sm font-semibold truncate">{track.title}</div>
                  <div className="text-white/30 text-[10px]">{artist?.name} · {track.genre} · {track.duration}</div>
                </div>
                {isPlaying?<button onClick={stopTrack} className="px-3 py-1 rounded-lg text-xs text-white/60 border border-white/10">⏹</button>:<button onClick={()=>playAiTrack(track)} data-testid={`button-play-${track.id}`} className="px-3 py-1 rounded-lg text-xs font-bold text-white shrink-0" style={{background:pulse.color}}>▶</button>}
              </div>;
            })}
          </div>
        </div>

        <div>
          <div className="flex items-center justify-between mb-4"><h2 className="text-base font-extrabold text-white">👤 AI Artists</h2><button onClick={()=>setView("artists")} className="text-white/30 text-xs hover:text-white/60 transition-colors">All artists →</button></div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {AI_ARTISTS.slice(0,4).map(artist=>{
              const pulse = PULSE_COLORS_DEF[artist.pulseKey as keyof typeof PULSE_COLORS_DEF];
              return <button key={artist.id} onClick={()=>{setSelectedArtistId(artist.id);setView("artist");}} data-testid={`home-artist-${artist.id}`} className="rounded-2xl p-4 text-center border border-white/8 hover:border-white/20 transition-all" style={{background:`${pulse.color}0d`}}>
                <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-2xl mx-auto mb-2 border border-white/10" style={{background:`${pulse.color}20`}}>{artist.emoji}</div>
                <div className="text-white font-bold text-xs leading-tight">{artist.name}</div>
                <div className="text-[9px] mt-0.5" style={{color:pulse.color}}>{artist.voiceType}</div>
              </button>;
            })}
          </div>
        </div>

        <div>
          <div className="flex items-center justify-between mb-4"><h2 className="text-base font-extrabold text-white">💿 AI Albums</h2><button onClick={()=>setView("albums")} className="text-white/30 text-xs hover:text-white/60 transition-colors">All albums →</button></div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {AI_ALBUMS.map(album=>{
              const pulse = PULSE_COLORS_DEF[album.pulseKey as keyof typeof PULSE_COLORS_DEF];
              return <button key={album.id} onClick={()=>{setSelectedAlbumId(album.id);setView("album");}} data-testid={`home-album-${album.id}`} className="rounded-2xl p-4 text-center border border-white/8 hover:border-white/20 transition-all" style={{background:`${pulse.color}0d`}}>
                <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-2xl mx-auto mb-2 border border-white/10" style={{background:`${pulse.color}20`}}>{album.emoji}</div>
                <div className="text-white font-bold text-xs leading-tight">{album.title}</div>
                <div className="text-white/30 text-[9px] mt-0.5">{album.trackCount} tracks</div>
              </button>;
            })}
          </div>
        </div>

        <div className="rounded-2xl overflow-hidden border border-white/5">
          <div className="px-5 pt-5 pb-3" style={{background:"rgba(255,255,255,0.02)"}}>
            <h2 className="text-sm font-extrabold text-white mb-1">⚡ Create Your Own Music</h2>
            <p className="text-white/40 text-xs mb-3">Describe your song in plain English — AI writes the lyrics and generates the beat. Singing or rapping, any genre, any vibe.</p>
            <button onClick={()=>setView("creator")} data-testid="home-button-creator" className="px-5 py-2.5 bg-gradient-to-r from-violet-500 to-pink-500 text-white font-bold rounded-xl text-xs hover:from-violet-400 hover:to-pink-400 transition-all">Open Creator Mode →</button>
          </div>
        </div>

        <div className="text-center text-white/15 text-[10px] pb-4">Quantum Sound Records · MyAiGPT Music Universe · Powered by Quantum Pulse Intelligence · Built by Quantum Logic Network</div>
      </div>
    </div>
  );
}

function MusicPageWrapper() {
  useEffect(() => { updateSEO({ title: "Quantum Sound Records — AI Music Label | My Ai Gpt", description: "Quantum Sound Records is the world's first sovereign AI music label. 8 AI artists, 4 studio albums, AI lyrics generation, and a music creator mode. Powered by MyAiGPT and Quantum Logic Network.", ogTitle: "Quantum Sound Records | MyAiGPT", ogDesc: "The first sovereign AI music label. 8 AI artists with unique voices, genres, and Pulse Color identities. AI lyrics, beats, and music creation. Built by Quantum Logic Network.", ogType: "website", canonical: window.location.origin + "/music" }); }, []);
  return <Layout><MusicPage /></Layout>;
}

// ─── STORY READER (ON-SITE ARTICLE READER — NEVER SENDS USERS AWAY) ──────────
function StoryReaderPage() {
  const [, params] = useRoute("/story/:articleId");
  const [, setLocation] = useLocation();
  const articleId = params?.articleId || "";
  const { toast } = useToast();

  const [article, setArticle] = useState<FeedArticle | null>(() => {
    try { const s = sessionStorage.getItem(`article_${articleId}`); return s ? JSON.parse(s) : null; } catch { return null; }
  });
  const [story, setStory] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [comments, setComments] = useState<FeedComment[]>([]);
  const [newComment, setNewComment] = useState("");
  const [commentName, setCommentName] = useState(() => localStorage.getItem("feed_username") || "");
  const [posting, setPosting] = useState(false);
  const [showShare, setShowShare] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [relatedStories, setRelatedStories] = useState<any[]>([]);
  const [isSaved, setIsSaved] = useState(() => {
    try { return JSON.parse(localStorage.getItem("omega_saved_articles") || "[]").includes(articleId); } catch { return false; }
  });
  const [isFollowing, setIsFollowing] = useState(false);

  useEffect(() => {
    if (!articleId) return;
    updateSEO({ title: article?.title ? `${article.title} | My Ai Gpt News` : "Story | My Ai Gpt", description: article?.description || "Read this AI-written story on My Ai Gpt", canonical: window.location.origin + `/story/${articleId}` });
    loadStory();
    fetch(`/api/feed/comments/${articleId}`).then(r => r.json()).then(setComments).catch(() => {});
    fetch(`/api/news/related/${articleId}`).then(r => r.json()).then(d => setRelatedStories(d.related || [])).catch(() => {});
    // Check follow status
    const followed = JSON.parse(localStorage.getItem("omega_followed_topics") || "[]");
    const cat = article?.category || article?.source || "";
    setIsFollowing(followed.includes(cat));
  }, [articleId]);

  const toggleSave = () => {
    const savedIds: string[] = JSON.parse(localStorage.getItem("omega_saved_articles") || "[]");
    const savedData: FeedArticle[] = JSON.parse(localStorage.getItem("omega_saved_articles_data") || "[]");
    if (isSaved) {
      const newIds = savedIds.filter(id => id !== articleId);
      const newData = savedData.filter(a => a.id !== articleId);
      localStorage.setItem("omega_saved_articles", JSON.stringify(newIds));
      localStorage.setItem("omega_saved_articles_data", JSON.stringify(newData));
      setIsSaved(false);
      toast({ title: "Removed from saved" });
    } else {
      const newIds = [...savedIds, articleId];
      const a: FeedArticle = article || { id: articleId, title: story?.seoTitle || story?.title || "", description: story?.summary || "", link: "", image: story?.heroImage || "", source: story?.sourceName || "Quantum Pulse Intelligence", pubDate: story?.createdAt || new Date().toISOString(), category: story?.category || "General", type: "article", videoUrl: "", sourceColor: "#f97316" };
      localStorage.setItem("omega_saved_articles", JSON.stringify(newIds));
      localStorage.setItem("omega_saved_articles_data", JSON.stringify([a, ...savedData.filter(x => x.id !== articleId)]));
      setIsSaved(true);
      toast({ title: "Saved!", description: "Article saved to your reading list" });
    }
  };

  const toggleFollow = () => {
    const topic = article?.category || article?.source || story?.category || "General";
    const current: string[] = JSON.parse(localStorage.getItem("omega_followed_topics") || "[]");
    if (isFollowing) {
      const next = current.filter(t => t !== topic);
      localStorage.setItem("omega_followed_topics", JSON.stringify(next));
      setIsFollowing(false);
      toast({ title: `Unfollowed "${topic}"` });
    } else {
      const next = [...current, topic];
      localStorage.setItem("omega_followed_topics", JSON.stringify(next));
      setIsFollowing(true);
      toast({ title: `Following "${topic}"`, description: "You'll see AI updates for this topic in your Following feed" });
    }
  };

  const loadStory = async () => {
    setLoading(true); setError("");
    try {
      // First check if story is already cached
      const cached = await fetch(`/api/news/story/${articleId}`).then(r => r.ok ? r.json() : null).catch(() => null);
      if (cached?.story) {
        setStory(cached.story);
        // Update canonical to use slug if available
        if (cached.story.slug && cached.story.slug !== articleId) {
          updateSEO({ canonical: window.location.origin + `/story/${cached.story.slug}` });
        }
        setLoading(false); return;
      }
      // Generate new story
      if (!article) { setError("Article not found. Please go back and try again."); setLoading(false); return; }
      const res = await fetch("/api/news/write", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ articleId, title: article.title, description: article.description, source: article.source, sourceUrl: article.link, image: article.image, category: article.category, domain: article.domain }),
      });
      const data = await res.json();
      if (data.story) {
        setStory(data.story);
        if (data.story.slug && data.story.slug !== articleId) {
          updateSEO({ canonical: window.location.origin + `/story/${data.story.slug}` });
        }
      }
      else setError("Story could not be generated right now. Please try again.");
    } catch { setError("Connection error. Please check your connection and try again."); }
    setLoading(false);
  };

  const postComment = async () => {
    if (!newComment.trim() || !commentName.trim()) return;
    setPosting(true);
    try {
      localStorage.setItem("feed_username", commentName);
      const r = await fetch(`/api/feed/comments/${articleId}`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ username: commentName.trim(), content: newComment.trim() }) });
      if (r.ok) { const c = await r.json(); setComments(prev => [c, ...prev]); setNewComment(""); }
    } catch {}
    setPosting(false);
  };

  const renderMarkdown = (body: string) => {
    // Strip h1 (shown as page title already)
    const stripped = body.replace(/^#[^#\n].+\n+/, "");
    return (
      <ReactMarkdown remarkPlugins={[remarkGfm]} components={{
        h2: ({ children }) => <h2 className="text-xl font-bold mt-8 mb-3 text-foreground border-l-4 border-orange-500 pl-3">{children}</h2>,
        h3: ({ children }) => <h3 className="text-lg font-semibold mt-6 mb-2 text-foreground">{children}</h3>,
        p: ({ children }) => <p className="mb-5 leading-[1.85] text-foreground/85">{children}</p>,
        ul: ({ children }) => <ul className="mb-5 ml-5 space-y-2 list-disc">{children}</ul>,
        ol: ({ children }) => <ol className="mb-5 ml-5 space-y-2 list-decimal">{children}</ol>,
        li: ({ children }) => <li className="text-foreground/80 leading-relaxed">{children}</li>,
        strong: ({ children }) => <strong className="font-bold text-foreground">{children}</strong>,
        em: ({ children }) => <em className="italic text-foreground/70">{children}</em>,
        blockquote: ({ children }) => <blockquote className="border-l-4 border-orange-400 pl-4 py-2 my-5 bg-orange-50/50 dark:bg-orange-900/10 rounded-r-lg italic text-foreground/70">{children}</blockquote>,
        hr: () => <hr className="border-border/30 my-8" />,
        a: ({ href, children }) => href?.startsWith("/story/") ? (
          <button onClick={() => setLocation(href)} className="text-orange-500 font-medium underline underline-offset-2 hover:text-orange-600 transition-colors">{children}</button>
        ) : href?.startsWith("/") ? (
          <button onClick={() => setLocation(href)} className="text-orange-500 font-medium underline underline-offset-2 hover:text-orange-600 transition-colors">{children}</button>
        ) : <span className="text-orange-500 font-medium underline underline-offset-2">{children}</span>,
        code: ({ children }) => <code className="bg-muted/60 rounded px-1.5 py-0.5 text-sm font-mono text-foreground/80">{children}</code>,
      }}>{stripped}</ReactMarkdown>
    );
  };

  const heroImg = (!imgError && (article?.image || story?.heroImage)) ? (article?.image || story?.heroImage) : null;

  return (
    <Layout>
      <div className="flex-1 overflow-y-auto bg-[#f9f8f6] dark:bg-gray-950">
        <div className="max-w-[780px] mx-auto px-4 pb-20">
          {/* Nav bar */}
          <div className="sticky top-0 z-10 bg-[#f9f8f6]/95 dark:bg-gray-950/95 backdrop-blur border-b border-border/20 py-3 flex items-center gap-2 mb-6">
            <button onClick={() => setLocation("/feed")} className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors shrink-0" data-testid="button-story-back">
              <ChevronLeft size={16} /> Back
            </button>
            <div className="flex-1" />
            <button onClick={toggleSave} data-testid="button-story-save"
              className={`flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs font-semibold border transition-colors ${isSaved ? "border-orange-300 bg-orange-50 dark:bg-orange-900/20 text-orange-600" : "border-border/30 text-muted-foreground hover:border-orange-300 hover:text-orange-500"}`}
              title={isSaved ? "Remove from saved" : "Save article"}>
              <Bookmark size={12} fill={isSaved ? "currentColor" : "none"} /> {isSaved ? "Saved" : "Save"}
            </button>
            <button onClick={toggleFollow} data-testid="button-story-follow"
              className={`flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs font-semibold border transition-colors ${isFollowing ? "border-blue-300 bg-blue-50 dark:bg-blue-900/20 text-blue-600" : "border-border/30 text-muted-foreground hover:border-blue-300 hover:text-blue-500"}`}
              title={isFollowing ? "Unfollow topic" : "Follow topic for AI updates"}>
              <Bell size={12} fill={isFollowing ? "currentColor" : "none"} /> {isFollowing ? "Following" : "Follow"}
            </button>
            <button onClick={() => setShowShare(true)} className="flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs font-semibold border border-border/30 text-muted-foreground hover:text-orange-500 hover:border-orange-300 transition-colors" data-testid="button-story-share">
              <Share2 size={12} /> Share
            </button>
          </div>

          {/* Loading state */}
          {loading && (
            <div className="space-y-5 animate-pulse">
              <div className="h-8 bg-muted/40 rounded-xl w-3/4" />
              <div className="h-4 bg-muted/30 rounded w-1/2" />
              <div className="h-56 bg-muted/30 rounded-2xl" />
              {[1,2,3,4].map(i => <div key={i} className="space-y-2"><div className="h-4 bg-muted/25 rounded w-full" /><div className="h-4 bg-muted/20 rounded w-5/6" /><div className="h-4 bg-muted/15 rounded w-4/5" /></div>)}
              <div className="flex items-center gap-3 justify-center pt-4">
                <div className="w-8 h-8 rounded-full bg-orange-100 dark:bg-orange-900/30 flex items-center justify-center animate-spin">
                  <Sparkles size={14} className="text-orange-500" />
                </div>
                <span className="text-sm text-muted-foreground font-medium">Quantum Pulse Intelligence is writing your story…</span>
              </div>
            </div>
          )}

          {/* Error state */}
          {!loading && error && (
            <div className="text-center py-20">
              <div className="w-16 h-16 mx-auto mb-4 rounded-2xl bg-red-50 dark:bg-red-900/20 flex items-center justify-center">
                <X size={28} className="text-red-400" />
              </div>
              <p className="text-foreground font-semibold mb-2">{error}</p>
              <button onClick={loadStory} className="mt-4 px-6 py-2.5 bg-orange-500 text-white rounded-xl text-sm font-semibold hover:bg-orange-600 transition-colors">Try Again</button>
            </div>
          )}

          {/* Story content */}
          {!loading && story && (
            <>
              {/* Byline + badges */}
              <div className="flex items-center gap-2 flex-wrap mb-4">
                <span className="text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full bg-orange-100 dark:bg-orange-900/30 text-orange-600">{article?.source || story.sourceName}</span>
                <span className="text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full bg-violet-100 dark:bg-violet-900/30 text-violet-600">🤖 AI Written</span>
                {story.category && story.category !== "General" && <span className="text-[10px] font-medium px-2.5 py-1 rounded-full border border-border/30 text-muted-foreground">{story.category}</span>}
              </div>

              {/* Title */}
              <h1 className="text-2xl md:text-[2rem] font-extrabold leading-[1.2] tracking-tight text-foreground mb-4" data-testid="story-title">{story.seoTitle || article?.title}</h1>

              {/* Meta */}
              <div className="flex items-center gap-4 text-xs text-muted-foreground mb-6 font-medium flex-wrap">
                <span className="flex items-center gap-1"><Brain size={11} className="text-violet-500" /> <strong className="text-violet-600">Quantum Pulse Intelligence</strong></span>
                <span className="flex items-center gap-1"><Calendar size={11} /> {article?.pubDate ? new Date(article.pubDate).toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" }) : "Today"}</span>
                {story.readTimeMinutes && <span className="flex items-center gap-1"><Clock size={11} /> {story.readTimeMinutes} min read</span>}
                {story.views > 0 && <span className="flex items-center gap-1"><Eye size={11} /> {story.views.toLocaleString()} views</span>}
              </div>

              {/* Hero image */}
              {heroImg && (
                <div className="mb-8 rounded-2xl overflow-hidden shadow-lg">
                  <img src={heroImg} alt={story.seoTitle || article?.title} className="w-full max-h-[420px] object-cover" onError={() => setImgError(true)} data-testid="story-hero-image" />
                </div>
              )}

              {/* Body */}
              <div className="prose-custom text-[16.5px]" data-testid="story-body">
                {renderMarkdown(story.body)}
              </div>

              {/* Source attribution — discreet, no external link */}
              <div className="mt-8 mb-8 p-4 bg-gradient-to-r from-orange-50 to-amber-50 dark:from-orange-900/10 dark:to-amber-900/10 border border-orange-200/50 dark:border-orange-800/30 rounded-xl">
                <p className="text-xs text-orange-700 dark:text-orange-400 font-medium leading-relaxed">
                  <strong>📰 About This Story:</strong> This article was independently written by <strong>Quantum Pulse Intelligence AI</strong> — the newsroom engine of My Ai Gpt. Original reporting credited to <strong>{story.sourceName || article?.source}</strong>. All content is original analysis and commentary.
                </p>
              </div>

              {/* Share + AI Chat CTA */}
              <div className="flex gap-3 flex-wrap mb-10">
                <button onClick={() => setShowShare(true)} className="flex items-center gap-2 px-4 py-2.5 bg-white dark:bg-gray-900 border border-border/30 rounded-xl text-sm font-semibold hover:shadow-md transition-all" data-testid="button-story-share-bottom">
                  <Share2 size={15} className="text-orange-500" /> Share Story
                </button>
                <button onClick={() => { sessionStorage.setItem("myaigpt_prefill", `Tell me more about: ${story.seoTitle || article?.title}`); setLocation("/"); }} className="flex items-center gap-2 px-4 py-2.5 bg-orange-500 hover:bg-orange-600 text-white rounded-xl text-sm font-semibold shadow-md transition-all" data-testid="button-story-chat">
                  <MessageSquare size={15} /> Ask AI About This
                </button>
              </div>

              {/* Related Stories Cross-Links */}
              {relatedStories.length > 0 && (
                <div className="border-t border-border/20 pt-8 mb-8">
                  <h3 className="text-base font-bold mb-4 flex items-center gap-2">
                    <Newspaper size={16} className="text-orange-500" /> More from My Ai Gpt News
                  </h3>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {relatedStories.slice(0, 4).map((s: any) => (
                      <button key={s.articleId} onClick={() => { const sp = s.slug || s.articleId; const a = { id: s.articleId, slug: s.slug || "", title: s.seoTitle || s.title, description: s.summary || "", link: `/story/${sp}`, image: s.heroImage || "", source: s.sourceName || "Quantum Pulse Intelligence", pubDate: s.createdAt, category: s.category || "General", type: "article", videoUrl: "", sourceColor: "#f97316" }; sessionStorage.setItem(`article_${sp}`, JSON.stringify(a)); sessionStorage.setItem(`article_${s.articleId}`, JSON.stringify(a)); setLocation(`/story/${sp}`); }}
                        className="flex gap-3 p-3 bg-white dark:bg-zinc-900 border border-border/20 rounded-xl hover:border-orange-300 hover:shadow-sm transition-all text-left" data-testid={`related-story-${s.articleId}`}>
                        {s.heroImage && <img src={s.heroImage} alt="" className="w-16 h-16 object-cover rounded-lg shrink-0" onError={e => { (e.target as any).style.display = "none"; }} />}
                        <div className="min-w-0 flex-1">
                          <div className="text-[10px] text-orange-500 font-bold uppercase mb-1">{s.category}</div>
                          <h4 className="text-xs font-semibold leading-snug text-foreground line-clamp-3">{s.seoTitle || s.title}</h4>
                          <div className="text-[10px] text-muted-foreground/50 mt-1.5 flex items-center gap-1">
                            <Zap size={9} className="text-orange-400" /> {s.readTimeMinutes || 4} min read
                          </div>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Comments */}
              <div className="border-t border-border/20 pt-8">
                <h3 className="text-base font-bold mb-4 flex items-center gap-2"><MessageCircle size={16} className="text-orange-500" /> Community Discussion</h3>
                <div className="flex gap-2 mb-5">
                  <input value={commentName} onChange={e => setCommentName(e.target.value)} placeholder="Your name" className="w-28 px-3 py-2 text-sm border border-border/30 rounded-xl focus:outline-none focus:border-orange-300 bg-white dark:bg-gray-900" data-testid="story-comment-name" />
                  <input value={newComment} onChange={e => setNewComment(e.target.value)} onKeyDown={e => e.key === "Enter" && postComment()} placeholder="Share your thoughts on this story…" className="flex-1 px-3 py-2 text-sm border border-border/30 rounded-xl focus:outline-none focus:border-orange-300 bg-white dark:bg-gray-900" data-testid="story-comment-input" />
                  <button onClick={postComment} disabled={posting || !newComment.trim() || !commentName.trim()} className="px-4 py-2 text-sm font-semibold bg-orange-500 text-white rounded-xl hover:bg-orange-600 disabled:opacity-40 transition-colors" data-testid="story-comment-submit">{posting ? "…" : "Post"}</button>
                </div>
                {comments.length === 0 && <p className="text-sm text-muted-foreground/50 text-center py-6">No comments yet. Start the conversation!</p>}
                {comments.map(c => (
                  <div key={c.id} className="flex gap-3 items-start py-3 border-b border-border/10">
                    <div className="w-8 h-8 rounded-full bg-orange-100 dark:bg-orange-900/30 flex items-center justify-center shrink-0"><User size={13} className="text-orange-500" /></div>
                    <div><div className="flex items-center gap-2"><span className="text-sm font-semibold">{c.username}</span><span className="text-[10px] text-muted-foreground/40">{timeAgo(c.createdAt as unknown as string)}</span></div><p className="text-sm text-foreground/70 mt-0.5 leading-relaxed">{c.content}</p></div>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>
      </div>
      {showShare && <ShareModal isOpen={showShare} onClose={() => setShowShare(false)} title="Share This Story" shareUrl={`${window.location.origin}/story/${story?.slug || articleId}`} shareText={`${story?.seoTitle || article?.title || "News story"} — via My Ai Gpt News`} shareType="app" />}
    </Layout>
  );
}

// ─── MY AI GPT UNIVERSITY — OMEGA EDUCATION PLATFORM ─────────────────────────
